window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["nicet-water-based"] = window.COURSE_LANG["nicet-water-based"] || {};
window.COURSE_LANG["nicet-water-based"]["ru"] = [
  {id:1, q:"На монтажных чертежах противопожарных спринклеров, что обычно обозначает кружок с дефлектором, направленным вниз?", opts:["Спринклер розеткой вверх (upright)","Спринклер розеткой вниз (pendent)","Реле потока","Обратный клапан"], re:"Спринклер розеткой вниз разбрызгивает воду вниз и свисает ниже распределительной линии, поэтому его символ показывает дефлектор, направленный вниз. Ист.: символы противопожарной защиты NFPA 170; определения ориентации спринклеров NFPA 13."},
  {id:2, q:"Какой стандарт устанавливает стандартизированные графические символы, используемые на чертежах пожарной безопасности и противопожарной защиты в США?", opts:["NFPA 25","NFPA 170","NFPA 72","NFPA 20"], re:"NFPA 170, Стандарт по символам пожарной безопасности и аварийных ситуаций, определяет стандартизированные символы, используемые на чертежах противопожарной защиты. Ист.: NFPA 170."},
  {id:3, q:"Спринклер розеткой вверх (upright) устанавливается так, что вода распыляется:", opts:["Вниз из-под распределительной линии","Вверх и отражается обратно вниз дефлектором","Только горизонтально","Прямо в стену"], re:"Спринклер розеткой вверх располагается над распределительной линией; вода идёт вверх, а дефлектор перенаправляет её вниз и в стороны полусферической струёй. Ист.: NFPA 13, определения типов спринклеров."},
  {id:4, q:"На спринклерном чертеже аббревиатура 'FDC' обозначает какой компонент?", opts:["Соединение для пожарной службы (fire department connection)","Гибкая муфта отвода","Прочистка трапа в полу","Стационарный контроллер дренчера"], re:"FDC означает fire department connection (соединение для пожарной службы) — наружный вход, через который пожарная служба нагнетает воду в систему. Ист.: NFPA 13; аббревиатуры NFPA 170."},
  {id:5, q:"Настенный спринклер (sidewall) выбирается на чертеже в первую очередь когда:", opts:["Потолок выше 30 ft","Монтаж в потолке непрактичен и спринклер должен подавать воду со стены","Помещение является морозильной камерой","Доступны только спринклеры розеткой вверх"], re:"Настенные спринклеры монтируются на стене и подают воду через помещение; используются там, где потолочная разводка непрактична, например в малых помещениях и коридорах. Ист.: NFPA 13, применение настенного спринклера."},
  {id:6, q:"На монтажных чертежах линия, пересечённая короткой перпендикулярной чёрточкой с кружком, обычно обозначает:", opts:["Изменение диаметра трубы","Регулирующий клапан","Только спринклерную головку","Проход через стену"], re:"Символы клапанов размещаются на участке трубы на монтажных чертежах; легенда определяет каждый тип клапана. Ист.: легенда символов NFPA 170; легенда проектного чертежа."},
  {id:7, q:"Каждый комплект монтажных спринклерных чертежей должен включать какой элемент для определения значения каждого используемого символа?", opts:["Легенду символов","Отчёт по грунтам","Матрицу пожарной сигнализации","Журнал OSHA"], re:"Легенда (перечень символов) на чертежах определяет значение каждого символа и аббревиатуры, чтобы проверяющие и монтажники единообразно читали чертёж. Ист.: требования к рабочим чертежам NFPA 13."},
  {id:8, q:"Штриховая (скрытая) линия на спринклерном чертеже чаще всего обозначает:", opts:["Объект выше или ниже плоскости чертежа / скрытый от обзора","Электрическую цепь","Границу участка","Обязательное примечание"], re:"Скрытые/штриховые линии обозначают кромки или трубопроводы, не видимые напрямую в текущем виде, например элементы выше потолка или ниже пола. Ист.: стандартное правило черчения; правила линий ASME/архитектурные."},
  {id:9, q:"На чертеже 'ITC' или 'испытательный кран инспектора' обозначает соединение, используемое для:", opts:["Заполнения системы антифризом","Имитации потока одного спринклера для проверки сигнализации потока воды","Подключения городской магистрали","Автоматического выпуска защемлённого воздуха"], re:"Испытательное соединение инспектора имеет отверстие, соответствующее одному спринклеру, и используется для проверки работы сигнализации потока воды. Ист.: NFPA 13; испытания NFPA 25."},
  {id:10, q:"Скрытый спринклер (concealed) показывается на чертежах с пометкой, указывающей, что он:", opts:["Установлен выше потолка и скрыт декоративной крышкой","Всегда с увеличенным отверстием","Только для наружного применения","Окрашен в красный цвет"], re:"Скрытые спринклеры располагаются утопленными выше линии потолка за заподлицо установленной крышкой, которая отпадает при пожаре. Ист.: NFPA 13, определение скрытого спринклера."},
  {id:11, q:"На спринклерных чертежах термин 'стояк' (riser) относится к:", opts:["Вертикальной питающей трубе с соответствующими клапанами, обслуживающей систему","Диагональной связи","Распределительной линии ближайшей к стене","Кровельному водостоку"], re:"Стояк — это вертикальная труба (с регулирующим клапаном, манометрами, сигнальным устройством и главным дренажём), питающая систему от источника. Ист.: NFPA 13, определение стояка системы."},
  {id:12, q:"Стрелка севера размещается на спринклерном поэтажном плане в первую очередь чтобы:", opts:["Указать проектную интенсивность орошения системы","Задать ориентацию чертежа относительно здания","Показать направление уклона трубы","Отметить расположение FDC"], re:"Стрелка севера ориентирует план так, чтобы читатель мог соотнести чертёж с реальным зданием и другими листами. Ист.: стандартное правило черчения/рабочих чертежей."},
  {id:13, q:"На чертеже диаметры труб чаще всего обозначаются:", opts:["Только цветом","Числовой выноской рядом с трубой (напр., 2\")","Только толщиной линии","Стрелкой севера"], re:"Диаметры труб подписываются числовыми выносками вдоль каждого участка, чтобы монтажник знал размер каждого отрезка. Ист.: рабочие чертежи NFPA 13; правила черчения."},
  {id:14, q:"Символ обратного клапана (check valve) на спринклерном чертеже обозначает устройство, которое:", opts:["Пропускает поток только в одном направлении","Снижает давление","Измеряет температуру","Дренирует систему"], re:"Обратный клапан пропускает воду в одном направлении и предотвращает обратный поток, защищая источник от загрязнения. Ист.: требования к клапанам NFPA 13; NFPA 170."},
  {id:15, q:"На гидравлических чертежах маленький флажок или номер опорного узла у фитинга используется для:", opts:["Обозначения опорной точки расчёта вдоль пути потока","Указания температурного класса спринклера","Указания цвета окраски","Показа границы участка"], re:"Опорные (узловые) точки гидравлики нумеруются, чтобы каждое соединение можно было привязать к листу гидравлического расчёта. Ист.: процедуры гидравлического расчёта NFPA 13."},
  {id:16, q:"'Sprig' (короткий вертикальный отвод), показанный на чертеже или детали стояка, — это:", opts:["Короткая вертикальная труба, поднимающаяся к спринклеру розеткой вверх над магистралью","Горизонтальная поперечная магистраль","Тип подвески","Дренажный фитинг"], re:"Sprig-up — это короткий патрубок трубы, поднимающийся от распределительной линии для питания расположенного выше спринклера розеткой вверх. Ист.: NFPA 13, определение sprig."},
  {id:17, q:"Когда спринклерный чертёж показывает символ 'датчика вскрытия' (tamper switch) на клапане, он контролирует:", opts:["Температуру воды","Открыт клапан или закрыт (контроль положения)","Толщину стенки трубы","Концентрацию антифриза"], re:"Датчик вскрытия (контроля положения) клапана сигнализирует, если регулирующий клапан смещён из нормального открытого положения. Ист.: NFPA 13; сигнализация контроля положения NFPA 72."},
  {id:18, q:"Вид в плане здания лучше всего описать как вид:", opts:["Смотрящий прямо вниз сверху по горизонтальному сечению","Смотрящий горизонтально на одну наружную грань","Рассечённый вертикально через здание","Под углом 45 градусов"], re:"План — это вид по горизонтальному сечению сверху, показывающий расположение стен, помещений и трубопроводов на одном уровне. Ист.: правила архитектурного черчения."},
  {id:19, q:"Вид фасада показывает:", opts:["Раскладку сверху вниз","Плоский вид одной вертикальной грани здания","Сечение, рассекающее интерьер","Схему без масштаба"], re:"Фасад — это прямой вид одной вертикальной стороны (фасада или внутренней поверхности), вычерченный в масштабе. Ист.: правила архитектурного черчения."},
  {id:20, q:"Вид разреза создаётся:", opts:["Взглядом вниз с кровли","Рассечением здания вертикальной плоскостью и просмотром сечения","Фотографированием экстерьера","Поворотом плана на 90 градусов"], re:"Чертёж разреза рассекает конструкцию вертикально, чтобы раскрыть внутренние соотношения, такие как высоты потолков и прокладка труб. Ист.: правила архитектурного черчения."},
  {id:21, q:"На архитекторской линейке '1/8\" = 1'-0\"' означает, что каждые 1/8 дюйма на бумаге равны:", opts:["1 дюйму в здании","1 футу в здании","8 футам в здании","1 ярду в здании"], re:"При 1/8\" = 1'-0\" одна восьмая дюйма на чертеже представляет один фут реальной длины (соотношение 1:96). Ист.: USFA/FEMA, Using Engineer and Architect Scales."},
  {id:22, q:"Архитекторская линейка использует дробную систему, тогда как инженерная линейка использует:", opts:["Десятичную систему (напр., 1\" = 20')","Только метрические единицы","Никакого определённого соотношения","Те же дроби, что и архитекторская линейка"], re:"Инженерные линейки десятичные (1\" = 10', 20', 30' и т. д.); архитекторские используют доли дюйма на фут. Ист.: USFA/FEMA, Using Engineer and Architect Scales."},
  {id:23, q:"При масштабе 1/4\" = 1'-0\" стена, начерченная длиной 3 дюйма на бумаге, представляет реальную длину:", opts:["3 фута","6 футов","12 футов","48 футов"], re:"При 1/4\" = 1' каждый дюйм равен 4 футам; 3 дюйма x 4 ft = 12 футов. Ист.: пересчёт архитекторского масштаба (USFA/FEMA)."},
  {id:24, q:"Почему проектировщику следует избегать снятия размеров напрямую с распечатанного листа, когда указан письменный размер?", opts:["Печать/копирование может исказить масштаб; письменные размеры имеют приоритет","Использовать масштабы незаконно","Бумага всегда точна","Письменные размеры — лишь рекомендации"], re:"Копирование и плоттерная печать могут растянуть чертёж, поэтому проставленные (письменные) размеры имеют приоритет над измеренными по масштабу. Ист.: стандартная практика черчения."},
  {id:25, q:"Зеркальный план потолка (RCP) наиболее полезен проектировщику спринклеров для:", opts:["Размещения элементов потолка, таких как плитки, светильники и диффузоры, влияющих на расстановку головок","Подбора подземной магистрали","Определения несущей способности грунта","Выбора пожарного насоса"], re:"RCP показывает потолок как бы отражённым на полу, помогая согласовать расположение спринклеров со светильниками, решётками и диффузорами. Ист.: практика архитектурной/MEP координации."},
  {id:26, q:"На чертеже аббревиатура 'AFF' обычно означает:", opts:["Над чистым полом (above finished floor)","Утверждённый пожарный расход","Автоматический проточный фитинг","Ежегодная пожарная форма"], re:"AFF (above finished floor, над чистым полом) обозначает высоту, измеренную вверх от поверхности готового пола, используемую для отметок потолка и головок. Ист.: стандартные аббревиатуры черчения."},
  {id:27, q:"Чертёж 'детали' в более крупном масштабе (напр., деталь стояка) предоставляется чтобы:", opts:["Скрыть информацию от AHJ","Показать малый участок крупнее и яснее, чем общий план","Заменить титульный лист","Сократить число диаметров труб"], re:"Детали увеличивают конкретный узел, чтобы ясно показать соединения и компоненты, которые были бы слишком мелкими на основном плане. Ист.: практика черчения/рабочих чертежей."},
  {id:28, q:"На спринклерном чертеже высота потолка наиболее непосредственно влияет на какой параметр проектирования?", opts:["Цвет рамки чертежа","Расстояние от спринклера до дефлектора и правила препятствий/покрытия","Шрифт основной надписи","Направление стрелки севера"], re:"Высота и конструкция потолка определяют расстояние дефлектора ниже потолка и правила препятствий, задающие шаг расстановки. Ист.: правила препятствий и зазоров NFPA 13."},
  {id:29, q:"Графический (линейный) масштаб, напечатанный на чертеже, полезен потому, что он:", opts:["Остаётся пропорционально верным, даже если лист увеличен или уменьшен","Указывает проектную интенсивность орошения","Показывает юридическую границу участка","Полностью заменяет необходимость в размерах"], re:"Линейный/графический масштаб масштабируется вместе с чертежом, поэтому остаётся точным после копирования, даже когда числовое соотношение перестаёт быть верным. Ист.: практика черчения (руководство по масштабам USFA/FEMA)."},
  {id:30, q:"Когда примечание на чертеже гласит 'NTS', это означает, что деталь:", opts:["Без масштаба (not to scale)","Возле южной лестницы","Новая система бака","Указанный технический стандарт"], re:"NTS (not to scale, без масштаба) сообщает читателю, что изображение схематично и его нельзя измерять для получения размеров. Ист.: стандартные аббревиатуры черчения."},
  {id:31, q:"Чтобы найти высоту потолка для зазора спринклера, проектировщик наиболее надёжно обращается к:", opts:["Только титульному листу","Видам разреза здания или разреза стены","Основной надписи","Легенде символов"], re:"Виды разрезов раскрывают вертикальные размеры, такие как высота от пола до потолка и от пола до перекрытия, необходимые для зазора головок. Ист.: архитектурные чертежи разрезов."},
  {id:32, q:"На генплане (гражданском) расположение подземной пожарной магистрали и FDC согласовываются с использованием какого типа масштаба?", opts:["Архитекторского (дробного) масштаба","Инженерного (десятичного) масштаба","Без масштаба","Только метрического"], re:"Генпланы/гражданские чертежи обычно вычерчиваются в инженерных (десятичных) масштабах, таких как 1\" = 20'. Ист.: USFA/FEMA, Using Engineer and Architect Scales."},
  {id:33, q:"'Отметку чистого пола' на чертеже проектировщик спринклеров использует главным образом чтобы:", opts:["Задать опорную отметку для высот труб, потолков и головок","Выбрать цвет спринклера","Установить интенсивность орошения системы","Определить класс горючих материалов"], re:"Отметка пола даёт базовую отметку, от которой измеряются высоты потолка и головок для раскладки и гидравлики. Ист.: практика черчения/координации."},
  {id:34, q:"Согласование раскладки спринклеров с воздуховодами HVAC, показанными на чертежах, важно потому, что:", opts:["Воздуховоды шире 4 ft и могут препятствовать разбрызгиванию спринклера","Воздуховоды меняют архитекторский масштаб","Воздуховоды задают класс опасности","Воздуховоды никогда не показываются на чертежах"], re:"Широкие воздуховоды (и другие препятствия) блокируют струю и могут требовать спринклеров под ними или изменённого шага согласно правилам препятствий. Ист.: положения о препятствиях NFPA 13."},
  {id:35, q:"Главный дренаж на спринклерном стояке предусмотрен чтобы:", opts:["Дренировать систему и выполнять испытание главным дренажём (проточное)","Питать FDC","Добавлять антифриз","Повышать давление"], re:"Главный дренаж опорожняет стояк и обеспечивает испытание главным дренажём, проверяющее наличие водоснабжения. Ист.: NFPA 13; испытание главным дренажём NFPA 25."},
  {id:36, q:"Сигнализатор потока воды (или сигнальный клапан) в водозаполненной системе служит чтобы:", opts:["Подавать сигнал тревоги, когда вода течёт из-за сработавшего спринклера","Снижать городское давление","Фильтровать осадок","Отмечать границу участка"], re:"Обнаружение потока воды инициирует тревогу, когда спринклер открывается и вода движется через стояк. Ист.: NFPA 13; NFPA 72."},
  {id:37, q:"На чертеже воздушной (сухой) системы клапан сухотрубной системы удерживает воду с помощью:", opts:["Сжатого воздуха или азота в трубопроводе над клапаном","Только пружины","Только силы тяжести","Нагревательного элемента"], re:"В сухой системе сжатый воздух/азот над захлопкой удерживает клапан сухотрубной системы закрытым, пока спринклер не откроется и воздух не выйдет. Ист.: сухотрубные системы NFPA 13."},
  {id:38, q:"Соединение для пожарной службы (FDC) позволяет пожарной службе:", opts:["Нагнетать дополнительную воду/давление в спринклерную систему","Дренировать систему","Перекрыть городскую воду","Проверять температурные классы спринклеров"], re:"FDC — это вход для пожарных насосов, чтобы увеличить расход и давление системы во время пожара. Ист.: требования к FDC NFPA 13."},
  {id:39, q:"Регулирующий клапан системы (напр., OS&Y или дисковый затвор), показанный у стояка, обычно держат:", opts:["Открытым и под контролем положения","Закрытым","Полуоткрытым","Снятым во время работы"], re:"Регулирующие клапаны должны быть нормально открыты и под контролем положения, чтобы вода всегда была доступна системе. Ист.: NFPA 13; контроль положения клапанов NFPA 25."},
  {id:40, q:"На чертежах 'поперечная магистраль' (cross main) — это труба, которая:", opts:["Питает распределительные линии","Несёт спринклеры напрямую","Соединяется только с FDC","Дренирует систему"], re:"Поперечные магистрали распределяют воду к распределительным линиям, которые, в свою очередь, несут спринклеры. Ист.: определения труб NFPA 13."},
  {id:41, q:"'Распределительная линия' (branch line) на спринклерном чертеже — это труба, которая:", opts:["Напрямую питает спринклеры","Является вертикальным стояком","Соединяет два здания","Несёт только дренажную воду"], re:"Распределительные линии — это трубы, к которым спринклеры присоединены напрямую. Ист.: определения труб NFPA 13."},
  {id:42, q:"Пожарный насос показывается на чертежах когда:", opts:["Доступного давления/расхода водоснабжения недостаточно для проектной потребности","У каждого здания он есть по закону","Система только водозаполненная","Используется антифриз"], re:"Пожарный насос повышает давление/расход, когда источник не может удовлетворить гидравлическую потребность. Ист.: NFPA 13; пожарные насосы NFPA 20."},
  {id:43, q:"На детали стояка манометры устанавливаются чтобы:", opts:["Задать архитекторский масштаб","Дренировать стояк","Сработать клапан сухотрубной системы","Показывать давления системы и источника для контроля и испытаний"], re:"Манометры отображают давления источника и системы, чтобы систему можно было контролировать и оценивать испытания главным дренажём. Ист.: NFPA 13; NFPA 25."},
  {id:44, q:"Узел предотвращения обратного потока (backflow) может показываться на входящем источнике в первую очередь чтобы:", opts:["Нагревать воду","Повышать интенсивность орошения","Заменить FDC","Защитить источник питьевой воды от загрязнения"], re:"Устройства предотвращения обратного потока не дают возможно загрязнённой воде системы вернуться в общественный водопровод. Ист.: NFPA 13; местный сантехнический кодекс/кодекс перекрёстных соединений."},
  {id:45, q:"В системе предварительного действия с двойной блокировкой вода поступает в трубопровод только когда:", opts:["Открывается главный дренаж","Спринклер открывается сам по себе","Срабатывает только обнаружение","Срабатывает обнаружение И открывается спринклер"], re:"Предварительное действие с двойной блокировкой требует как независимого сигнала обнаружения, так и открытого спринклера, прежде чем впустить воду, минимизируя случайный сброс. Ист.: системы предварительного действия NFPA 13."},
  {id:46, q:"Вспомогательный дренаж (drum drip) в сухой системе предусматривается в:", opts:["Всасывании пожарного насоса","Только в высшей точке","FDC","Низких точках/защемлённых участках для удаления конденсата"], re:"Вспомогательные дренажи низких точек (drum drips) собирают и удаляют конденсат, скапливающийся в трубопроводе сухой системы. Ист.: дренаж сухой системы NFPA 13."},
  {id:47, q:"Дренчерный клапан на чертеже связан с:", opts:["Контурами антифриза","Только закрытыми спринклерами розеткой вниз","Функцией снижения давления","Открытыми спринклерами/насадками, из которых течёт вода при срабатывании клапана"], re:"Дренчерные системы используют открытые насадки; когда дренчерный клапан срабатывает по обнаружению, вода течёт из всех них одновременно. Ист.: дренчерные системы NFPA 13."},
  {id:48, q:"На чертежах подвески и сейсмические связи показываются чтобы:", opts:["Определить класс горючих материалов","Повысить интенсивность орошения","Отметить FDC","Поддерживать и фиксировать трубопровод"], re:"Подвески несут вес трубы, а связи ограничивают перемещение (включая сейсмическое) согласно правилам подвески и связей NFPA 13. Ист.: NFPA 13, глава о подвеске/связях."},
  {id:49, q:"'Пожарный сухотруб' (standpipe), показанный рядом со спринклерным трубопроводом, предназначен чтобы:", opts:["Питать городскую магистраль","Заменить спринклеры","Дренировать конденсат","Обеспечить пожарные краны для ручного пожаротушения"], re:"Пожарные сухотрубы подают воду к пожарным кранам на каждом этаже для рукавных струй пожарной службы или жильцов (NFPA 14). Ист.: NFPA 14; согласование с NFPA 13."},
  {id:50, q:"Редукционный клапан давления (PRV) может появиться на стояке высотного здания чтобы:", opts:["Обеспечить FDC","Добавить воздух в систему","Повысить расход выше источника","Ограничить чрезмерное давление до приемлемых уровней для расположенных ниже компонентов"], re:"PRV снижают высокое статическое давление (обычное на нижних этажах высоких зданий), чтобы защитить трубопровод и устройства. Ист.: пределы давления NFPA 13 / NFPA 14."},
  {id:51, q:"На чертеже 'точка подключения' к водоснабжению важна потому, что она:", opts:["Выбирает класс горючих материалов","Задаёт цвет спринклера","Определяет архитекторский масштаб","Определяет, где система подключается к источнику, используемому для гидравлических расчётов"], re:"Точка подключения источника устанавливает основу давления/расхода источника для гидравлического проектирования. Ист.: требования к водоснабжению и гидравлическому расчёту NFPA 13."},
  {id:52, q:"Согласно NFPA 13, какое назначение классифицируется как лёгкая опасность (Light Hazard)?", opts:["Авторемонтная мастерская","Читальный зал библиотеки","Производство бумаги","Авиационный ангар"], re:"Лёгкая опасность охватывает содержимое малого количества/горючести, такое как офисы, церкви и читальные залы библиотек. Ист.: классификация по назначению NFPA 13 (лёгкая опасность)."},
  {id:53, q:"Пекарня или прачечная обычно классифицируется по NFPA 13 как:", opts:["Лёгкая опасность","Средняя опасность группа 1","Высокая опасность группа 1","Высокая опасность группа 2"], re:"Пекарни и прачечные являются примерами помещений средней опасности группы 1 (умеренное количество, низкая горючесть). Ист.: классификация по назначению NFPA 13 (OH1)."},
  {id:54, q:"Что из перечисленного является примером помещения средней опасности группы 2?", opts:["Зал церкви","Читальный зал библиотеки","Механический цех / металлообработка","Офис"], re:"Средняя опасность группы 2 включает механические цеха, торговлю и подобные помещения умеренной-повышенной горючести. Ист.: классификация по назначению NFPA 13 (OH2)."},
  {id:55, q:"Авиационные ангары и подобные операции высокой горючести, как правило, классифицируются как:", opts:["Лёгкая опасность","Средняя опасность группа 1","Высокая опасность группа 1","Лёгкая опасность с исключениями"], re:"Высокая опасность группы 1 охватывает высокую горючесть с быстрым развитием пожара, такую как авиационные ангары и полиграфические операции. Ист.: классификация по назначению NFPA 13 (EH1)."},
  {id:56, q:"Автомобильная окрасочная распылительная камера (значительное количество горючих жидкостей) лучше всего классифицируется как:", opts:["Лёгкая опасность","Средняя опасность группа 1","Средняя опасность группа 2","Высокая опасность группа 2"], re:"Высокая опасность группы 2 охватывает помещения со значительным количеством легковоспламеняющихся/горючих жидкостей, такие как нанесение краски распылением. Ист.: классификация по назначению NFPA 13 (EH2)."},
  {id:57, q:"В NFPA 13 классификация пожарной опасности по назначению используется главным образом для определения:", opts:["Цвета окраски стен","Проектной интенсивности орошения водоснабжения и критериев площади","Архитекторского масштаба","Основной надписи чертежа"], re:"Классификация опасности задаёт проектную интенсивность орошения и рабочую площадь, используемые для подбора системы. Ист.: подходы к проектированию по классу опасности NFPA 13."},
  {id:58, q:"Горючий материал Класса I по NFPA 13 лучше всего описать как:", opts:["Резиновые шины","Пластик с высоким тепловыделением","Горючая жидкость в бочках","По существу негорючий продукт, может быть на горючих поддонах / в коробках"], re:"Класс I — это по существу негорючий продукт, допускающий обычные гофрокартонные коробки и деревянные поддоны. Ист.: классификация горючих материалов NFPA 13 (Класс I)."},
  {id:59, q:"Пластики группы A отличаются от пластиков групп B и C тем, что имеют:", opts:["Наименьшую теплоту сгорания","Теплоту сгорания и скорость горения намного выше обычных горючих материалов","Никакого влияния на проектирование спринклеров","Ту же скорость горения, что и дерево"], re:"Пластики группы A имеют наибольшую теплоту сгорания и самую быструю скорость горения из трёх групп, что задаёт наиболее жёсткие критерии хранения. Ист.: классификация пластиков NFPA 13."},
  {id:60, q:"Какой материал является примером пластика группы A?", opts:["Нейлон","Полистирол (напр., вспененный)","Фенольный","Жёсткий ПВХ (менее 5% пластифицированный)"], re:"Полистирол (вспененный/невспененный), полиэтилен, полипропилен, ABS и PET являются пластиками группы A. Ист.: классификация пластиков NFPA 13 (группа A)."},
  {id:61, q:"Нейлон и невспененный натуральный каучук являются примерами какой группы пластиков?", opts:["Группа A","Группа B","Группа C","Не является пластиком"], re:"Пластики группы B включают нейлон, целлюлозные материалы и невспененный натуральный каучук (между группами A и C по тяжести). Ист.: классификация пластиков NFPA 13 (группа B)."},
  {id:62, q:"Что из перечисленного является пластиком группы C?", opts:["Полиэтилен","Полипропилен","Фенольный (или PTFE)","ABS"], re:"Пластики группы C (напр., фенольный, меламин, PTFE, жёсткий ПВХ) горят подобно обычным горючим материалам. Ист.: классификация пластиков NFPA 13 (группа C)."},
  {id:63, q:"NFPA 13 рассматривает пожарный риск пластиков группы C как примерно эквивалентный какому классу горючих материалов?", opts:["Класс I","Класс II","Класс III","Класс IV"], re:"Пластики группы C считаются эквивалентными горючим материалам Класса III (поведение, подобное обычным горючим). Ист.: эквивалентность горючих материалов/пластиков NFPA 13."},
  {id:64, q:"Горючий материал Класса IV содержит:", opts:["Совсем без пластиков","Значительное количество пластиков группы A (в установленных пределах), добавленное к продукту более низкого класса","Только негорючие предметы","Чистую горючую жидкость"], re:"Класс IV — это продукт, содержащий значительное, но ограниченное количество пластиков группы A (напр., 5-15% по массе). Ист.: классификация горючих материалов NFPA 13 (Класс IV)."},
  {id:65, q:"Классификация горючих материалов (Класс I-IV, пластики) является отправной точкой для проектирования защиты в:", opts:["Офисах лёгкой опасности","Складских помещениях / складах","Только открытых парковочных палубах","Жилых спальнях"], re:"Складские помещения защищаются исходя из класса горючих материалов, высоты хранения и компоновки, а не только базовой опасности по назначению. Ист.: защита складского хранения NFPA 13."},
  {id:66, q:"Горючие материалы Класса III обычно описываются как:", opts:["Только негорючие продукты","Дерево, бумага, натуральные волокна или пластики группы C (с ограниченным количеством группы A/B)","Чистые пластики группы A","Горючие газы"], re:"Класс III — это дерево, бумага, ткань из натурального волокна или пластики группы C, лишь с небольшой допустимой долей пластиков группы A/B. Ист.: классификация горючих материалов NFPA 13 (Класс III)."},
  {id:67, q:"Когда содержимое сочетает несколько видов опасности в одном пространстве, проектировщик обычно защищает по:", opts:["Наименьшей присутствующей опасности","Лёгкой опасности по умолчанию","Наиболее требовательной (наивысшей) присутствующей опасности или проектирует по площади","Тому, что дешевле"], re:"Смешанные горючие материалы/назначения обычно защищаются по наивысшей присутствующей опасности, если только зоны не разделены и не спроектированы по отдельности. Ист.: руководство по смешанным горючим материалам/назначениям NFPA 13."},
  {id:68, q:"Герметизация хранимого горючего материала (напр., пластиковая плёнка поверх) имеет значение потому, что она:", opts:["Не влияет на поведение пожара","Понижает класс горючих материалов","Может удерживать тепло/ограничивать проникновение воды, повышая потребность в защите","Устраняет необходимость в спринклерах"], re:"Герметизация может экранировать горючий материал от воды и усилить поведение пожара, часто требуя усиленной защиты. Ист.: складское хранение NFPA 13 (положения о герметизации)."},
  {id:69, q:"Водозаполненная спринклерная система уместна там, где:", opts:["Температура может опускаться ниже нуля","Случайную воду нельзя допускать вовсе","Помещение отапливается и поддерживается выше 40 F (4 C)","Используются только открытые насадки"], re:"Водозаполненные системы держат воду в трубе и применяются в отапливаемых помещениях, поддерживаемых при 40 F (4 C) или выше. Ист.: применение водозаполненной системы NFPA 13."},
  {id:70, q:"Сухотрубная система выбирается главным образом для:", opts:["Отапливаемого офисного пространства","Зон, требующих максимально быстрой подачи воды","Неотапливаемых/морозных зон, таких как холодные склады или парковки","Мест без водоснабжения"], re:"Сухие системы используют сжатый воздух, чтобы держать воду вне трубопровода, подверженного промерзанию, что распространено в неотапливаемых пространствах. Ист.: применение сухотрубной системы NFPA 13."},
  {id:71, q:"По сравнению с водозаполненной системой сухотрубная система имеет:", opts:["Более быструю подачу воды к открытому спринклеру","Отсутствие необходимости в регулирующем клапане","Задержку, потому что воздух должен выйти, прежде чем вода достигнет спринклера","Отсутствие необходимости в водоснабжении"], re:"Сухие системы имеют присущую задержку, поскольку защемлённый воздух должен выйти, прежде чем вода потечёт из открытой головки. Ист.: характеристики сухой системы NFPA 13."},
  {id:72, q:"Система предварительного действия с одинарной блокировкой впускает воду в трубопровод когда:", opts:["Срабатывает только спринклер","Открывается главный дренаж","Срабатывает отдельная система обнаружения","Подключается FDC"], re:"Предварительное действие с одинарной блокировкой заполняет трубу при сигнале обнаружения; затем вода течёт, когда спринклер открывается. Ист.: типы систем предварительного действия NFPA 13."},
  {id:73, q:"Система предварительного действия обычно выбирается для защиты:", opts:["Открытых парковок","Наружных погрузочных доков","Чувствительных к воде зон, таких как ЦОД или архивы","Только котельных"], re:"Системы предварительного действия снижают вероятность случайного сброса воды, что делает их подходящими для чувствительных к воде пространств, таких как ЦОД и музеи. Ист.: применения предварительного действия NFPA 13."},
  {id:74, q:"Дренчерная система наиболее уместна для:", opts:["Типичного офиса","Холодного хранения без опасности","Зон высокой опасности, требующих одновременной воды из всех головок (напр., авиационные ангары)","Малой жилой единицы"], re:"Дренчерные системы используют открытые головки и подают воду повсюду одновременно для быстро распространяющихся пожаров высокой опасности. Ист.: применения дренчера NFPA 13."},
  {id:75, q:"Система предварительного действия с двойной блокировкой хорошо подходит для:", opts:["Отапливаемого вестибюля","Открытых навесов","Морозильных складов, где случайная вода обходится дорого, а промерзание вызывает беспокойство","Стандартного офиса со спринклерами"], re:"Предварительное действие с двойной блокировкой не пускает воду, пока не сработают и обнаружение, и спринклер, что идеально для морозильных камер. Ист.: предварительное действие с двойной блокировкой NFPA 13."},
  {id:76, q:"Примерно ниже какой температуры NFPA 13 обычно уводит проектировщиков от водозаполненных систем к сухим или предварительного действия?", opts:["120 F (49 C)","70 F (21 C)","90 F (32 C)","40 F (4 C)"], re:"Там, где температура может опускаться ниже 40 F (4 C), водозаполненная система рискует промёрзнуть, поэтому применяют сухую/предварительного действия или защиту от промерзания. Ист.: порог защиты от промерзания NFPA 13."},
  {id:77, q:"Открытые спринклеры (без термочувствительного элемента) используются в какой системе?", opts:["Водозаполненной","Сухотрубной","Дренчерной","Предварительного действия с одинарной блокировкой"], re:"Дренчерные системы используют открытые спринклеры/насадки, чтобы из всех текла вода сразу при срабатывании дренчерного клапана. Ист.: определение дренчерной системы NFPA 13."},
  {id:78, q:"Какая система держит трубопровод сухим, пока не сработает обнаружение, И предназначена для ограничения случайного сброса воды?", opts:["Водозаполненная","Обычная дренчерная","Предварительного действия","Контур антифриза"], re:"Системы предварительного действия держат трубу сухой, пока не сработает обнаружение (а для блокировочных типов — спринклер), ограничивая непреднамеренный сброс. Ист.: системы предварительного действия NFPA 13."},
  {id:79, q:"Спринклерная система с антифризом — это разновидность, обычно используемая чтобы:", opts:["Повысить давление","Заменить пожарный насос","Защитить малые неотапливаемые участки в остальном водозаполненной системы без отдельного сухого клапана","Устранить стояк"], re:"Контуры антифриза защищают ограниченные неотапливаемые части, заполняя этот участок одобренным раствором антифриза. Ист.: положения о системе с антифризом NFPA 13."},
  {id:80, q:"Для типичного отапливаемого офисного здания наиболее распространённый и экономичный тип системы — это:", opts:["Дренчерная","Предварительного действия с двойной блокировкой","Водозаполненная","Сухотрубная"], re:"Водозаполненные системы наиболее распространены и просты для отапливаемых помещений, обеспечивая самый быстрый отклик. Ист.: NFPA 13; распространённая практика проектирования."},
  {id:81, q:"Ключевой недостаток сухотрубных систем по сравнению с водозаполненными — это:", opts:["Их нельзя использовать на складах","Они не требуют обслуживания","Повышенная сложность, потенциал коррозии и задержка подачи воды","Они не могут обнаруживать пожар"], re:"Сухие системы добавляют оборудование подачи воздуха, склонны к внутренней коррозии/конденсации и задерживают подачу воды. Ист.: соображения по сухой системе NFPA 13."},
  {id:82, q:"При выборе типа системы ПЕРВОЕ соображение, которое оценивает проектировщик, обычно — это:", opts:["Цвет трубы","Марка спринклера","Среда/опасность здания (напр., промерзание, чувствительность к воде, уровень опасности)","Шрифт основной надписи"], re:"Тип системы следует из среды и опасности: отапливаемое или промерзающее, чувствительное к воде содержимое и тяжесть опасности. Ист.: обоснование выбора системы NFPA 13."},
  {id:83, q:"Комбинированная сухотрубная система предварительного действия может назначаться для:", opts:["Малого офиса","Жилой спальни","Очень длинного трубопровода в холодных зонах, нуждающегося в преимуществах обоих подходов","Открытой парковки"], re:"Комбинированные схемы сухотрубной системы предварительного действия отвечают потребностям больших/длинных холодных систем, где желательны и защита от промерзания, и контроль положения. Ист.: положения о комбинированной системе NFPA 13."},
  {id:84, q:"Для морозильного складского помещения, где любая вода в простаивающем трубопроводе вызывает повреждение льдом, предпочтительный выбор — это:", opts:["Водозаполненная","Предварительного действия с одинарной блокировкой","Предварительного действия с двойной блокировкой","Контур антифриза на всю систему"], re:"Предварительное действие с двойной блокировкой держит трубопровод сухим, пока не произойдут обнаружение и активация спринклера, что лучше всего для морозильных камер. Ист.: применение предварительного действия с двойной блокировкой NFPA 13."},
  {id:85, q:"NFPA 13 — это стандарт по:", opts:["Установке пожарных насосов","Осмотру, испытанию и обслуживанию систем на основе воды","Установке систем пожарной сигнализации","Установке спринклерных систем"], re:"NFPA 13 — это Стандарт по установке спринклерных систем. Ист.: NFPA 13 (название/область применения)."},
  {id:86, q:"Какой документ определяет Орган, имеющий юрисдикцию (AHJ)?", opts:["Только владелец здания","Генеральный подрядчик","Производитель спринклеров","NFPA, как ведомство/лицо, ответственное за обеспечение соблюдения кодекса или утверждение оборудования"], re:"NFPA определяет AHJ как организацию, ведомство или лицо, ответственное за обеспечение соблюдения кодекса/стандарта или за утверждение оборудования и монтажа. Ист.: определения NFPA (AHJ)."},
  {id:87, q:"Как NFPA 13 становится юридически обязательным в юрисдикции?", opts:["Он автоматически является законом повсюду","Производители голосуют за него","Он принимается по ссылке через строительный/пожарный кодекс или местное постановление","Он применяется, только если напечатан в цвете"], re:"NFPA 13 приобретает силу закона, когда принимается по ссылке в применимом строительном или пожарном кодексе либо постановлении. Ист.: процесс принятия кодексов; NFPA."},
  {id:88, q:"Какой стандарт чаще всего ссылается на NFPA 13, требуя установки спринклеров в зданиях?", opts:["NFPA 25","NFPA 170","Международный строительный кодекс (IBC) / Международный пожарный кодекс (IFC)","NFPA 20"], re:"Модельные кодексы, такие как IBC и IFC, ссылаются на NFPA 13 для установки требуемых спринклерных систем. Ист.: стандарты, на которые ссылаются IBC/IFC."},
  {id:89, q:"NFPA 25 охватывает:", opts:["Установку новых спринклерных систем","Проектирование систем пожарной сигнализации","Осмотр, испытание и обслуживание систем противопожарной защиты на основе воды","Производство труб"], re:"NFPA 25 — это Стандарт по осмотру, испытанию и обслуживанию систем противопожарной защиты на основе воды. Ист.: NFPA 25 (название/область применения)."},
  {id:90, q:"NFPA 20 — это стандарт по:", opts:["Системам пожарного сухотруба и рукавов","Символам на чертежах","Обслуживанию спринклеров","Установке стационарных пожарных насосов для противопожарной защиты"], re:"NFPA 20 — это Стандарт по установке стационарных насосов для противопожарной защиты. Ист.: NFPA 20 (название/область применения)."},
  {id:91, q:"NFPA 14 — это стандарт по:", opts:["Установке спринклеров","ITM на основе воды","Системам пожарной сигнализации","Системам пожарного сухотруба и рукавов"], re:"NFPA 14 — это Стандарт по установке систем пожарного сухотруба и рукавов. Ист.: NFPA 14 (название/область применения)."},
  {id:92, q:"Когда AHJ и NFPA 13 расходятся, в принимающей юрисдикции проектировщик обычно должен:", opts:["Игнорировать AHJ","Выбрать то, что дешевле","Использовать только каталог производителя","Соблюдать обязательные требования кодекса/AHJ, которые могут быть строже"], re:"Принятый кодекс и обеспечение соблюдения со стороны AHJ имеют силу; местные поправки могут быть строже базового стандарта. Ист.: принятие кодексов/полномочия AHJ."},
  {id:93, q:"NFPA 13R предназначен для спринклерных систем в:", opts:["Складах высокой опасности","Нефтеперерабатывающих заводах","Авиационных ангарах","Жилых зданиях малой этажности до четырёх этажей (как определено)"], re:"NFPA 13R рассматривает жилые помещения высотой до четырёх этажей включительно в пределах своей области применения. Ист.: NFPA 13R (область применения)."},
  {id:94, q:"NFPA 13D применяется к спринклерным системам в:", opts:["Высотных офисах","Больницах","Складских помещениях","Одно- и двухсемейных жилых домах и заводских домах"], re:"NFPA 13D — это стандарт по спринклерным системам в одно- и двухсемейных жилых домах и заводских домах. Ист.: NFPA 13D (область применения)."},
  {id:95, q:"Рабочие (монтажные) чертежи подаются в AHJ главным образом чтобы:", opts:["Задать архитекторский масштаб","Продать здание","Заменить гидравлические расчёты","Получить рассмотрение и утверждение/разрешение до монтажа"], re:"Монтажные чертежи подаются для рассмотрения, утверждения и выдачи разрешения AHJ до монтажа. Ист.: требования к рабочим чертежам/утверждению NFPA 13."},
  {id:96, q:"Редакция NFPA 13, которой должен следовать проектировщик, определяется:", opts:["Всегда новейшей редакцией","Производителем труб","Личным предпочтением проектировщика","Редакцией, на которую ссылается/которую принял действующий кодекс в этой юрисдикции"], re:"Применимая редакция — это та, что принята действующим кодексом юрисдикции, и она может не быть самой новой. Ист.: практика принятия кодексов."},
  {id:97, q:"'Внесённый в перечень' (listed) компонент, упомянутый в NFPA 13, означает, что продукт:", opts:["Окрашен в красный цвет","Освобождён от осмотра","Дешевле альтернатив","Оценён признанной испытательной лабораторией и опубликован в перечне для предусмотренного применения"], re:"'Внесённый в перечень' означает оборудование, оценённое признанной лабораторией (напр., UL/FM) и опубликованное как пригодное для конкретного применения. Ист.: определения NFPA (внесённый в перечень)."},
  {id:98, q:"NFPA 170 поддерживает чтение чертежей, предоставляя:", opts:["Методы гидравлического расчёта","Классы горючих материалов","Кривые насоса","Стандартизированные символы пожарной безопасности и аварийных ситуаций"], re:"NFPA 170 стандартизирует символы пожарной безопасности/аварийных ситуаций, используемые на чертежах и в знаках. Ист.: NFPA 170 (область применения)."},
  {id:99, q:"Максимальная площадь пола, защищаемая одной спринклерной системой для лёгкой или средней опасности, традиционно ограничивается:", opts:["25,000 sq ft","Без ограничения","100,000 sq ft","52,000 sq ft"], re:"NFPA 13 традиционно ограничивает одну систему лёгкой/средней опасности 52,000 sq ft (высокая опасность/высокостеллажное хранение — 40,000 sq ft). Ист.: ограничения площади защиты системы NFPA 13."},
  {id:100, q:"В иерархии проектирования роль NFPA 13 по отношению к принимающему строительному кодексу состоит в том, чтобы:", opts:["Отменять строительный кодекс во всех случаях","Определять нагрузку по числу людей","Заменять AHJ","Служить стандартом установки, на который ссылается кодекс для спринклерных систем"], re:"Строительный/пожарный кодекс ссылается на NFPA 13 как на стандарт установки; кодекс и AHJ остаются юридической властью. Ист.: структура стандартов, на которые ссылается модельный кодекс."},
  {id:101, q:"Что представляет собой номинальный K-фактор спринклера при проектировании?", opts:["Тепловую чувствительность (индекс времени срабатывания) рабочего элемента","Температуру, при которой срабатывает рабочий элемент","Максимальную площадь покрытия, которую спринклер может защищать","Коэффициент расхода, связывающий поток с квадратным корнем из давления (Q = K√P)"], re:"K-фактор — это коэффициент расхода в формуле Q = K√P, где Q — поток (gpm), а P — давление (psi). NFPA 13 предписывает использовать номинальный K-фактор для гидравлических расчётов."},
  {id:102, q:"Спринклер стандартного распыления (standard-spray) с номинальным K-фактором 5.6 при потоке под давлением 7 psi выдаёт примерно сколько gpm? (Q = K√P)", opts:["Около 14.8 gpm","Около 5.6 gpm","Около 39 gpm","Около 25 gpm"], re:"Q = K√P = 5.6 × √7 = 5.6 × 2.646 ≈ 14.8 gpm. K-фактор, умноженный на квадратный корень из давления, даёт расход."},
  {id:103, q:"Наиболее распространённый номинальный K-фактор, исторически используемый для спринклеров стандартного распыления лёгкой и обычной опасности:", opts:["K-2.8","K-5.6","K-11.2","K-25.2"], re:"K-5.6 (отверстие 1/2 дюйма) — традиционный K-фактор стандартного распыления для лёгкой и обычной опасности. NFPA 13 перечисляет номинальные K-факторы; K-5.6 — давно устоявшийся базовый вариант."},
  {id:104, q:"По сравнению со спринклером K-5.6 при том же давлении, спринклер K-11.2 выдаёт примерно:", opts:["Половину потока","Тот же поток","В четыре раза больше потока","В два раза больше потока"], re:"Поскольку поток пропорционален K, удвоение K с 5.6 до 11.2 удваивает расход при заданном давлении (Q = K√P)."},
  {id:105, q:"Когда водоснабжение обеспечивает ограниченное давление, но достаточный объём, выбор спринклера с бо́льшим K-фактором выгоден, потому что он:", opts:["Автоматически позволяет более широкий шаг расстановки спринклеров","Снижает требуемую расчётную интенсивность","Подаёт требуемый поток при более низком рабочем давлении","Снижает требуемый температурный класс"], re:"Бо́льший K-фактор подаёт тот же поток при более низком давлении (Q = K√P), поэтому он предпочтителен там, где давление подачи ограничено. Пределы шага расстановки и интенсивности устанавливаются независимо."},
  {id:106, q:"Для применений складирования NFPA 13 обычно требует минимальный номинальный K-фактор не менее:", opts:["K-2.8","K-8.0","K-4.2","K-25.2"], re:"Защита складирования требует бо́льших отверстий для подачи более высоких интенсивностей; критерии складирования NFPA 13 обычно требуют спринклеры K-8.0 (и крупнее). K-2.8 и K-4.2 ограничены применениями лёгкой опасности/жилыми."},
  {id:107, q:"Спринклер вертикального распыления (upright) выбирают вместо подвесного (pendent) главным образом тогда, когда:", opts:["Ветвь трубопровода проходит открыто под потолком/конструкцией","Чистовой потолок скрывает трубопровод","Требуется покрытие настенным спринклером от одной стены","Требуется защита складирования ESFR"], re:"Вертикальные спринклеры используют на открытых ветвях трубопровода (например, под открытой конструкцией), чтобы дефлектор правильно направлял воду вниз/наружу. Подвесные опускаются ниже чистовых потолков."},
  {id:108, q:"Настенный спринклер стандартного распыления (standard sidewall spray) наиболее уместен там, где:", opts:["Должно защищаться высокостеллажное складирование","Зоны процессов повышенной опасности требуют шага расстановки 12 ft","Используется защита ESFR только от потолка","Ветвь трубопровода нельзя проложить по потолку, и покрытие должно идти от стены"], re:"Настенные спринклеры выдают полупараболоид от стены и применяются там, где верхний трубопровод непрактичен. NFPA 13 ограничивает настенные спринклеры в основном помещениями лёгкой и обычной опасности (Группа 1)."},
  {id:109, q:"Настенные спринклеры стандартного распыления обычно ограничены NFPA 13 какими видами эксплуатации?", opts:["Только повышенная опасность Группа 2","Только лёгкая опасность и обычная опасность (Группа 1)","Только высокостеллажное складирование","Все виды эксплуатации без ограничений"], re:"NFPA 13 ограничивает настенные спринклеры стандартного распыления лёгкой опасностью и обычной опасностью Группы 1; другие виды опасности требуют верхнего распыления или специальных спринклеров."},
  {id:110, q:"Сухой подвесной спринклер (dry-pendent) выбирают главным образом для того, чтобы:", opts:["Увеличить K-фактор водозаполненной системы","Позволить подвесному спринклеру опуститься от водозаполненной системы в неотапливаемое/промерзающее помещение без застоя воды в головке","Обеспечить быстрое срабатывание","Защитить от высоких температур потолка"], re:"Сухой подвесной/сухой настенный спринклер удерживает воду в отапливаемой части системы, позволяя одной головке заходить в морозильную камеру или неотапливаемую зону без замерзания. Он не меняет K-фактор или класс срабатывания."},
  {id:111, q:"Скрытые подвесные спринклеры (concealed pendent) с накладной пластиной выбирают главным образом ради:", opts:["Более высокой интенсивности расхода","Более широкого максимального шага расстановки, чем у стандартных подвесных","Складских видов эксплуатации","Эстетики в чистовых потолках, при этом накладная пластина отпадает при заданной температуре"], re:"Скрытые спринклеры прячут головку за накладной пластиной, которая отделяется при заданной температуре (обычно 135 °F) до срабатывания спринклера; это эстетический выбор для чистовых потолков, и они следуют шагу расстановки стандартного распыления."},
  {id:112, q:"Какой тип спринклера специально сертифицирован и предназначен для защиты высокостеллажного и стеллажного складирования с уровня потолка, часто устраняя внутристеллажные спринклеры?", opts:["ESFR (Early Suppression Fast Response)","Настенный стандартного распыления","Жилой спринклер","Открытый дренчерный спринклер"], re:"Спринклеры ESFR спроектированы для подавления (а не просто контроля) складских пожаров с потолка, часто устраняя необходимость во внутристеллажных спринклерах в пределах их сертифицированных ограничений."},
  {id:113, q:"Жилые спринклеры (по жилым положениям NFPA 13) сертифицированы главным образом для того, чтобы:", opts:["Максимизировать интенсивность контроля на складах","Защищать химические процессы повышенной опасности","Обеспечить пригодные для жизни условия для эвакуации жильцов в жилых помещениях с помощью быстро срабатывающих элементов","Заменить ESFR в стеллажном складировании"], re:"Жилые спринклеры используют быстро срабатывающие элементы и схемы смачивания стен для повышения безопасности жизни/пригодности условий в жилых помещениях; они не являются головками контроля/подавления для промышленного складирования."},
  {id:114, q:"Спринклер контролируемого режима специального применения (CMSA, ранее 'крупнокапельный') характеризуется:", opts:["Крупными каплями воды и высоким импульсом для проникновения через факел пожара при складировании","Малым отверстием и быстро срабатывающим элементом для офисов","Накладной пластиной для скрытого монтажа","Только настенным распылением"], re:"Спринклеры CMSA образуют крупные капли высокого импульса, проникающие через факел пожара для защиты складирования; это вариант контролируемого режима, отличный от спринклеров подавления ESFR."},
  {id:115, q:"Для гидравлически рассчитанной системы лёгкой опасности NFPA 13 обычно требует спринклеры с номинальным K-фактором не менее:", opts:["K-1.4","K-2.8","K-5.6","K-14.0"], re:"Гидравлически рассчитанные системы лёгкой и обычной опасности обычно используют K-5.6 или крупнее; меньшие отверстия (K-2.8/K-4.2) ограничены конкретными сертифицированными применениями лёгкой опасности."},
  {id:116, q:"Открытый спринклер (без термочувствительного элемента) используется в:", opts:["Дренчерных системах, где все головки выдают поток одновременно при срабатывании системы","Стандартных водозаполненных системах лёгкой опасности","Помещениях обычной опасности с быстрым срабатыванием","Потолках складирования ESFR"], re:"Открытые спринклеры не имеют плавкого/колбового элемента и используются в дренчерных системах, где отдельная система обнаружения открывает дренчерный клапан, и вода идёт из каждой головки одновременно."},
  {id:117, q:"Выбор спринклера расширенного покрытия (EC) вместо спринклера стандартного распыления главным образом позволяет проектировщику:", opts:["Снизить требуемую расчётную интенсивность","Исключить гидравлические расчёты","Снизить требуемый температурный класс","Покрыть бо́льшую площадь пола на спринклер в пределах его конкретной сертификации"], re:"Спринклеры EC сертифицированы для бо́льших площадей защиты и более широких шагов расстановки, чем стандартное распыление, сокращая число головок. Их следует использовать строго в пределах сертификации, и они по-прежнему требуют гидравлического расчёта."},
  {id:118, q:"Для спринклеров стандартного распыления при ЛЁГКОЙ опасности (конструкция без препятствий) максимальная площадь защиты на спринклер составляет:", opts:["130 ft²","196 ft²","400 ft²","225 ft²"], re:"Таблица NFPA 13 для стандартного распыления: максимальная площадь защиты для лёгкой опасности составляет 225 ft² на спринклер (например, 15 ft × 15 ft)."},
  {id:119, q:"Для спринклеров стандартного распыления при ОБЫЧНОЙ опасности (конструкция без препятствий) максимальная площадь защиты на спринклер составляет:", opts:["225 ft²","130 ft²","100 ft²","400 ft²"], re:"NFPA 13: максимальная площадь защиты для обычной опасности при стандартном распылении составляет 130 ft² на спринклер."},
  {id:120, q:"Для спринклеров стандартного распыления при ЛЁГКОЙ или ОБЫЧНОЙ опасности максимальное расстояние между спринклерами на ветви трубопровода составляет:", opts:["10 ft","15 ft","12 ft","20 ft"], re:"NFPA 13 устанавливает максимальный шаг расстановки 15 ft между спринклерами стандартного распыления как для лёгкой, так и для обычной опасности."},
  {id:121, q:"Для спринклеров стандартного распыления при ПОВЫШЕННОЙ опасности максимальное расстояние между спринклерами составляет:", opts:["15 ft","8 ft","20 ft","12 ft"], re:"NFPA 13 ограничивает шаг расстановки стандартного распыления повышенной опасности до 12 ft (системы по сортаменту труб и гидравлически рассчитанные при интенсивностях 0.25 gpm/ft² или выше)."},
  {id:122, q:"Для спринклеров стандартного распыления ПОВЫШЕННОЙ опасности максимальная площадь защиты на спринклер (гидравлически рассчитанная, интенсивность менее 0.25 gpm/ft²) составляет:", opts:["400 ft²","100 ft²","225 ft²","130 ft²"], re:"Для повышенной опасности гидравлически рассчитанные системы ниже 0.25 gpm/ft² могут использовать до 130 ft²; при 0.25 gpm/ft² и выше (и по сортаменту труб) максимум составляет 100 ft²."},
  {id:123, q:"Площадь защиты на спринклер (A_s) определяется каким соотношением?", opts:["A_s = S − L","A_s = K × √P","A_s = S × L, где S — размер вдоль ветви, а L — размер между ветвями","A_s = интенсивность × давление"], re:"NFPA 13 вычисляет площадь защиты на спринклер как A_s = S × L, где S — расстояние вдоль ветви трубопровода (бо́льшее из удвоенного расстояния до стены или шага расстановки), а L — расстояние между ветвями, оба берутся как большее применимое значение."},
  {id:124, q:"При вычислении S (вдоль ветви трубопровода) для спринклера, смежного со стеной, используемый размер:", opts:["Только фактическое расстояние до стены","Всегда 15 ft","Половина расстояния до стены","Удвоенное расстояние до стены или шаг расстановки до следующего спринклера — что больше"], re:"NFPA 13 берёт S как большее из: удвоенного расстояния до стены (концевой спринклер) или расстояния до смежного спринклера. Это гарантирует, что площадь не будет занижена для концевых головок."},
  {id:125, q:"Максимальное расстояние от спринклера стандартного распыления до стены составляет:", opts:["Равно максимальному шагу расстановки между спринклерами","Половина максимально допустимого расстояния между спринклерами","Четверть ширины помещения","Всегда 4 in"], re:"NFPA 13: расстояние до стены не может превышать половину допустимого шага расстановки между спринклерами (например, 7.5 ft для схемы с шагом 15 ft)."},
  {id:126, q:"Минимальное расстояние, на котором дефлектор спринклера стандартного распыления может быть размещён от стены, составляет:", opts:["4 in","12 in","18 in","2 in"], re:"NFPA 13 требует, чтобы спринклеры находились не менее чем в 4 in от стены, чтобы стена не препятствовала формирующейся схеме распыления."},
  {id:127, q:"Минимальное допустимое расстояние между двумя спринклерами стандартного распыления (без перегородки/baffle) составляет:", opts:["4 ft","6 ft","8 ft","10 ft"], re:"NFPA 13 требует не менее 6 ft между спринклерами (измеряется вдоль уклона потолка) для предотвращения взаимного охлаждения (cold-soldering), если между ними не установлена сертифицированная перегородка."},
  {id:128, q:"Два спринклера могут располагаться ближе 6 ft между центрами только когда:", opts:["Потолок наклонный","Опасность лёгкая","Они быстро срабатывающие","Между ними установлена перегородка для защиты рабочих элементов"], re:"Сертифицированная перегородка между близко расположенными головками защищает каждый рабочий элемент от распыления другого (предотвращая взаимное охлаждение), что и есть условие, при котором NFPA 13 допускает шаг расстановки менее 6 ft."},
  {id:129, q:"'Правило малого помещения' NFPA 13 применяется к помещению лёгкой опасности, которое:", opts:["Любое помещение с наклонным потолком","Любое помещение менее 1,500 ft²","Любое помещение обычной опасности","Без препятствий, лёгкой опасности эксплуатации, и площадью 800 ft² или менее"], re:"Правило малого помещения применяется к отсеку лёгкой опасности без препятствий площадью 800 ft² или менее, позволяя размещать спринклер на расстоянии до 9 ft от любой одной стены."},
  {id:130, q:"По правилу малого помещения спринклер может быть расположен максимум на каком расстоянии от любой одной стены?", opts:["7.5 ft","12 ft","9 ft","15 ft"], re:"Правило малого помещения позволяет размещать спринклер на расстоянии до 9 ft от любой одной стены (вместо обычного предела в половину шага расстановки до стены), в пределах помещения лёгкой опасности площадью 800 ft²."},
  {id:131, q:"Спринклеры расширенного покрытия при лёгкой опасности могут быть сертифицированы для максимальной площади защиты до:", opts:["225 ft²","130 ft²","400 ft²","100 ft²"], re:"Спринклеры EC могут быть сертифицированы для покрытия до 400 ft² (например, 20 ft × 20 ft) при лёгкой опасности, что значительно выше предела 225 ft² для стандартного распыления, но только в пределах их конкретной сертификации."},
  {id:132, q:"Спринклеры расширенного покрытия должны устанавливаться:", opts:["С любым шагом расстановки по выбору проектировщика","Без гидравлического расчёта","Только в видах эксплуатации повышенной опасности","Строго в пределах площади защиты и шага расстановки, указанных в их индивидуальной сертификации"], re:"Пределы шага расстановки/площади спринклеров EC берутся из сертификации производителя, а не из обобщённых таблиц стандартного распыления, поэтому их следует применять точно так, как указано в сертификации."},
  {id:133, q:"Спринклер расположен в 7 ft от одной стены и в 6 ft от следующего спринклера вдоль ветви трубопровода. Значение S, используемое для расчёта площади защиты, составляет:", opts:["6 ft","7 ft","13 ft","14 ft"], re:"S — это большее из удвоенного расстояния до стены (2 × 7 = 14 ft) или шага расстановки спринклеров (6 ft); следовательно, S = 14 ft."},
  {id:134, q:"Если спринклеры расположены в 12 ft друг от друга вдоль ветви (S = 12 ft), а ветви трубопровода — в 10 ft друг от друга (L = 10 ft), площадь защиты на спринклер составляет:", opts:["120 ft²","22 ft²","144 ft²","100 ft²"], re:"A_s = S × L = 12 ft × 10 ft = 120 ft², что не должно превышать максимально допустимую площадь защиты для данной опасности."},
  {id:135, q:"'Правило трёх размеров' NFPA 13 для спринклеров стандартного распыления требует, чтобы спринклер был расположен от препятствия на горизонтальном расстоянии не менее:", opts:["Трёх максимальных размеров препятствия (например, ширины воздуховода), максимум до 24 in","Трёх шагов расстановки спринклеров","Трёх футов во всех случаях","Половины высоты препятствия"], re:"Правило трёх размеров: держите спринклер на расстоянии не менее трёх максимальных размеров препятствия (макс. 24 in), чтобы распыление могло проходить с обеих сторон. (Для спринклеров расширенного покрытия применяется правило четырёх размеров, макс. 36 in.)"},
  {id:136, q:"Правило трёх размеров ограничивает требуемый горизонтальный зазор от препятствия максимумом в:", opts:["12 in","18 in","24 in","36 in"], re:"Даже для очень крупных препятствий правило трёх размеров для спринклеров стандартного распыления ограничивает требуемое горизонтальное расстояние до 24 in."},
  {id:137, q:"Для спринклеров расширенного покрытия аналогичное правило препятствий — это 'правило четырёх размеров', с максимальным зазором в:", opts:["24 in","36 in","48 in","12 in"], re:"Спринклеры EC следуют правилу четырёх размеров (четыре размера препятствия), ограниченному 36 in, что отражает их бо́льшую дальность распыления."},
  {id:138, q:"По 'правилу балки', дефлектор спринклера, расположенный на уровне или выше низа балки/препятствия, должен быть отделён по горизонтали от этого препятствия не менее чем на:", opts:["12 in (1 ft)","6 in","24 in","36 in"], re:"Правило балки требует не менее 1 ft (12 in) горизонтального разделения, когда дефлектор находится на любом расстоянии выше низа препятствия, увеличиваясь по мере подъёма дефлектора (согласно таблице стандарта 'дефлектор-выше-низа-препятствия')."},
  {id:139, q:"Непрерывные препятствия шире какого размера обычно требуют установки спринклеров под ними?", opts:["Более 2 ft","Более 4 ft","Более 6 ft","Более 8 ft"], re:"NFPA 13 обычно требует спринклеры под неподвижными препятствиями шире 4 ft (например, широкие воздуховоды, настилы, столы), потому что препятствие экранирует пол под ним."},
  {id:140, q:"Когда спринклер должен быть установлен под широким препятствием, его дефлектор должен располагаться в пределах какого расстояния от низа препятствия?", opts:["В пределах 18 in","В пределах 12 in","В пределах 24 in","В пределах 36 in"], re:"NFPA 13 требует, чтобы дефлектор спринклера под широким препятствием находился не более чем в 12 in ниже низа этого препятствия, чтобы схема распыления правильно формировалась под ним."},
  {id:141, q:"Минимальный вертикальный зазор от дефлектора спринклера стандартного распыления до ВЕРХА СКЛАДИРОВАНИЯ должен составлять не менее:", opts:["12 in","24 in","18 in","36 in"], re:"NFPA 13 требует минимальный зазор 18 in между дефлектором и верхом складирования, чтобы схема распыления могла полностью сформироваться до достижения товара."},
  {id:142, q:"Для спринклеров ESFR минимальный зазор от дефлектора до верха складирования составляет:", opts:["18 in","24 in","36 in","12 in"], re:"Защита складирования ESFR требует минимального зазора 36 in от дефлектора до верха складирования — больше, чем 18 in, используемые для стандартного распыления, — чтобы распыление в режиме подавления могло сформироваться."},
  {id:143, q:"Для конструкции без препятствий дефлектор подвесного или вертикального спринклера стандартного распыления должен располагаться на каком расстоянии ниже потолка?", opts:["Максимум 36 in ниже потолка","Ровно 6 in ниже потолка","Минимум 4 in ниже потолка","Минимум 1 in и максимум 12 in ниже потолка"], re:"NFPA 13: под потолками без препятствий (гладкими) дефлекторы подвесных/вертикальных спринклеров стандартного распыления размещают на 1 in до 12 in ниже потолка, чтобы сбалансировать сбор тепла и формирование схемы распыления."},
  {id:144, q:"Для настенных спринклеров стандартного распыления дефлектор обычно располагается на каком расстоянии ниже потолка?", opts:["1 in до 6 in","12 in до 18 in","4 in до 6 in","18 in до 24 in"], re:"NFPA 13 обычно требует размещать дефлекторы настенных спринклеров на 4 in до 6 in ниже потолка (специальные сертификации могут допускать 6 in до 18 in)."},
  {id:145, q:"Назначение правил препятствий при расстановке спринклеров по своей сути состоит в том, чтобы:", opts:["Увеличить K-фактор спринклера","Снизить требуемый температурный класс","Обеспечить, чтобы схема распыления достигала пола/опасности, не будучи заблокированной или затенённой","Позволить более широкий максимальный шаг расстановки"], re:"Правила препятствий защищают сформированную схему распределения воды от блокировки или 'затенения', которое оставило бы незащищённые зоны — основная причина правил трёх размеров/балки/под-препятствием."},
  {id:146, q:"Воздуховод шириной 24 in проходит под потолком. Применяя правило трёх размеров, спринклер должен располагаться по горизонтали не менее чем на каком расстоянии от ближней кромки воздуховода?", opts:["72 in","24 in (ограничено максимумом в 24 in)","12 in","48 in"], re:"Три размера в 24 in составляют 72 in, но правило ограничивает требуемое горизонтальное расстояние максимумом в 24 in; следовательно, требуется 24 in."},
  {id:147, q:"Спринклеры под открытой решёткой или препятствием решётчатого типа:", opts:["Никогда не требуются независимо от размера","Могут не требоваться, если препятствие достаточно открыто для пропуска воды/тепла, согласно положениям стандарта","Всегда требуют головок ESFR","Должны располагаться с шагом максимум 4 ft"], re:"Открытая решётка, пропускающая тепло и воду, может рассматриваться иначе, чем сплошные препятствия; NFPA 13 имеет особые положения для открытой/решётчатой конструкции вместо общих требований к спринклерам под препятствием."},
  {id:148, q:"Когда спринклеры располагаются ближе 6 ft, перегородка между ними должна:", opts:["Быть горючей, чтобы выгореть раньше","Устанавливаться только на настенных спринклерах","Быть высотой не менее 24 in","Быть сплошной и жёсткой, рассчитанной на экранирование рабочих элементов, и оставаться на месте во время срабатывания"], re:"NFPA 13 требует сплошную жёсткую перегородку (примерно 8 in длиной, 6 in высотой, установленную между дефлекторами), которая остаётся на месте до и во время срабатывания для экранирования смежных рабочих элементов."},
  {id:149, q:"Подвесной светильник шириной 10 in висит под потолочным спринклером стандартного распыления. По правилу трёх размеров минимальный требуемый горизонтальный зазор до спринклера составляет:", opts:["24 in (предел правила, так как 3 × 10 in = 30 in превышает 24 in)","5 in","10 in","30 in"], re:"Три размера в 10 in составляют 30 in, но правило трёх размеров ограничивает требуемый горизонтальный зазор максимумом в 24 in; следовательно, требуется только 24 in, а не арифметическое значение 30 in."},
  {id:150, q:"Для препятствий у стены (таких как софит), через которые настенный спринклер должен распылять, проектировщик должен проверить:", opts:["K-фактор составляет не менее 11.2","Препятствие не прерывает сертифицированную горизонтальную дальность распыления спринклера, и дефлектор обходит его согласно стандарту","Температурный класс высокий","Минимальный шаг расстановки составляет 4 ft"], re:"Расстановка настенных спринклеров должна держать софиты, световые ниши и подобные настенные препятствия вне сертифицированной траектории распыления, чтобы схема не блокировалась, в соответствии с положениями NFPA 13 о препятствиях."},
  {id:151, q:"Минимальный зазор 18 in до складирования увеличивается до 36 in для какого складируемого товара?", opts:["Резиновые шины","Бумажные архивы","Консервы","Пустые поддоны"], re:"NFPA 13 требует не менее 36 in зазора от дефлекторов стандартного распыления при складировании резиновых шин, что отражает тяжёлую пожарную нагрузку складирования шин."},
  {id:152, q:"Максимальная площадь защиты на спринклер ESFR составляет:", opts:["130 ft²","144 ft²","225 ft²","100 ft²"], re:"NFPA 13 ограничивает покрытие спринклера ESFR максимумом в 100 ft² на спринклер."},
  {id:153, q:"Максимальное расстояние между спринклерами ESFR составляет:", opts:["12 ft","15 ft","20 ft","8 ft"], re:"Спринклеры ESFR имеют максимальный шаг расстановки 12 ft между головками (с дополнительными ограничениями при больших высотах потолка)."},
  {id:154, q:"Минимальный шаг расстановки между спринклерами ESFR составляет:", opts:["8 ft","6 ft","4 ft","10 ft"], re:"NFPA 13 устанавливает минимальный шаг расстановки 8 ft между спринклерами ESFR (больше, чем минимум 6 ft для стандартного распыления), чтобы избежать взаимного охлаждения быстро срабатывающих элементов."},
  {id:155, q:"ESFR расшифровывается как:", opts:["Extended Spray Fire Resistant","Enhanced Storage Flow Regulator","Extra Spacing Flow Rated","Early Suppression Fast Response"], re:"ESFR = Early Suppression Fast Response — быстро срабатывающий спринклер, спроектированный для подавления складских пожаров с потолка, а не просто их контроля."},
  {id:156, q:"Принципиальное различие между спринклером ESFR 'режима подавления' и спринклером 'режима контроля' состоит в том, что ESFR стремится:", opts:["Только предварительно смочить смежные товары","Действительно потушить/подавить пожар, подавая большой объём быстро к очагу пожара","Срабатывать при более высокой температуре","Сократить число внутристеллажных уровней на один"], re:"ESFR подаёт высокий быстрый поток, предназначенный для подавления (сбивания) пожара, тогда как спринклеры режима контроля стремятся контролировать распространение пожара и предварительно смачивать окружение до ручного тушения."},
  {id:157, q:"Потолочная защита ESFR проектируется гидравлически на основе:", opts:["Интенсивности на площади","Только сортамента труб","Фиксированной интенсивности 0.20 gpm/ft²","Минимального рабочего ДАВЛЕНИЯ для заданного числа спринклеров (например, 12 наиболее удалённых)"], re:"Проектирование ESFR основано на давлении: сертификация задаёт минимальное рабочее давление для набора расчётных спринклеров (обычно 12 гидравлически наиболее требовательных, по четыре на каждой из трёх линий), а не интенсивность/площадь."},
  {id:158, q:"Типичные номинальные K-факторы для спринклеров ESFR включают:", opts:["K-2.8 и K-4.2","K-14.0, K-16.8, K-22.4 и K-25.2","Только K-5.6","K-1.4"], re:"Спринклеры ESFR используют крупные отверстия — распространённые номинальные K-факторы — это K-14.0, K-16.8, K-22.4 и K-25.2 — для подачи высоких потоков, необходимых для подавления."},
  {id:159, q:"Системы ESFR обычно НЕ допускаются в каком типе системы трубопровода, потому что задержка в подаче воды подрывает подавление?", opts:["Водозаполненные системы","Воздушные (сухотрубные) системы (кроме случаев, специально сертифицированных/разрешённых)","Сетчатые (gridded) системы","Кольцевые (looped) системы"], re:"Поскольку подавление зависит от немедленной подачи полного потока, ESFR обычно применяется в водозаполненных системах; сухие системы задерживают воду и ограничены специально сертифицированными схемами."},
  {id:160, q:"Внутристеллажные спринклеры добавляются в проект складирования главным образом для того, чтобы:", opts:["Заменить потолочные спринклеры","Снизить требование к зазору складирования","Увеличить потолочный шаг расстановки","Обеспечить защиту внутри стеллажа там, где потолочное распыление не может достичь пожара"], re:"Внутристеллажные спринклеры защищают внутри складского массива там, где потолочное распыление блокируется верхними грузами; они дополняют (а не заменяют) потолочную защиту, когда вариант только с потолка недостаточен."},
  {id:161, q:"Ключевое преимущество выбора потолочной защиты ESFR для стеллажного складирования состоит в том, что в пределах своей сертификации она может:", opts:["Снизить требуемый зазор до 6 in","Устранить необходимость в водоснабжении","Позволить неограниченную высоту складирования","Устранить необходимость во внутристеллажных спринклерах"], re:"Главное проектное преимущество ESFR в том, что в пределах сертифицированных ограничений по высоте потолка и высоте складирования он может защищать стеллажное складирование только с потолка, устраняя внутристеллажные спринклеры."},
  {id:162, q:"Зазор от дефлекторов ESFR до верха складирования должен составлять минимум:", opts:["18 in","24 in","36 in","12 in"], re:"ESFR требует минимальный зазор 36 in от дефлектора до верха складирования, вдвое больше 18 in, используемых для стандартного распыления, чтобы распыление подавления могло сформироваться."},
  {id:163, q:"Критерии защиты складских видов эксплуатации наиболее напрямую зависят от какого набора переменных?", opts:["Только общей площади пола здания","Только цвета спринклера","Класса товара, метода/высоты складирования и высоты потолка","Числа выходов"], re:"Проектирование складирования (интенсивности, давления ESFR, потребности во внутристеллажных спринклерах) определяется классификацией товара, компоновкой и высотой складирования и высотой потолка — ключевыми переменными в главах NFPA 13 о складировании."},
  {id:164, q:"Спринклеры CMSA (контролируемый режим специального применения) отличаются от ESFR тем, что спринклеры CMSA предназначены для того, чтобы:", opts:["Контролировать пожар (ограничивать рост и предварительно смачивать), а не подавлять его","Полностью подавить пожар","Работать только как открытые дренчерные головки","Обеспечивать жилое покрытие безопасности жизни"], re:"CMSA — это технология режима контроля (крупные капли, высокий импульс), предназначенная для контроля складских пожаров, тогда как ESFR — это технология режима подавления, стремящаяся потушить пожар."},
  {id:165, q:"Для защиты складирования NFPA 13 обычно требует номинальный K-фактор спринклера не менее:", opts:["K-8.0","K-4.2","K-2.8","K-1.4"], re:"Интенсивности складирования требуют бо́льших отверстий; критерии складирования NFPA 13 обычно требуют K-8.0 или крупнее (CMSA и ESFR используют ещё бо́льшие K-факторы)."},
  {id:166, q:"Когда ESFR нельзя использовать (например, потому что высота складирования или потолка превышает его сертификацию), распространённый альтернативный подход к потолочному проектированию для складирования — это:", opts:["Жилые спринклеры","Открытый дренчер без обнаружения","Защита интенсивностью/площадью CMSA или режима контроля, возможно, с внутристеллажными спринклерами","Только настенные спринклеры"], re:"Где превышены ограничения ESFR, проектировщики прибегают к потолочной защите режима контроля (CMSA или стандартной интенсивности/площади режима контроля), часто в сочетании с внутристеллажными спринклерами."},
  {id:167, q:"Главная причина, по которой внутристеллажные спринклеры могут потребоваться даже с потолочными спринклерами режима контроля, состоит в том, что:", opts:["Потолочные спринклеры слишком холодные","Внутристеллажные спринклеры заменяют пожарный насос","Потолочные спринклеры не могут достичь пожара глубоко внутри высоких стеллажей","Товар негорючий"], re:"Высокое плотное стеллажное складирование блокирует потолочное распыление от достижения пожаров на нижних уровнях; внутристеллажные спринклеры размещают воду внутри массива для устранения этого затенения."},
  {id:168, q:"Эффективность защиты ESFR наиболее чувствительна к препятствиям, потому что:", opts:["Препятствия могут отклонить высокоимпульсное распыление и помешать ему достичь очага пожара","Его капли очень малы и легко блокируются","Он использует низкое рабочее давление","Он работает как головка режима контроля"], re:"ESFR опирается на высокоимпульсную струю, проникающую через факел к пожару; препятствия рядом с головками могут отклонить это распыление, поэтому ESFR имеет строгие правила препятствий (и зазоров)."},
  {id:169, q:"Диапазон температурной классификации для спринклера ОБЫЧНОЙ температуры составляет:", opts:["135–170°F","100–134°F","175–225°F","250–300°F"], re:"NFPA 13: спринклеры обычной температуры имеют температурный класс 135–170°F (обычно 135°F или 155°F)."},
  {id:170, q:"Диапазон температурной классификации для спринклера ПРОМЕЖУТОЧНОЙ температуры составляет:", opts:["135–170°F","250–300°F","175–225°F","325–375°F"], re:"NFPA 13: спринклеры промежуточной температуры классифицированы на 175–225°F (например, 200°F)."},
  {id:171, q:"Диапазон температурной классификации для спринклера ВЫСОКОЙ температуры составляет:", opts:["250–300°F","175–225°F","135–170°F","100–134°F"], re:"NFPA 13: спринклеры высокой температуры классифицированы на 250–300°F, используются там, где ожидаются повышенные температуры окружающей среды."},
  {id:172, q:"Спринклеры рядом с агрегатным воздухонагревателем, световым фонарём или другим источником тепла обычно требуют:", opts:["Более низкого (обычного) температурного класса","Только быстрого срабатывания","Более высокого температурного класса во избежание преждевременного/ложного срабатывания","Бо́льшего K-фактора"], re:"NFPA 13 требует спринклеры промежуточной или высокой температуры рядом с источниками тепла (агрегатные воздухонагреватели, световые фонари, механическое оборудование), чтобы нормальное тепло окружающей среды не вызывало непреднамеренного срабатывания."},
  {id:173, q:"Стандартизированный цвет жидкости в стеклянной колбе для спринклера ОБЫЧНОЙ температуры (135°F):", opts:["Оранжевый (или красный для 155°F)","Зелёный","Синий","Лиловый"], re:"Цветовые коды стеклянной колбы: 135°F — оранжевый, а 155°F — красный (оба класса обычной температуры). Цвет указывает рабочую температуру, независимо от скорости срабатывания."},
  {id:174, q:"Для спринклера со стеклянной колбой ЖЁЛТАЯ или ЗЕЛЁНАЯ колба указывает на какой температурный класс?", opts:["Промежуточный","Обычный","Высокий","Сверхвысокий"], re:"Жёлтые (175°F) и зелёные (200°F) стеклянные колбы обозначают промежуточный температурный класс согласно цветовому коду NFPA 13."},
  {id:175, q:"Максимальная ожидаемая температура окружающей среды у потолка определяет выбор у спринклера:", opts:["K-фактора","Стиля дефлектора","Класса срабатывания (QR/SR)","Температурного класса"], re:"Температурный класс выбирают так, чтобы спринклер не срабатывал от нормального тепла окружающей среды; NFPA 13 связывает класс с максимальной ожидаемой температурой окружающей среды у потолка."},
  {id:176, q:"Спринклер быстрого срабатывания (QR) определяется индексом времени срабатывания (RTI):", opts:["80 (m·s)^1/2 или более","50 (m·s)^1/2 или менее","Ровно 100 (m·s)^1/2","Более 350 (m·s)^1/2"], re:"Быстро срабатывающие элементы имеют RTI 50 (m·s)^1/2 или менее; элементы стандартного срабатывания имеют RTI 80 (m·s)^1/2 или более."},
  {id:177, q:"Спринклер стандартного срабатывания (SR) имеет индекс времени срабатывания (RTI) примерно:", opts:["50 или менее","Всегда 250","Всегда 100","80 или более"], re:"Спринклеры стандартного срабатывания имеют RTI около 80 (m·s)^1/2 или более, что означает более толстый термоэлемент, который реагирует медленнее, чем быстрое срабатывание (RTI ≤ 50)."},
  {id:178, q:"В водозаполненном виде эксплуатации ЛЁГКОЙ опасности NFPA 13 обычно требует какой класс срабатывания?", opts:["Стандартное срабатывание","Быстрое срабатывание","Только высокая температура","Открытые спринклеры"], re:"NFPA 13 обычно требует спринклеры быстрого срабатывания во всех водозаполненных видах эксплуатации лёгкой опасности для повышения безопасности жизни, с ограниченными исключениями."},
  {id:179, q:"Спринклеры быстрого срабатывания и стандартного срабатывания в одном и том же отсеке:", opts:["Можно свободно смешивать","Должны использовать только один и тот же K-фактор","Оба должны быть высокотемпературными","Не должны смешиваться в одном отсеке"], re:"NFPA 13 запрещает смешивать спринклеры QR и SR в одном отсеке, потому что гидравлическое/рабочее проектирование предполагает единообразное поведение срабатывания по всей расчётной площади."},
  {id:180, q:"Класс срабатывания (QR против SR) определяется у спринклера:", opts:["Размером отверстия (K-фактором)","Тепловой чувствительностью / RTI рабочего элемента","Только температурным классом","Ориентацией дефлектора"], re:"Класс срабатывания является функцией тепловой чувствительности рабочего элемента, выраженной как RTI; он не зависит от температурного класса и K-фактора."},
  {id:181, q:"Быстро срабатывающий элемент жилого спринклера выбирают главным образом для того, чтобы:", opts:["Срабатывать раньше для улучшения пригодности условий и времени эвакуации жильцов","Увеличить интенсивность расхода","Повысить температурный класс","Позволить более широкий шаг расстановки на складах"], re:"Жилые спринклеры используют быстро срабатывающие элементы, чтобы активироваться рано, поддерживая пригодные для жизни условия для эвакуации жильцов — основа безопасности жизни жилой сертификации."},
  {id:182, q:"Два спринклера с одинаковым K-фактором и температурным классом всё же могут различаться по характеристикам, потому что у них могут быть разные:", opts:["Классы срабатывания (RTI), то есть быстрое против стандартного срабатывания","Размеры резьбы трубопровода","Только цвета окраски","Сертифицирующие органы"], re:"Температурный класс задаёт рабочую температуру, но RTI (класс срабатывания) задаёт, насколько быстро элемент её достигает; два в остальном идентичных спринклера могут быть QR или SR."},
  {id:183, q:"Для спринклера рамочного типа (без колбы) температурный класс определяется по:", opts:["Размеру резьбы","Цвету, нанесённому на рычаги рамки (или цвету спая)","Размеру дефлектора","Форме накладной пластины"], re:"NFPA 13 предписывает цветовую маркировку рычагов рамки для спринклеров спайного типа (например, без окраски/чёрный = обычный, белый = промежуточный, синий = высокий) для указания температурного класса."},
  {id:184, q:"Спринклеры ESFR по своей сути относятся к какому классу срабатывания?", opts:["Стандартное срабатывание","Переменное","Быстрое срабатывание (RTI ≤ 50)","Только высокая температура"], re:"ESFR означает Early Suppression FAST Response; элемент является быстро срабатывающим (RTI ≤ 50), чтобы спринклер открывался достаточно рано для подавления складского пожара."},
  {id:185, q:"Когда спринклер со стеклянной колбой показывает СИНЮЮ колбу, температурный класс:", opts:["Обычный","Высокий (286°F)","Промежуточный","Жилой"], re:"Синяя стеклянная колба соответствует 286°F, что попадает в класс высокой температуры согласно цветовому коду колб NFPA 13."},
  {id:186, q:"В методе интенсивность/площадь 'интенсивность' выражается в единицах:", opts:["gpm на спринклер","gpm/ft² (галлоны в минуту на квадратный фут)","psi на ft²","ft² на спринклер"], re:"Расчётная интенсивность — это расход на единицу площади пола, gpm/ft², применяемый на расчётной площади для определения гидравлической потребности."},
  {id:187, q:"Типичная расчётная интенсивность ЛЁГКОЙ опасности, используемая в методе интенсивность/площадь, составляет примерно:", opts:["0.05 gpm/ft²","0.30 gpm/ft²","0.20 gpm/ft²","0.10 gpm/ft²"], re:"Лёгкая опасность обычно проектируется в районе 0.10 gpm/ft² на расчётной площади (например, 1,500 ft² для метода кривой)."},
  {id:188, q:"Представительная расчётная точка ОБЫЧНОЙ опасности Группы 2:", opts:["0.10 gpm/ft² на 1,500 ft²","0.20 gpm/ft² на 1,500 ft²","0.05 gpm/ft² на 3,000 ft²","0.60 gpm/ft² на 2,500 ft²"], re:"Обычная опасность Группы 2 обычно составляет 0.20 gpm/ft², применяемые на расчётной площади 1,500 ft² в методе интенсивность/площадь."},
  {id:189, q:"Минимальный расход, требуемый от одного спринклера, равен:", opts:["Расчётной интенсивности, делённой на площадь","K-фактору, умноженному на площадь","Расчётной интенсивности, умноженной на площадь защиты спринклера (A_s)","Давлению, умноженному на K-фактор"], re:"Минимальный поток от спринклера = интенсивность (gpm/ft²) × площадь защиты A_s (ft²). Это задаёт минимальное давление через Q = K√P."},
  {id:190, q:"Спринклер, защищающий 130 ft² при интенсивности обычной опасности 0.20 gpm/ft², должен выдавать не менее:", opts:["13 gpm","26 gpm","6.5 gpm","65 gpm"], re:"Требуемый поток = интенсивность × площадь = 0.20 gpm/ft² × 130 ft² = 26 gpm минимум от этого спринклера."},
  {id:191, q:"В подходе интенсивность/площадь увеличение принятой расчётной ПЛОЩАДИ обычно:", opts:["Повышает требуемую интенсивность вдоль кривой (больше площади при немного меньшей интенсивности, или наоборот) согласно расчётной кривой","Снижает требуемую интенсивность","Не влияет на потребность","Исключает гидравлический расчёт"], re:"Классические кривые интенсивность/площадь обменивают интенсивность на площадь: выбор бо́льшей площади меняет интенсивность согласно кривой. (Издание NFPA 13 2022 года ограничило, а издание 2025 года устранило эти кривые в пользу единственной расчётной точки.)"},
  {id:192, q:"Классификация опасности вида эксплуатации выбирается главным образом на основе:", opts:["Количества и горючести содержимого и ожидаемой пожарной нагрузки","Только высоты здания","Цвета спринклера","Числа этажей"], re:"NFPA 13 классифицирует виды эксплуатации (лёгкая, обычная 1/2, повышенная 1/2) по горючести и количеству содержимого и ожидаемой скорости выделения тепла — основа для выбора интенсивности и площади."},
  {id:193, q:"Какой пример вида эксплуатации обычно классифицируется как ЛЁГКАЯ опасность?", opts:["Авторемонтная мастерская","Операция окраски распылением","Офис, церковь или школьный класс","Склад легковоспламеняющихся жидкостей"], re:"Офисы, церкви и школы — классические виды эксплуатации лёгкой опасности (низкая горючая нагрузка). Ремонтные мастерские — обычная опасность; распыление и складирование легковоспламеняющихся жидкостей — повышенная опасность."},
  {id:194, q:"Какой пример обычно классифицируется как ОБЫЧНАЯ опасность (Группа 2)?", opts:["Личный офис","Читальный зал библиотеки","Механический цех или зона авторемонта","Жилая спальня"], re:"Механические цеха и ремонтные мастерские — представительные виды эксплуатации обычной опасности Группы 2, с умеренно-высоким горючим содержимым и скоростью выделения тепла."},
  {id:195, q:"Какой пример обычно классифицируется как ПОВЫШЕННАЯ опасность?", opts:["Школьный класс","Зона розничной торговли сухими товарами","Гостиничный номер","Зона процесса распыления легковоспламеняющейся жидкости или гидравлической жидкости"], re:"Распыление легковоспламеняющихся жидкостей и процессы с горючей гидравлической жидкостью — виды эксплуатации повышенной опасности, требующие самых высоких интенсивностей и наиболее плотного шага расстановки."},
  {id:196, q:"Виды эксплуатации повышенной опасности требуют более высокой интенсивности И более плотного шага расстановки главным образом потому, что:", opts:["Потолки всегда выше","Спринклеры должны быть определённого цвета","Пожары развиваются и распространяются быстрее и выделяют больше тепла, требуя больше воды раньше по площади","Здания крупнее"], re:"Повышенная опасность подразумевает быстрый рост пожара и высокие скорости выделения тепла, поэтому NFPA 13 предписывает бо́льшие интенсивности и более плотный шаг расстановки (12 ft / ≤130 ft²) для быстрого применения большего количества воды по расчётной площади."},
  {id:197, q:"Для складских видов эксплуатации потолочная расчётная потребность чаще всего выражается как:", opts:["Только давление, без потока","Единственный фиксированный поток независимо от товара","Интенсивность (gpm/ft²) на расчётной площади или как рабочее давление ESFR для заданного числа головок","Только K-фактор"], re:"Потолочная защита складирования задаётся либо как интенсивность/площадь (режим контроля), либо, для ESFR, как минимальное рабочее давление для определённого числа расчётных спринклеров."},
  {id:198, q:"'Расчётная площадь' (или удалённая площадь) в методе интенсивность/площадь представляет собой:", opts:["Гидравлически наиболее требовательную площадь, которая, как предполагается, работает при пожаре","Всю площадь пола здания","Только площадь непосредственно под стояком (riser)","Площадь, покрываемую одним спринклером"], re:"Расчётная/удалённая площадь — это гидравлически наиболее требовательная часть системы, которая, как предполагается, работает; интенсивность применяется по ней для определения потребности у основания стояка."},
  {id:199, q:"Когда система использует спринклеры быстрого срабатывания в водозаполненной системе лёгкой или обычной опасности, NFPA 13 исторически допускал для расчётной площади:", opts:["Увеличение на 30%","Удвоение","Сокращение (до 40% при оговорённых условиях), отражающее более раннее срабатывание меньшего числа головок","Устранение надбавки на пожарные рукава"], re:"NFPA 13 исторически допускал сокращение расчётной площади (до 40% при определённых условиях потолка/уклона) для спринклеров быстрого срабатывания в водозаполненных системах лёгкой/обычной опасности, потому что более быстрое срабатывание ограничивает число спринклеров, которые, как ожидается, откроются."},
  {id:200, q:"Выбор правильной классификации опасности является основополагающим шагом проектирования, потому что он определяет:", opts:["Только цвет окраски трубопровода","Разрешение на эксплуатацию здания","Интенсивность, расчётную площадь, максимальный шаг расстановки и максимальную площадь защиты, используемые для всей расстановки","Время прибытия пожарной части"], re:"Классификация опасности задаёт интенсивность, расчётную/удалённую площадь, максимальный шаг расстановки и максимальную площадь защиты на спринклер — каждое последующее решение по расстановке и гидравлике вытекает из неё (главы NFPA 13 об эксплуатации и проектировании)."},
  {id:201, q:"В методе проектирования «интенсивность/площадь» что выражает расчётная «интенсивность» (плотность орошения)?", opts:["Число спринклеров на каждые 100 ft² пола","Потери на трение на фут ответвления","Массу запасённой воды на кубический фут пространства","Минимальный расход на единицу площади пола, в gpm на квадратный фут"], re:"Интенсивность — это минимальная требуемая интенсивность орошения по расчётной площади, выражаемая в gpm/ft² (NFPA 13, метод проектирования «интенсивность/площадь»)."},
  {id:202, q:"Для помещения лёгкой пожарной опасности (Light Hazard) обычно задаваемая расчётная интенсивность ближе всего к какому значению?", opts:["0.05 gpm/ft²","0.40 gpm/ft²","0.20 gpm/ft²","0.10 gpm/ft²"], re:"Лёгкая опасность обычно проектируется примерно при 0.10 gpm/ft² по наиболее удалённой расчётной площади (кривые «интенсивность/площадь» NFPA 13, Light Hazard)."},
  {id:203, q:"Обычная опасность группы 1 (Ordinary Hazard Group 1) чаще всего проектируется при какой интенсивности по 1,500 ft²?", opts:["0.15 gpm/ft²","0.12 gpm/ft²","0.10 gpm/ft²","0.30 gpm/ft²"], re:"Одноточечный проект для Ordinary Hazard Group 1 — 0.15 gpm/ft² по 1,500 ft² (проектирование «интенсивность/площадь» NFPA 13)."},
  {id:204, q:"Обычная опасность группы 2 (Ordinary Hazard Group 2) чаще всего проектируется при какой интенсивности по 1,500 ft²?", opts:["0.40 gpm/ft²","0.15 gpm/ft²","0.10 gpm/ft²","0.20 gpm/ft²"], re:"Одноточечный проект для Ordinary Hazard Group 2 — 0.20 gpm/ft² по 1,500 ft² (проектирование «интенсивность/площадь» NFPA 13)."},
  {id:205, q:"На кривых «интенсивность/площадь» NFPA 13, по мере увеличения выбранной РАСЧЁТНОЙ ПЛОЩАДИ при заданной опасности, требуемая интенсивность обычно что делает?", opts:["Увеличивается","Уменьшается","Остаётся в точности той же","Удваивается"], re:"Кривые имеют такой наклон, что бóльшая удалённая площадь сочетается с меньшей интенсивностью (а меньшая площадь — с большей интенсивностью) при той же опасности (концепция кривой «интенсивность/площадь» NFPA 13)."},
  {id:206, q:"Проектировщик выбирает интенсивность 0.15 gpm/ft² по расчётной площади 1,500 ft². Сколько в сумме составляет теоретический минимальный расход СПРИНКЛЕРОВ, требуемый по этой площади (до учёта рукавов, трения и переподачи)?", opts:["150 gpm","1,500 gpm","300 gpm","225 gpm"], re:"Интенсивность × площадь = 0.15 × 1,500 = 225 gpm — это минимальный спринклерный расход по расчётной площади (метод «интенсивность/площадь» NFPA 13)."},
  {id:207, q:"Для проекта повышенной опасности группы 2 (Extra Hazard Group 2) при 0.40 gpm/ft² по 2,500 ft² минимальный спринклерный расход по расчётной площади составляет:", opts:["250 gpm","1,000 gpm","625 gpm","2,500 gpm"], re:"0.40 gpm/ft² × 2,500 ft² = 1,000 gpm минимального спринклерного расхода по площади (метод «интенсивность/площадь» NFPA 13, Extra Hazard)."},
  {id:208, q:"В рамках метода «интенсивность/площадь» минимальный требуемый расход из ОДНОГО спринклера равен:", opts:["K-фактору, умноженному на расчётную площадь","Интенсивности, умноженной на площадь пола, которую защищает этот спринклер","Запасу на рукава, делённому на число оросителей","Статическому давлению, умноженному на 0.433"], re:"Минимальный расход на спринклер = интенсивность × площадь покрытия, назначенная этому спринклеру (проектирование «интенсивность/площадь» NFPA 13)."},
  {id:209, q:"Спринклер покрывает 130 ft² в помещении, спроектированном на 0.15 gpm/ft². Его минимальный требуемый расход составляет:", opts:["13.0 gpm","15.0 gpm","19.5 gpm","26.0 gpm"], re:"0.15 gpm/ft² × 130 ft² = 19.5 gpm минимального расхода для этого спринклера (метод «интенсивность/площадь» NFPA 13)."},
  {id:210, q:"Спринклер лёгкой опасности покрывает 200 ft² при расчётной интенсивности 0.10 gpm/ft². Его минимальный требуемый расход составляет:", opts:["10 gpm","20 gpm","30 gpm","200 gpm"], re:"0.10 gpm/ft² × 200 ft² = 20 gpm минимального расхода для этого оросителя (метод «интенсивность/площадь» NFPA 13)."},
  {id:211, q:"В методе «интенсивность/площадь» расчётная площадь призвана представлять какую часть системы?", opts:["Площадь, ближайшую к стояку","Весь этаж здания","Наиболее гидравлически удалённую/требовательную площадь","Только спринклеры коридора"], re:"Расчётная площадь моделирует наиболее гидравлически удалённую (требовательную) группу спринклеров; если она обеспечена, то и более близкие площади тоже (метод «интенсивность/площадь» NFPA 13)."},
  {id:212, q:"Какая пара переменных задаёт точку на кривой «интенсивность/площадь» NFPA 13?", opts:["Давление и скорость","Интенсивность и расчётная площадь","K-фактор и высота","Значение C и диаметр трубы"], re:"Каждая кривая строится с интенсивностью (gpm/ft²) по одной оси и расчётной площадью (ft²) по другой (кривые «интенсивность/площадь» NFPA 13)."},
  {id:213, q:"Если фактический расход каждого спринклера в расчётной площади превышает минимум, требуемый по интенсивности, проектировщик должен использовать:", opts:["Только расход минимальной интенсивности","Половину расчётного расхода","Фактический (больший) расчётный расход у каждого оросителя","Расход рукавной струи"], re:"Спринклеры ближе к источнику работают при большем давлении и подают БОЛЬШЕ минимума; расчёт должен использовать фактический расход каждого оросителя, никогда не меньше минимума по интенсивности (гидравлический расчёт NFPA 13)."},
  {id:214, q:"Метод «интенсивность/площадь» обеспечивает достаточное водоснабжение, гарантируя минимальную:", opts:["Интенсивность орошения по заданной рабочей площади","Толщину стенки трубы","Температурную характеристику спринклера","Число зональных управляющих клапанов"], re:"Он гарантирует минимальную интенсивность орошения, подаваемую по выбранной расчётной (рабочей) площади (метод «интенсивность/площадь» NFPA 13)."},
  {id:215, q:"Для помещений повышенной опасности (Extra Hazard) максимальная расчётная площадь на кривых обычно составляет:", opts:["1,500 ft²","2,500 ft²","5,000 ft²","10,000 ft²"], re:"Расчётные площади Extra Hazard доходят примерно до 2,500 ft² на кривых «интенсивность/площадь» (NFPA 13, Extra Hazard)."},
  {id:216, q:"По сравнению с лёгкой опасностью, помещение повышенной опасности (Extra Hazard) требует:", opts:["Меньшей интенсивности и меньшей площади","Бóльшей интенсивности и бóльшей потребности в воде","Той же интенсивности, но меньшего давления","Никакого гидравлического расчёта"], re:"Extra Hazard использует значительно бóльшие интенсивности (0.30–0.40 gpm/ft²) и бóльшую суммарную потребность, чем Light Hazard (~0.10) (классификации опасности NFPA 13)."},
  {id:217, q:"Минимальная рабочая интенсивность, выбранная для проекта, должна быть не меньше значения, требуемого для:", opts:["Цвета здания","Класса пожарной опасности помещения","Логотипа изготовителя спринклера","Местного тарифа на воду"], re:"Требуемая интенсивность устанавливается классификацией пожарной опасности помещения (Light, Ordinary, Extra) (метод «интенсивность/площадь» NFPA 13)."},
  {id:218, q:"Основное уравнение расхода спринклера:", opts:["Q = K × P","Q = K ÷ P","Q = K × √P","Q = P × √K"], re:"Расход спринклера Q (gpm) = K√P, где P — давление в отверстии в psi (гидравлический расчёт NFPA 13; формула K-фактора)."},
  {id:219, q:"В Q = K√P единицы Q и P обычно:", opts:["Q в cfm и P в дюймах водяного столба","Q в psi и P в gpm","Q в gpm и P в psi","Q в литрах и P в барах"], re:"В практике спринклеров США Q — в галлонах в минуту (gpm), а P — в фунтах на квадратный дюйм (psi) (гидравлический расчёт NFPA 13)."},
  {id:220, q:"Спринклер распыления со стандартным отверстием (1/2 дюйма) имеет номинальный K-фактор, ближайший к:", opts:["2.8","5.6","11.2","25.2"], re:"Стандартный спринклер распыления с отверстием 1/2 дюйма имеет номинальный K, равный 5.6 (NFPA 13; K-фактор стандартного спринклера распыления)."},
  {id:221, q:"Спринклер K=5.6 работает при 25 psi. Его расход составляет:", opts:["28.0 gpm","14.0 gpm","56.0 gpm","140 gpm"], re:"Q = 5.6×√25 = 5.6×5 = 28.0 gpm (Q=K√P, NFPA 13)."},
  {id:222, q:"Спринклер K=8.0 работает при 25 psi. Его расход составляет:", opts:["40.0 gpm","32.0 gpm","20.0 gpm","64.0 gpm"], re:"Q = 8.0×√25 = 8.0×5 = 40.0 gpm (Q=K√P, NFPA 13)."},
  {id:223, q:"Спринклер K=11.2 работает при 25 psi. Его расход составляет:", opts:["44.8 gpm","50.0 gpm","112 gpm","56.0 gpm"], re:"Q = 11.2×√25 = 11.2×5 = 56.0 gpm (Q=K√P, NFPA 13)."},
  {id:224, q:"Чтобы найти давление, когда известны расход и K, выражение перестраивают к виду:", opts:["P = (Q/K)²","P = Q×K","P = K/Q²","P = √(Q×K)"], re:"Решение Q=K√P относительно P даёт P = (Q/K)² (гидравлический расчёт NFPA 13)."},
  {id:225, q:"Ороситель K=5.6 должен подавать 28 gpm. Требуемое давление составляет:", opts:["5 psi","25 psi","20 psi","50 psi"], re:"P = (Q/K)² = (28/5.6)² = 5² = 25 psi (гидравлический расчёт NFPA 13)."},
  {id:226, q:"Ороситель K=8.0 должен подавать 40 gpm. Требуемое давление составляет:", opts:["16 psi","20 psi","40 psi","25 psi"], re:"P = (Q/K)² = (40/8.0)² = 5² = 25 psi (гидравлический расчёт NFPA 13)."},
  {id:227, q:"NFPA 13 устанавливает минимальное рабочее давление для большинства стандартных спринклеров распыления, равное:", opts:["7 psi","3 psi","15 psi","20 psi"], re:"Минимальное рабочее давление для стандартных спринклеров распыления составляет 7 psi (минимальное рабочее давление NFPA 13)."},
  {id:228, q:"Спринклер K=5.6 при минимальном по NFPA 13 давлении 7 psi подаёт приблизительно:", opts:["11.2 gpm","28.0 gpm","19.6 gpm","14.8 gpm"], re:"Q = 5.6×√7 = 5.6×2.646 ≈ 14.8 gpm (Q=K√P, NFPA 13)."},
  {id:229, q:"Если известно, что спринклер подаёт 30 gpm при 25 psi, его K-фактор равен:", opts:["6.0","1.2","7.5","30"], re:"K = Q/√P = 30/√25 = 30/5 = 6.0 (гидравлический расчёт NFPA 13)."},
  {id:230, q:"K-фактор спринклера зависит главным образом от его:", opts:["Размера и геометрии выпускного отверстия","Цвета рамки","Только температурной характеристики","Расстояния от стояка"], re:"K задаётся геометрией отверстия/насадки и является постоянной величиной для данной модели спринклера (NFPA 13; перечень изготовителя)."},
  {id:231, q:"Удвоение давления на спринклере изменяет его расход примерно в:", opts:["2.0","1.41","4.0","0.5"], re:"Поскольку Q∝√P, удвоение P умножает расход на √2 ≈ 1.41, а не на 2 (соотношение Q=K√P)."},
  {id:232, q:"Чтобы УДВОИТЬ расход спринклера, давление нужно увеличить в:", opts:["2","√2","4","8"], re:"Q∝√P, поэтому удвоение Q требует 2² = 4-кратного давления (соотношение Q=K√P)."},
  {id:233, q:"Спринклер с большим отверстием типа ESFR K=25.2 при 50 psi подаёт приблизительно:", opts:["126 gpm","1,260 gpm","252 gpm","178 gpm"], re:"Q = 25.2×√50 = 25.2×7.071 ≈ 178 gpm (Q=K√P; перечень K=25.2)."},
  {id:234, q:"Два одинаковых спринклера на одном ответвлении подают разный расход, потому что у них разные:", opts:["Рабочие давления","K-факторы","Температурные характеристики","Размеры резьбы"], re:"Одинаковые оросители имеют один и тот же K, поэтому разный расход возникает из-за разного рабочего давления вдоль трубы (Q=K√P, гидравлический расчёт NFPA 13)."},
  {id:235, q:"Какое уравнение задаёт NFPA 13 для потерь на трение в трубе в расчётах систем на основе воды?", opts:["Дарси-Вейсбаха","Бернулли","Хазена-Вильямса","Маннинга"], re:"NFPA 13 предписывает формулу Хазена-Вильямса для потерь на трение в гидравлических расчётах противопожарных спринклеров (гидравлический расчёт NFPA 13)."},
  {id:236, q:"Формула потерь на трение Хазена-Вильямса в NFPA 13 имеет вид p = 4.52×Q^1.85 / (C^1.85 × d^4.87). Член 'C' представляет:", opts:["Длину окружности трубы","Коэффициент внутренней шероховатости/трения трубы","Стоимость на фут","Содержание хлора"], re:"C — это коэффициент потерь на трение Хазена-Вильямса, описывающий внутреннюю гладкость трубы (формула Хазена-Вильямса NFPA 13)."},
  {id:237, q:"В формуле Хазена-Вильямса p = 4.52 Q^1.85/(C^1.85 d^4.87) 'p' — это:", opts:["Полное давление насоса","Скорость в ft/s","Потери на трение на фут трубы (psi/ft)","Высотный напор"], re:"p — это фрикционное сопротивление на фут трубы, в psi на фут (формула Хазена-Вильямса NFPA 13)."},
  {id:238, q:"В формуле Хазена-Вильямса диаметр 'd', который следует использовать, — это диаметр трубы:", opts:["Номинальный диаметр","Наружный диаметр","Диаметр резьбы","Фактический внутренний диаметр"], re:"d — это фактический внутренний диаметр трубы в дюймах, а не номинальный размер (формула Хазена-Вильямса NFPA 13)."},
  {id:239, q:"Значение C по Хазену-Вильямсу, обычно используемое для новой (без покрытия) чёрной или оцинкованной СТАЛЬНОЙ трубы в сухих/предварительного действия системах NFPA 13 и как основа таблицы, равно:", opts:["100","150","140","120"], re:"C = 120 — это значение по Хазену-Вильямсу, обычно назначаемое стальной трубе, и оно является основой таблицы эквивалентной длины NFPA 13 (таблица значений C NFPA 13)."},
  {id:240, q:"Значение C по Хазену-Вильямсу, назначаемое МЕДНОЙ трубе и трубе из CPVC/пластика, равно:", opts:["100","120","150","130"], re:"Медной трубе и трубе из CPVC/пластика назначается C = 150 (более гладкий внутренний слой) (таблица значений C NFPA 13)."},
  {id:241, q:"Более высокое значение C по Хазену-Вильямсу указывает на трубу, которая создаёт:", opts:["Бóльшие потери на трение","Меньшие потери на трение","Отсутствие расхода","Бóльшие потери по высоте"], re:"Более высокое C означает более гладкий внутренний слой и, следовательно, МЕНЬШИЕ потери на трение при том же расходе (соотношение Хазена-Вильямса)."},
  {id:242, q:"В формуле Хазена-Вильямса потери на трение возрастают с расходом Q в степени:", opts:["1.0","4.87","2.0","1.85"], re:"Потери на трение изменяются как Q^1.85 в уравнении Хазена-Вильямса (формула Хазена-Вильямса NFPA 13)."},
  {id:243, q:"В формуле Хазена-Вильямса потери на трение чрезвычайно чувствительны к диаметру, изменяясь обратно пропорционально d в степени около:", opts:["1.85","2.63","0.54","4.87"], re:"Потери на трение изменяются как 1/d^4.87, поэтому малые изменения диаметра дают большой эффект (формула Хазена-Вильямса NFPA 13)."},
  {id:244, q:"Какой выбор сам по себе БОЛЬШЕ всего снизит потери на трение при заданном расходе?", opts:["Использование трубы с немного бóльшим внутренним диаметром","Добавление большего числа фитингов","Снижение значения C","Увеличение длины трубы"], re:"Поскольку потери ∝ 1/d^4.87, увеличение диаметра даёт наиболее сильный эффект снижения потерь (формула Хазена-Вильямса)."},
  {id:245, q:"Суммарные потери на трение на участке трубы равны:", opts:["p, умноженному на значение C","p, делённому на длину трубы","p (psi/ft), умноженному на длину трубы в футах","p, умноженному на K-фактор"], re:"Суммарные потери на трение = p (psi/ft) × длина (ft), где длина включает эквивалентную длину фитингов (гидравлический расчёт NFPA 13)."},
  {id:246, q:"Для 100 gpm в стальной трубе Schedule 40 диаметром 1 дюйм (d = 1.049 дюйма, C = 120) потери на трение ближе всего к:", opts:["0.26 psi/ft","25 psi/ft","9.1 psi/ft","2.56 psi/ft"], re:"p = 4.52×100^1.85/(120^1.85×1.049^4.87) ≈ 2.56 psi/ft (формула Хазена-Вильямса NFPA 13, пересчитано)."},
  {id:247, q:"Перевод ТЕХ ЖЕ 100 gpm со стальной трубы Schedule 40 диаметром 1 дюйм на 2 дюйма (d ≈ 2.067 дюйма) изменяет потери на трение примерно с 2.56 psi/ft до приблизительно:", opts:["5.0 psi/ft","1.3 psi/ft","2.5 psi/ft","0.09 psi/ft"], re:"p = 4.52×100^1.85/(120^1.85×2.067^4.87) ≈ 0.09 psi/ft — большое снижение от увеличения диаметра (Хазена-Вильямса NFPA 13, пересчитано)."},
  {id:248, q:"Уменьшение расхода Q в трубе вдвое изменяет потери на трение по Хазену-Вильямсу примерно до:", opts:["Половины исходного","Четверти исходного","Около 28% от исходного","Того же, что и исходное"], re:"(1/2)^1.85 ≈ 0.277, поэтому потери падают примерно до 28% от исходного при уменьшении расхода вдвое (член Q^1.85 Хазена-Вильямса)."},
  {id:249, q:"Чугунной/высокопрочной трубе с цементным покрытием обычно назначают значение C по Хазену-Вильямсу, равное:", opts:["140","120","100","180"], re:"Чугуну или высокопрочному чугуну с цементным покрытием обычно назначают C = 140 (таблица значений C NFPA 13)."},
  {id:250, q:"Чугуну без покрытия и более старым/шероховатым трубам могут назначить значение C по Хазену-Вильямсу настолько низкое, как:", opts:["150","130","100","180"], re:"Чёрной трубе без покрытия/состарившейся назначают более низкое C, например 100, отражающее бóльшее трение (таблица значений C NFPA 13)."},
  {id:251, q:"В формуле Хазена-Вильямса, если используемое значение C слишком ВЫСОКОЕ (труба предполагается более гладкой, чем в реальности), рассчитанные потери на трение будут:", opts:["Слишком низкими (не в запас)","Слишком высокими (в запас)","Без изменений","В точности верными"], re:"Значение C выше истинного занижает потери на трение, давая результат не в запас (оптимистичный) (член C Хазена-Вильямса)."},
  {id:252, q:"В поузловом гидравлическом расчёте «узел» — это:", opts:["Только основание стояка","Любой прямой участок трубы","Точка, где меняется размер, расход или направление трубы (например, фитинг или спринклер)","Только насос"], re:"Узлы — это опорные точки (спринклеры, фитинги, тройники, изменения размера), между которыми вычисляются потери на трение (процедура гидравлического расчёта NFPA 13)."},
  {id:253, q:"Гидравлические расчёты обычно ведутся начиная от:", opts:["Источника воды к наиболее удалённому спринклеру","Наиболее удалённого спринклера обратно к источнику","Середины системы наружу","Только нагнетания насоса"], re:"Расчёты начинаются у наиболее удалённого (гидравлически наименее благоприятного) спринклера и идут обратно к источнику, накапливая расход и давление (гидравлический расчёт NFPA 13)."},
  {id:254, q:"По мере продвижения от концевого спринклера обратно к стояку накопленный расход в трубе:", opts:["Уменьшается","Остаётся постоянным","Увеличивается по мере того, как каждый спринклер добавляет свой расход","Падает до нуля у каждого тройника"], re:"Каждый нижестоящий спринклер добавляет свой расход, поэтому суммарный расход растёт к источнику (гидравлический расчёт NFPA 13)."},
  {id:255, q:"Когда два потока сходятся в общем узле соединения при разных рассчитанных давлениях, правильное правило таково:", opts:["Усреднить два давления","Сложить два давления","Использовать меньшее давление и игнорировать другое","Использовать большее из двух давлений и пересчитать расход потока с меньшим давлением"], re:"Бóльшее давление в узле определяет режим; ответвление с меньшим давлением нужно пересчитать до этого давления, чтобы уравновесить узел (гидравлический расчёт NFPA 13; узловой анализ соединений)."},
  {id:256, q:"Чтобы повысить расход ответвления с его рассчитанного значения Q при давлении P_low до большего давления в узле P_high, уравновешенный расход равен:", opts:["Q × (P_high/P_low)","Q × √(P_high/P_low)","Q × (P_low/P_high)","Q ÷ √(P_high/P_low)"], re:"Поскольку Q∝√P для этого потока, скорректированный расход = Q×√(P_high/P_low) (узловой анализ соединений NFPA 13)."},
  {id:257, q:"Рассчитано, что ответвление подаёт 25 gpm при 16 psi, но узел, к которому оно подходит, находится при 25 psi. Уравновешенный расход ответвления становится:", opts:["20.0 gpm","25.0 gpm","31.25 gpm","40.0 gpm"], re:"Q_adj = 25×√(25/16) = 25×1.25 = 31.25 gpm (узловой анализ соединений, Q∝√P)."},
  {id:258, q:"Уравновешивание расходов в узле обеспечивает соблюдение какого физического принципа?", opts:["Только сохранения энергии","Сохранения массы/расхода — приток равен оттоку","Постоянной скорости повсюду","Равной длины трубы на всех путях"], re:"В каждом узле суммарный приток должен равняться суммарному оттоку (неразрывность / сохранение массы) (анализ гидравлических сетей)."},
  {id:259, q:"В любом отдельном узле все трубы, подсоединённые к этому узлу, имеют одно и то же:", opts:["Значение расхода","Значение C","Диаметр","Давление"], re:"У узла одно давление; каждый путь, сходящийся там, должен быть приведён к этому общему давлению (концепция гидравлического узла)."},
  {id:260, q:"Полное давление, требуемое в опорном узле, равно сумме:", opts:["Потерь на трение, изменения высоты и начального (нижестоящего) давления","Только потерь на трение","Только K-фактора","Скорости, умноженной на площадь"], re:"P в узле = нижестоящее давление + потери на трение + изменение высоты между узлами (гидравлический расчёт NFPA 13)."},
  {id:261, q:"Изменение высоты между двумя узлами переводится в давление по норме примерно:", opts:["1.0 psi на фут","0.433 psi на фут высоты","2.31 psi на фут","0.052 psi на фут"], re:"Каждый фут водяного столба ≈ 0.433 psi; поднимающаяся труба добавляет это, опускающаяся — возвращает (высотное давление NFPA 13)."},
  {id:262, q:"Узел расположен на 10 ft выше узла под ним. Высотное давление, которое нужно добавить, составляет:", opts:["1.0 psi","4.33 psi","10 psi","23.1 psi"], re:"0.433 psi/ft × 10 ft = 4.33 psi добавляется за подъём (высотное давление NFPA 13)."},
  {id:263, q:"В кольцевой системе (grid) вода может достигать спринклера несколькими путями, что обычно:", opts:["Увеличивает суммарные потери на трение","Не требует узлового анализа","Делает уравновешивание ненужным","Снижает потери на трение по сравнению с тупиковой системой той же потребности"], re:"Параллельные пути в кольце разделяют расход, снижая скорость и потери на трение по сравнению с одним тупиковым путём (кольцевые системы NFPA 13)."},
  {id:264, q:"Скоростное давление (Pv) в гидравлике NFPA 13 вычисляется как:", opts:["Pv = 0.001123 × Q² / d⁴","Pv = 0.433 × Q","Pv = 4.52 × Q^1.85","Pv = K×√P"], re:"NFPA 13 даёт скоростное давление Pv = 0.001123×Q²/d⁴ (psi), где Q в gpm и d в дюймах (формула скоростного давления NFPA 13)."},
  {id:265, q:"В гидравлике NFPA 13 нормальное давление (Pn), полное давление (Pt) и скоростное давление (Pv) связаны соотношением:", opts:["Pn = Pt + Pv","Pn = Pt − Pv","Pn = Pt × Pv","Pn = Pv − Pt"], re:"Нормальное давление Pn = Pt − Pv; скоростное давление вычитается из полного давления (метод скоростного давления NFPA 13)."},
  {id:266, q:"При использовании метода скоростного давления расход из спринклера или ответвления в узле основан на:", opts:["Полном давлении","Высотном давлении","Только скоростном давлении","Нормальном давлении (Pt минус Pv)"], re:"Расход определяется нормальным давлением Pn (Pt − Pv); скоростное давление не создаёт расхода через отверстие (метод скоростного давления NFPA 13)."},
  {id:267, q:"Большинству гидравлических расчётов спринклеров разрешено игнорировать скоростное давление, потому что:", opts:["Оно применяется только к сухотрубам (standpipes)","Оно всегда больше полного давления","NFPA 13 запрещает его включать","Оно обычно мало, и его опущение идёт в запас"], re:"Скоростное давление обычно невелико, а его игнорирование идёт в запас, поэтому NFPA 13 разрешает его опускать (скоростное давление NFPA 13 является необязательным)."},
  {id:268, q:"После уравновешивания каждого соединения накопленное давление, перенесённое обратно к источнику, представляет собой:", opts:["Статическое давление городской магистрали","Давление потребности системы у источника","Температурную характеристику спринклера","Толщину стенки трубы"], re:"Накопленное и уравновешенное давление в основании стояка/источника — это полное давление потребности системы, которое должно быть обеспечено водоснабжением (гидравлический расчёт NFPA 13)."},
  {id:269, q:"График водоснабжения для проектирования спринклеров строится на специальной бумаге, масштабированной так, что кривая водоснабжения выглядит как:", opts:["Прямая линия (ось расхода в степени 1.85)","Вертикальная линия","Идеальная окружность","Горизонтальная линия"], re:"Бумага N^1.85 масштабирует ось расхода в степени 1.85, так что кривая водоснабжения Хазена-Вильямса строится как прямая линия (гидравлический график NFPA 13; бумага N1.85)."},
  {id:270, q:"На гидравлическом графике кривая ВОДОСНАБЖЕНИЯ показывает, что по мере увеличения расхода доступное давление:", opts:["Уменьшается","Увеличивается","Остаётся постоянным","Сразу становится отрицательным"], re:"Бóльший расход «просаживает» водоснабжение: остаточное давление падает по мере роста расхода, поэтому кривая водоснабжения идёт вниз (кривая водоснабжения на основе испытания расходом)."},
  {id:271, q:"Система достаточна, когда точка потребности попадает:", opts:["На кривую водоснабжения или ниже неё (внутрь)","Выше (вне) кривой водоснабжения","Точно в нулевой расход","Только в статическое давление"], re:"Потребность должна лежать на кривой доступного водоснабжения или ниже неё, то есть водоснабжение способно подать требуемый расход при требуемом давлении (потребность против водоснабжения NFPA 13)."},
  {id:272, q:"Вертикальный зазор между кривой доступного водоснабжения и точкой потребности при расчётном расходе называется:", opts:["Потерями на трение","Высотным напором","Запасом (запасом по давлению)","Скоростным давлением"], re:"Эта разница давлений и есть запас или «подушка» между водоснабжением и потребностью (гидравлический график NFPA 13; запас)."},
  {id:273, q:"БОЛЬШИЙ запас между водоснабжением и потребностью обычно указывает на:", opts:["Водоснабжение, едва достаточное","Бóльший резерв производительности и устойчивость к колебаниям водоснабжения","Недостаточно крупную водопроводную магистраль","Ошибочный расчёт"], re:"Бóльшая подушка означает, что водоснабжение с комфортом превышает потребность, давая резерв на ухудшение или колебания (концепция запаса NFPA 13)."},
  {id:274, q:"При испытании расходом «статическое» давление — это давление, измеренное при:", opts:["Максимальном расходе","Холостом режиме насоса (churn)","20 psi остаточном","Нулевом расходе (ни один гидрант не течёт)"], re:"Статическое давление считывается при отсутствии течения воды (нулевой расход) (терминология NFPA 291 / испытания расходом)."},
  {id:275, q:"При испытании расходом «остаточное» давление — это давление, измеренное:", opts:["При отсутствии расхода","После окончания испытания","Пока истекает известное количество воды","Только у насоса"], re:"Остаточное давление — это давление, оставшееся в системе во время сброса измеренного расхода (терминология испытания расходом)."},
  {id:276, q:"Построение кривой водоснабжения на бумаге N1.85 полезно, потому что позволяет проектировщику:", opts:["Считывать доступный расход при любом давлении как прямолинейную интерполяцию","Не измерять давление","Исключить запас на рукава","Игнорировать потери на трение"], re:"Прямолинейная кривая водоснабжения позволяет простую графическую интерполяцию доступного расхода при любом давлении (графический метод N1.85)."},
  {id:277, q:"Полная ПОТРЕБНОСТЬ системы, наносимая на график, должна включать:", opts:["Только расход спринклеров","Только статическое давление","Только запас на рукава","Расход спринклеров плюс требуемый запас на рукавную струю"], re:"Потребность системы = расход спринклеров по расчётной площади ПЛЮС запас на рукавную струю (расчёт потребности NFPA 13)."},
  {id:278, q:"Если точка потребности наносится ВЫШЕ кривой водоснабжения, проектировщик должен:", opts:["Увеличить водоснабжение (например, насосом) или снизить потребность (труба большего диаметра), пока потребность не уместится под кривой","Ничего не делать; всё проходит","Снизить только интенсивность","Убрать запас на рукава"], re:"Потребность выше водоснабжения означает, что водоснабжение недостаточно; нужно либо усилить водоснабжение, либо снизить потребность, чтобы точка попала внутрь кривой (потребность против водоснабжения NFPA 13)."},
  {id:279, q:"Распространённая причина, по которой кривую водоснабжения продлевают до 20 psi, состоит в том, что:", opts:["20 psi — это максимально допустимое давление","Нормы обычно требуют оценивать доступный пожарный расход при 20 psi остаточном","Спринклеры не могут течь ниже 20 psi","20 psi — это статическое давление"], re:"Пожарный расход по соглашению указывается как расход, доступный при 20 psi остаточном, согласно практике противопожарных норм (соглашение о пожарном расходе NFPA 291 / противопожарных норм)."},
  {id:280, q:"На графике круто падающая (быстро снижающаяся) кривая водоснабжения указывает на водоснабжение, которое является:", opts:["Сильным с малой потерей давления при расходе","Независимым от расхода","Слабым — давление быстро падает по мере увеличения расхода","Всегда достаточным"], re:"Крутой наклон вниз означает, что остаточное давление быстро обрушивается с расходом, что указывает на сравнительно слабое водоснабжение (интерпретация кривой водоснабжения)."},
  {id:281, q:"Если добавляется пожарный насос, на гидравлическом графике эффект состоит в том, чтобы:", opts:["Опустить всю кривую водоснабжения","Поднять кривую водоснабжения вверх, добавляя давление при заданном расходе","Устранить кривую потребности","Сплющить потребность до нуля"], re:"Насос добавляет напор, смещая кривую доступного водоснабжения вверх и увеличивая запас над потребностью (концепция усиленного водоснабжения/насоса)."},
  {id:282, q:"Точка, где потребность системы и доступное водоснабжение едва сходятся (без оставшейся подушки), означает, что запас равен:", opts:["Нулю","Максимуму","Отрицательной величине","Статическому давлению"], re:"Если потребность в точности равна водоснабжению, подушка/запас равен нулю — минимально допустимое условие (определение запаса)."},
  {id:283, q:"Горизонтальная ось стандартного гидравлического графика спринклеров представляет:", opts:["Время (s)","Давление (psi)","Расход (gpm)","Высоту (ft)"], re:"Расход в gpm нанесён на горизонтальную ось (масштабирован в степени 1.85); давление — на вертикальную ось (график N1.85)."},
  {id:284, q:"Вертикальная ось стандартного гидравлического графика спринклеров представляет:", opts:["Расход (gpm)","Значение C","Давление (psi)","Диаметр трубы"], re:"Давление в psi наносится на вертикальную ось гидравлического графика (график N1.85)."},
  {id:285, q:"Практическая причина, по которой проектировщики предпочитают щедрый запас, — это учёт:", opts:["Более низких температурных характеристик","Более ярких цветов спринклеров","Более коротких участков трубы","Будущего огрубления трубы шероховатостью, сезонного снижения водоснабжения и небольшой погрешности испытания расходом"], re:"Запас покрывает ухудшение водоснабжения со временем, сезонные/суточные колебания давления и неточность испытания (инженерное обоснование запаса)."},
  {id:286, q:"Полная ПОТРЕБНОСТЬ спринклерной системы, которую нужно обеспечить, — это сумма:", opts:["Расхода спринклеров по расчётной площади плюс запас на рукавную струю","Статического давления плюс остаточного давления","K-фактора плюс значения C","Только высоты плюс скорости"], re:"Потребность = рассчитанный расход спринклеров по расчётной площади + требуемый запас на внутреннюю/наружную рукавную струю (потребность в воде NFPA 13)."},
  {id:287, q:"Запас на рукавную струю для помещения лёгкой опасности (Light Hazard) обычно составляет:", opts:["250 gpm","100 gpm","500 gpm","1,000 gpm"], re:"Запас на рукавную струю для Light Hazard составляет 100 gpm (таблица рукавной струи/водоснабжения NFPA 13)."},
  {id:288, q:"Запас на рукавную струю для помещения обычной опасности (Ordinary Hazard) обычно составляет:", opts:["100 gpm","500 gpm","250 gpm","750 gpm"], re:"Запас на рукавную струю для Ordinary Hazard составляет 250 gpm (таблица рукавной струи/водоснабжения NFPA 13)."},
  {id:289, q:"Запас на рукавную струю для помещения повышенной опасности (Extra Hazard) обычно составляет:", opts:["100 gpm","500 gpm","250 gpm","2,000 gpm"], re:"Запас на рукавную струю для Extra Hazard составляет 500 gpm (таблица рукавной струи/водоснабжения NFPA 13)."},
  {id:290, q:"В потребности системы запас на рукавную струю обычно добавляется к спринклерной потребности в какой точке?", opts:["В точке присоединения к водоснабжению (например, в основании стояка или городской магистрали)","У каждого спринклера","Только у наиболее удалённого оросителя","Он никогда не добавляется"], re:"Запас на рукава добавляется там, где он отбирался бы, — обычно в основании стояка/точке присоединения водоснабжения, а не у спринклеров (применение запаса на рукава NFPA 13)."},
  {id:291, q:"Требуемая ПРОДОЛЖИТЕЛЬНОСТЬ водоснабжения для помещения лёгкой опасности (Light Hazard) порядка:", opts:["90 минут","60 минут","30 минут","8 часов"], re:"Продолжительность водоснабжения для Light Hazard порядка 30 минут (таблица продолжительности водоснабжения NFPA 13)."},
  {id:292, q:"Требуемая ПРОДОЛЖИТЕЛЬНОСТЬ водоснабжения для помещения повышенной опасности (Extra Hazard) порядка:", opts:["90–120 минут","60 минут","30 минут","10 минут"], re:"Продолжительность водоснабжения для Extra Hazard порядка 90–120 минут — дольше, чем у меньших опасностей (таблица продолжительности водоснабжения NFPA 13)."},
  {id:293, q:"Испытание расходом пожарного гидранта используется в проектировании спринклеров главным образом для того, чтобы:", opts:["Определить высоту здания","Установить температурную характеристику спринклера","Выбрать цвет трубы","Установить кривую доступного водоснабжения"], re:"Испытание расходом определяет доступное водоснабжение (статическое, остаточное и наклон), используемое для построения кривой водоснабжения (назначение испытания расходом)."},
  {id:294, q:"«Пожарный расход, доступный при 20 psi» из испытания расходом означает:", opts:["Труба диаметром 20 дюймов","Статическое давление равно 20 psi","Давление отключения насоса равно 20 psi","Расход, когда остаточное давление упало до 20 psi"], re:"Это прогнозируемый расход, который водоснабжение может подать, всё ещё поддерживая 20 psi остаточного (соглашение о пожарном расходе)."},
  {id:295, q:"При сравнении потребности системы с кривой водоснабжения потребность должна быть обеспечена при:", opts:["Требуемом расходе потребности, а не только при нулевом расходе","Только статическом (безрасходном) давлении","Удвоенном расходе потребности","Только давлении холостого режима насоса (churn)"], re:"Достаточность оценивается в точке расхода потребности — водоснабжение должно обеспечить давление потребности ПРИ расходе потребности (потребность против водоснабжения NFPA 13)."},
  {id:296, q:"Если водоснабжение даёт обильное статическое давление, но его остаточное обрушивается при расходе, система всё равно может отказать, потому что:", opts:["K-фактор меняется","Статическое давление неважно","Само по себе статическое давление не гарантирует достаточного расхода в точке потребности","Высота увеличивается"], re:"Высокое статическое при плохом остаточном даёт крутую, слабую кривую; потребность при расчётном расходе может превысить доступное остаточное давление (интерпретация кривой водоснабжения)."},
  {id:297, q:"Добавление запаса на рукавную струю к потребности смещает точку потребности системы на графике:", opts:["Полностью за пределы графика","К нулевому расходу","Вниз к статическому давлению","К большему расходу (и, следовательно, к большему требуемому давлению на кривой водоснабжения)"], re:"Рукавный расход увеличивает суммарный расход потребности, перемещая точку потребности вправо/вверх вдоль кривой водоснабжения и уменьшая подушку (наращивание потребности NFPA 13)."},
  {id:298, q:"Две точки испытания расходом нужны для определения кривой водоснабжения, потому что:", opts:["Закон требует двух гидрантов","Требуются два насоса","Одна точка даёт давление, вторая устанавливает наклон (падение давления против расхода)","Одна точка — это температура"], re:"Статическое фиксирует давление при нулевом расходе; точка остаточного-при-расходе задаёт наклон кривой, вместе определяя водоснабжение (построение испытания расходом / кривой водоснабжения)."},
  {id:299, q:"Если городское водоснабжение само по себе не может обеспечить потребность системы в пределах запаса, распространённое решение — это:", opts:["Добавить пожарный насос и/или накопительный бак для усиления водоснабжения","Снизить требуемую интенсивность ниже нормы","Убрать спринклеры из расчётной площади","Удалить запас на рукава"], re:"Пожарный насос и/или накопительный бак для воды усиливают кривую доступного водоснабжения, чтобы обеспечить потребность с запасом (наращивание водоснабжения по NFPA 13 / NFPA 20)."},
  {id:300, q:"ОКОНЧАТЕЛЬНАЯ проверка гидравлического проекта спринклеров состоит в том, что:", opts:["Все спринклеры имеют одинаковое давление","Каждая труба одного диаметра","Потребность системы (включая рукава) умещается в пределах доступного водоснабжения с требуемым запасом","Не используется ни одного фитинга"], re:"Принятие проекта требует, чтобы суммарная потребность плюс рукава попадали внутрь кривой водоснабжения, оставляя достаточный запас (окончательная проверка потребности против водоснабжения NFPA 13)."},
  {id:301, q:"NFPA 13 допускает два основных метода подбора диаметра труб спринклерной системы. Это:", opts:["Метод по сортаменту труб и метод гидравлического расчёта","Метод по скорости и метод по площади","Метод по трению и метод по плотности","Метод по гравитации и метод по давлению"], re:"NFPA 13 подбирает диаметр труб либо по методу сортамента труб (с использованием нормативных таблиц числа спринклеров, допустимого для каждого диаметра трубы), либо гидравлическим расчётом. Ref: NFPA 13, главы проектирования систем по системам с сортаментным подбором и гидравлически рассчитываемым системам."},
  {id:302, q:"По методу сортамента труб для помещения с лёгкой пожарной нагрузкой (Light Hazard) при использовании стали Schedule 40 труба распределительной линии 1 in. может питать максимум сколько спринклеров?", opts:["1 спринклер","2 спринклера","4 спринклера","6 спринклеров"], re:"В сортаменте труб NFPA 13 для лёгкой нагрузки: 1 in. = 2 спринклера, 1-1/4 in. = 3, 1-1/2 in. = 5, 2 in. = 10. Ref: таблица сортамента труб для лёгкой нагрузки NFPA 13."},
  {id:303, q:"По сортаменту труб для лёгкой нагрузки (сталь Schedule 40) труба 2 in. может питать максимум сколько спринклеров?", opts:["5 спринклеров","8 спринклеров","10 спринклеров","30 спринклеров"], re:"Сортамент труб NFPA 13 для лёгкой нагрузки: 1-1/2 in. = 5, 2 in. = 10, 2-1/2 in. = 30. Ref: таблица сортамента труб для лёгкой нагрузки NFPA 13."},
  {id:304, q:"Метод сортамента труб НЕ может использоваться для проектирования новой системы в какой из следующих ситуаций?", opts:["Любая система, где расчётный спрос ниже доступного снабжения","Офисное здание с лёгкой нагрузкой","Любая водозаполненная система","Гидравлически спроектированное расширение с повышенной нагрузкой (Extra Hazard) или где NFPA 13 ограничивает его применение существующими системами и небольшими расширениями"], re:"NFPA 13 ограничивает проектирование по сортаменту труб в основном существующими системами с сортаментным подбором и ограниченными расширениями; новые системы обычно должны рассчитываться гидравлически. Ref: ограничения систем с сортаментным подбором труб NFPA 13."},
  {id:305, q:"В гидравлически рассчитываемой системе потери на трение в трубопроводе чаще всего определяются в NFPA 13 по какой формуле?", opts:["Формула Хазена-Уильямса","Уравнение Дарси-Вейсбаха","Энергетическое уравнение Бернулли","Уравнение Маннинга"], re:"Гидравлические расчёты NFPA 13 используют формулу Хазена-Уильямса для потерь на трение в трубе. Ref: процедуры гидравлического расчёта NFPA 13 (Хазен-Уильямс)."},
  {id:306, q:"В формуле Хазена-Уильямса в применении NFPA 13 переменная 'C' представляет:", opts:["Площадь поперечного сечения трубы","Коэффициент потерь на трение (шероховатости) внутренней поверхности трубы","Скорость воды","Статическое давление в основании стояка"], re:"'C' — коэффициент шероховатости Хазена-Уильямса, описывающий относительную гладкость внутренней поверхности трубы; меньшее C означает более шероховатую трубу и большие потери на трение. Ref: номенклатура формулы Хазена-Уильямса NFPA 13."},
  {id:307, q:"Какое значение C по Хазену-Уильямсу NFPA 13 присваивает новой (без покрытия) чёрной или оцинкованной стальной трубе для гидравлических расчётов пожарных спринклеров?", opts:["100","140","120","150"], re:"NFPA 13 присваивает C = 120 чёрной и оцинкованной стальной трубе в своей таблице значений C по Хазену-Уильямсу. Ref: таблица значений C по Хазену-Уильямсу NFPA 13."},
  {id:308, q:"Какому материалу трубопровода присвоено САМОЕ ВЫСОКОЕ значение C по Хазену-Уильямсу (самый гладкий) в NFPA 13?", opts:["Чёрная стальная труба (сухая система), C = 100","Оцинкованная стальная труба, C = 120","Чугун с цементной футеровкой (чугун/ковкий чугун), C = 140","Пластик (CPVC) / медная труба, C = 150"], re:"NFPA 13 присваивает C = 150 пластику (сертифицированный CPVC) и медной трубе — самым гладким из распространённых спринклерных материалов. Ref: таблица значений C по Хазену-Уильямсу NFPA 13."},
  {id:309, q:"NFPA 13 присваивает меньшее значение C по Хазену-Уильямсу системам с сухой трубой и системам предварительного действия (чёрная сталь). Это значение:", opts:["100","120","130","140"], re:"Чёрной стальной трубе в эксплуатации с сухой трубой/предварительным действием присваивается C = 100, чтобы учесть ускоренную внутреннюю коррозию от периодического воздействия воды и воздуха. Ref: таблица значений C по Хазену-Уильямсу NFPA 13."},
  {id:310, q:"В соотношении потерь давления по Хазену-Уильямсу, используемом NFPA 13, потери на трение на единицу длины наиболее чувствительны к какой переменной?", opts:["Только длина трубы","Расход (Q), который возводится в степень около 1.85","Статическая высота","Цвет трубы"], re:"В формуле Хазена-Уильямса потери на трение изменяются примерно как Q^1.85 и обратно пропорционально C^1.85 и диаметру^4.87; расход сильно влияет на потери. Ref: формула Хазена-Уильямса NFPA 13."},
  {id:311, q:"При переводе потерь фитингов и клапанов в трубу в гидравлическом расчёте NFPA 13 требует, чтобы проектировщик добавлял у фитинга его:", opts:["Фактическую физическую длину","Номинальный диаметр","Эквивалентную длину трубы","Толщину стенки"], re:"Трение фитингов и клапанов учитывается добавлением эквивалентной длины трубы (из таблицы эквивалентных длин NFPA 13) к фактической длине трубы. Ref: эквивалентные длины труб фитингов и клапанов NFPA 13."},
  {id:312, q:"Таблица эквивалентных длин фитингов NFPA 13 основана на стальной трубе Schedule 40 и значении C, равном 120. Если фактическая труба имеет другое значение C, табличная эквивалентная длина должна быть:", opts:["Полностью проигнорирована","Заменена номинальным диаметром","Удвоена в каждом случае","Умножена на поправочный коэффициент для фактического значения C"], re:"NFPA 13 требует умножать табличную эквивалентную длину на поправку по коэффициенту C (таблица предполагает C = 120, Schedule 40). Ref: примечание к таблице эквивалентных длин NFPA 13 о поправке на значение C."},
  {id:313, q:"Основное преимущество метода гидравлического расчёта перед методом сортамента труб в том, что он:", opts:["Подгоняет диаметры труб под фактический спрос и доступное водоснабжение, обычно позволяя применять меньшую и более экономичную трубу","Устраняет необходимость в любых подвесах/опорах","Устраняет необходимость в спринклерах","Позволяет принимать любое значение C"], re:"Гидравлический расчёт согласует диаметры труб с требуемой плотностью/площадью и реальной кривой снабжения, обычно давая меньшую и более эффективную трубу, чем консервативные таблицы сортамента. Ref: основа проектирования гидравлически рассчитываемых систем NFPA 13."},
  {id:314, q:"В NFPA 13 скорость воды в трубе влияет на проектирование главным образом потому, что более высокая скорость:", opts:["Уменьшает потери на трение","Увеличивает потери на трение на фут трубы","Не влияет на давление","Увеличивает значение C трубы"], re:"Более высокая скорость потока увеличивает потери на трение; хотя NFPA 13 не ограничивает скорость, проектировщики контролируют её, так как чрезмерная скорость повышает требуемое давление. Ref: принципы гидравлического расчёта NFPA 13 (Хазен-Уильямс)."},
  {id:315, q:"По сортаменту труб для обычной нагрузки (Ordinary Hazard, сталь Schedule 40) максимальное число спринклеров, допустимое на трубе распределительной линии 1-1/4 in., составляет:", opts:["2","4","3","5"], re:"Сортамент труб NFPA 13 для обычной нагрузки: 1 in. = 2, 1-1/4 in. = 3, 1-1/2 in. = 5, 2 in. = 10. Ref: таблица сортамента труб для обычной нагрузки NFPA 13."},
  {id:316, q:"В гидравлическом расчёте древовидной конфигурации потери на трение балансируются в общих опорных точках так, чтобы:", opts:["Каждая труба несла одинаковый расход","Высота игнорировалась","Все спринклеры выдавали ровно минимум","Две трассы, сходящиеся в узле, были сбалансированы до одинакового давления перед суммированием расходов"], re:"В каждом узле давления сходящихся трасс должны быть сбалансированы (уравнены, обычно по большему значению) перед суммированием их расходов. Ref: процедура гидравлического расчёта NFPA 13 (балансировка давлений в узлах)."},
  {id:317, q:"Нормальное давление (Pn), скоростное давление (Pv) и полное давление (Pt) связаны в гидравлических расчётах NFPA 13 как:", opts:["Pt = Pn + Pv","Pt = Pn - Pv","Pn = Pt + Pv","Pv = Pt + Pn"], re:"Полное давление равно нормальному (статическому) давлению плюс скоростное давление: Pt = Pn + Pv. NFPA 13 допускает, но не требует включения скоростного давления. Ref: гидравлический расчёт NFPA 13, положения о скоростном давлении."},
  {id:318, q:"Надземные спринклерные трубы и трубки, применяемые по NFPA 13, как правило, должны быть:", opts:["Любые трубы, имеющиеся на объекте","Типа, специально допущенного NFPA 13 (например, сертифицированного или соответствующего указанным стандартам ASTM/ASME)","Только нержавеющая сталь","Только медь"], re:"NFPA 13 ограничивает надземные трубы/трубки материалами, соответствующими указанным в стандарте спецификациям (такими как сталь ASTM A53/A795, медь ASTM B), или специально сертифицированными. Ref: требования к надземным трубам и трубкам NFPA 13."},
  {id:319, q:"Трубы и фитинги CPVC могут применяться в пожарной спринклерной системе только когда они:", opts:["Schedule 40 PVC любого производителя","Сертифицированы только для питьевой воды","Сертифицированы для пожарной спринклерной эксплуатации и установлены согласно их сертификации","Окрашены вспучивающейся краской"], re:"Только CPVC, специально сертифицированный для применения в пожарных спринклерах, может быть установлен, и он должен соответствовать ограничениям сертификации (например, скрытое размещение, шаг подвесов, растворный цемент). Обычный CPVC по ASTM не сертифицирован автоматически. Ref: требования к неметаллическим трубам / сертификации NFPA 13."},
  {id:320, q:"Когда стальная труба соединяется резьбовыми фитингами, NFPA 13 требует минимальную толщину стенки, соответствующую:", opts:["Schedule 5","Schedule 10","Только Schedule 80","Schedule 30 (8 in. и больше) или Schedule 40 (меньше 8 in.)"], re:"Нарезка резьбы требует толщины стенки не менее Schedule 30 для 8 in. и больше или Schedule 40 для трубы меньшего размера; более тонкая стенка (Schedule 10) не может нарезаться резьбой. Ref: требования к толщине соединения стальной трубы (резьбового) NFPA 13."},
  {id:321, q:"Тонкостенная (Schedule 10) стальная спринклерная труба допускается NFPA 13 только при соединении:", opts:["Сертифицированными методами, такими как накатные канавочные или сварные соединения (не резьба)","Резьбовыми фитингами","Растворным цементом","Обжимными муфтами"], re:"Schedule 10 не имеет толщины стенки для нарезаемой резьбы, поэтому должна соединяться накатными канавочными, сварными или другими сертифицированными методами. Ref: методы соединения стальной трубы и минимальная толщина стенки NFPA 13."},
  {id:322, q:"Труба, соединённая канавочными механическими муфтами, должна использовать:", opts:["Любую прокладку, имеющуюся под рукой","Сертифицированную комбинацию фитингов, прокладок и канавок","Только сварные соединения","Резьбовые переходники"], re:"NFPA 13 требует, чтобы канавочные соединения выполнялись с сертифицированной комбинацией фитингов, прокладок и канавок для обеспечения совместимости и целостности. Ref: требования к канавочным фитингам/муфтам NFPA 13."},
  {id:323, q:"Медная труба, применяемая в спринклерных системах, во многих случаях соединяется высокотемпературной пайкой (твёрдый припой), а не мягкой пайкой, потому что:", opts:["Соединения мягкой пайкой не удерживают воду","Медь нельзя паять","Соединения твёрдым припоем имеют большую температурную/прочностную способность, требуемую для условий пожара и сертификаций","Твёрдая пайка только быстрее"], re:"Соединения твёрдым припоем обеспечивают большую прочность и огнестойкость, чем мягкий припой 50/50; NFPA 13 ссылается на стандарты соединения меди и сертификации для этих соединений. Ref: положения о соединении медной трубы NFPA 13."},
  {id:324, q:"Сварка спринклерной трубы по NFPA 13 должна выполняться:", opts:["Любым работником с горелкой","Только в цеху, никогда на объекте","Без какой-либо документации","С использованием аттестованных сварщиков/процедур со швами полного провара и отверстиями, вырезанными сертифицированными/одобренными средствами"], re:"NFPA 13 требует аттестованных процедур сварки и сварщиков, швов полного провара в ответвлениях выпусков и извлечения дисков/керновых вырезок, чтобы они не перекрывали трубу. Ref: положения о сварных трубах и фитингах NFPA 13."},
  {id:325, q:"После приварки ответвления выпуска к магистрали NFPA 13 требует, чтобы:", opts:["Вырезанная керновая вырезка (диск) была извлечена и не оставалась внутри трубопровода","Диск был оставлен внутри для усиления соединения","Труба была оцинкована после","Выпуск был нарезан резьбой"], re:"Вырезка, удалённая при вырезании выпуска, должна быть извлечена; диск, оставленный в трубе, мог бы перекрыть поток к спринклерам. Ref: требования к сварным выпускам NFPA 13 (извлечение вырезок)."},
  {id:326, q:"Какой стандарт обычно упоминается в NFPA 13 для чёрной и горячеоцинкованной стальной спринклерной трубы обычного веса?", opts:["ASTM D1785","ASTM A53 / ASTM A795","ASME B16.3","AWWA C151"], re:"NFPA 13 ссылается на ASTM A53 и ASTM A795 (и A135) для стальной спринклерной трубы. ASTM D1785 — для пластика PVC. Ref: указанные спецификации стальной трубы NFPA 13."},
  {id:327, q:"Фитинги, применяемые в спринклерных системах, должны:", opts:["Всегда быть из чугуна","Иметь номинальное давление выше 1000 psi","Соответствовать материалу/методу соединения трубы и отвечать указанным стандартам NFPA 13 или быть сертифицированными","Изготавливаться на объекте"], re:"NFPA 13 требует, чтобы фитинги соответствовали указанным стандартам (например, серии ASME B16, сертификации UL) и были совместимы с трубой и методом соединения/давлением. Ref: требования к фитингам NFPA 13."},
  {id:328, q:"Минимальное номинальное давление для компонентов спринклерной системы (труб, фитингов, клапанов) в стандартных системах NFPA 13 обычно составляет:", opts:["50 psi","100 psi","500 psi","175 psi (где максимальное давление системы его не превышает)"], re:"NFPA 13 обычно рассчитывает компоненты системы не менее чем на 175 psi, где максимальное рабочее давление системы не превышает 175 psi; системы более высокого давления требуют компонентов с соответствующим номиналом. Ref: положения о номинальном давлении компонентов NFPA 13."},
  {id:329, q:"Сертификации неметаллических (CPVC) труб часто ограничивают их применение какой компоновкой, если не сертифицировано иное?", opts:["Водозаполненные системы и скрытые/специально защищённые установки согласно сертификации","Открыто в любом помещении","Сухотрубные системы с повышенной нагрузкой (Extra Hazard)","Только под землёй"], re:"Сертификации CPVC обычно ограничивают применение водозаполненными системами и требуют скрытого размещения или специальной защиты (мембрана, заполнение водой), кроме случаев, когда сертификация допускает открытое применение. Ref: ограничения сертификации продукции NFPA 13 / CPVC."},
  {id:330, q:"При соединении разнородных металлов, таких как медная труба и стальная труба, проектировщик должен учесть:", opts:["Снижение значения C до 50","Гальваническую коррозию (применение диэлектрических/сертифицированных переходных фитингов)","Обязательную сварку","Удвоение шага подвесов"], re:"Соединение меди со сталью может вызвать гальваническую коррозию; для её смягчения применяют диэлектрические соединения или сертифицированные переходные фитинги. Ref: NFPA 13 / надлежащая практика по соединениям разнородных металлов."},
  {id:331, q:"Накатная канавочная стальная труба Schedule 10 допускается NFPA 13 для давлений до:", opts:["100 psi","175 psi","300 psi","1000 psi"], re:"NFPA 13 допускает накатную канавочную сталь Schedule 10 (в применимых размерах) для систем с давлением до 300 psi с заданной минимальной толщиной стенки для больших размеров. Ref: положения о толщине стенки/давлении стальной трубы (накатной канавочной) NFPA 13."},
  {id:332, q:"Оцинкованной стальной трубе иногда отдают предпочтение перед чёрной сталью в сухих системах и системах предварительного действия, потому что оцинковка:", opts:["Увеличивает значение C до 150","Устраняет необходимость в подвесах/опорах","Допускает соединения мягкой пайкой","Обеспечивает некоторую дополнительную стойкость к внутренней коррозии от захваченной воды/конденсата"], re:"Оцинковка добавляет стойкость к внутренней коррозии, полезную там, где конденсат и периодическое воздействие воды ускоряют коррозию в сухих системах/системах предварительного действия. Ref: положения о материале трубы NFPA 13 / соображения по коррозии."},
  {id:333, q:"Труба или компонент, 'сертифицированный' (listed) по NFPA 13, означает, что он был:", opts:["Оценён признанной испытательной лабораторией и опубликован как соответствующий надлежащим стандартам для предполагаемого применения","Одобрен только монтажником","Изготовлен за рубежом","Использован ранее на другом объекте"], re:"'Сертифицированный' означает, что общенационально признанная испытательная лаборатория оценила продукт и опубликовала его как соответствующий применимому стандарту для предполагаемого применения в противопожарной защите. Ref: определения сертифицированного/одобренного NFPA 13."},
  {id:334, q:"Нержавеющая сталь и некоторые другие специальные материалы труб могут применяться в спринклерных системах, когда они:", opts:["Никогда не допускаются","Сертифицированы или специально допущены и соединены методами, согласующимися с NFPA 13 и сертификацией","Только для подземных магистралей","Окрашены под сталь"], re:"Специальные материалы (например, нержавеющая сталь) допустимы там, где они соответствуют указанным спецификациям или сертифицированы и соединены надлежащими сертифицированными методами. Ref: положения о надземных трубах/трубках и специальных материалах NFPA 13."},
  {id:335, q:"В гидравлических расчётах NFPA 13 эквивалентная длина, присвоенная фитингу, представляет:", opts:["Физический размер фитинга от торца до торца","Номинальный размер трубы","Длину прямой трубы, которая создала бы такие же потери на трение, как фитинг","Номинальное давление фитинга"], re:"Эквивалентная длина — это длина прямой трубы того же диаметра, дающая такие же потери на трение, как фитинг. Ref: эквивалентная длина трубы фитингов и клапанов NFPA 13."},
  {id:336, q:"К какой трубе и значению C нормирована таблица эквивалентных длин NFPA 13?", opts:["Сталь Schedule 80, C = 100","Медь, C = 150","Чугун, C = 140","Сталь Schedule 40, C = 120"], re:"Таблица эквивалентных длин фитингов основана на стальной трубе Schedule 40 и C = 120; для других значений C требуются поправки. Ref: основа таблицы эквивалентных длин NFPA 13."},
  {id:337, q:"Для стандартного отвода 90 градусов из стали Schedule 40 размером 2 in. таблица NFPA 13 даёт эквивалентную длину примерно:", opts:["5 ft","1 ft","12 ft","20 ft"], re:"NFPA 13 указывает для стандартного отвода 90 градусов 2 in. эквивалентную длину около 5 ft. Ref: таблица эквивалентной длины трубы фитингов и клапанов NFPA 13."},
  {id:338, q:"По сравнению со стандартным отводом 90 градусов того же размера, отвод 90 градусов с большим радиусом (плавный) имеет эквивалентную длину, которая:", opts:["Больше","Меньше","Идентична","Всегда равна нулю"], re:"Отвод с большим радиусом/плавный создаёт меньшую турбулентность, поэтому его эквивалентная длина меньше, чем у стандартного отвода 90 градусов того же размера. Ref: таблица эквивалентных длин NFPA 13 (стандартный отвод против отвода с большим радиусом)."},
  {id:339, q:"Когда поток идёт прямо НАСКВОЗЬ через прямой проход тройника или крестовины (без изменения направления), эквивалентная длина, начисляемая в NFPA 13, составляет:", opts:["Полное значение ответвления (поворота)","Всегда 60 ft","Ноль или не учитывается как поворот (только трассе ответвления/поворота начисляется значение тройника)","То же, что у задвижки"], re:"Потоку, проходящему прямо насквозь через прямой проход тройника/крестовины, потери фитинга не начисляются; только потоку, поворачивающему на 90 градусов через ответвление, присваивается эквивалентная длина тройника. Ref: примечания таблицы эквивалентных длин NFPA 13 о тройниках и крестовинах."},
  {id:340, q:"Для полностью открытой задвижки 2 in. эквивалентная длина по NFPA 13 составляет примерно:", opts:["6 ft","9 ft","15 ft","1 ft"], re:"Полностью открытая задвижка имеет очень малые потери; NFPA 13 указывает около 1 ft эквивалентной длины для 2 in. Ref: таблица эквивалентных длин NFPA 13 (задвижка)."},
  {id:341, q:"Дисковый поворотный затвор (баттерфляй) 2 in. имеет эквивалентную длину по NFPA 13 примерно:", opts:["6 ft","1 ft","20 ft","40 ft"], re:"Дисковый поворотный затвор 2 in. указан примерно в 6 ft эквивалентной длины, так как диск остаётся в трассе потока. Ref: таблица эквивалентных длин NFPA 13 (дисковый поворотный затвор)."},
  {id:342, q:"Поворотный обратный клапан 2 in. имеет эквивалентную длину по NFPA 13 примерно:", opts:["1 ft","9 ft","3 ft","27 ft"], re:"Поворотный обратный клапан 2 in. указан примерно в 9 ft эквивалентной длины. Ref: таблица эквивалентных длин NFPA 13 (поворотный обратный клапан)."},
  {id:343, q:"Среди следующих фитингов/клапанов 2 in. какой обычно имеет НАИБОЛЬШУЮ эквивалентную длину (наибольшие потери на трение)?", opts:["Полностью открытая задвижка","Стандартный отвод 90 градусов","Поворотный обратный клапан","Отвод 45 градусов"], re:"Из этих поворотный обратный клапан (~9 ft для 2 in.) имеет наибольшую эквивалентную длину; задвижка — наименьшую (~1 ft). Ref: таблица эквивалентных длин NFPA 13."},
  {id:344, q:"По мере увеличения номинального размера трубы эквивалентная длина данного типа фитинга (например, отвода 90 градусов) обычно:", opts:["Уменьшается","Остаётся точно такой же","Становится отрицательной","Увеличивается"], re:"Большие фитинги имеют большие эквивалентные длины; например, отвод 90 градусов растёт от ~2 ft при 1 in. до ~14 ft при 6 in. Ref: тенденция таблицы эквивалентных длин NFPA 13 по размерам."},
  {id:345, q:"Отвод 45 градусов имеет эквивалентную длину, которая по сравнению со стандартным отводом 90 градусов того же размера:", opts:["Меньше","Больше","Ровно вдвое","Точно такая же"], re:"Отвод 45 градусов поворачивает поток меньше и имеет меньшую эквивалентную длину, чем отвод 90 градусов того же размера. Ref: таблица эквивалентных длин NFPA 13 (отвод 45 против 90 градусов)."},
  {id:346, q:"NFPA 13 обычно НЕ требует добавлять эквивалентную длину фитинга для каких соединений?", opts:["Отводы 90 градусов в основании стояка","Прямые соединения со спринклером и фитинг, где распределительная линия подсоединяется непосредственно к спринклеру (согласно примечаниям таблицы)","Дисковые поворотные затворы на стояке","Поворотные обратные клапаны"], re:"Согласно примечаниям таблицы, потери на трение обычно не добавляются для фитинга, непосредственно подсоединяющегося к спринклеру (собственные потери спринклера учитываются отдельно); клапаны и поворотные фитинги по-прежнему учитываются. Ref: примечания по применению таблицы эквивалентных длин NFPA 13."},
  {id:347, q:"Для медной трубки или пластиковой трубы NFPA 13 указывает проектировщику:", opts:["Использовать значения эквивалентной длины для стали без изменений","Полностью игнорировать фитинги","Использовать сертифицированные данные фитингов / надлежащие эквивалентные длины и применить надлежащую поправку на значение C","Использовать только столбец 6 in."], re:"Поскольку таблица основана на стали/C=120, медь и пластик требуют данных фитингов от производителя/сертифицированных или поправочного коэффициента на значение C (например, C = 150). Ref: положения о поправке на значение C таблицы эквивалентных длин NFPA 13."},
  {id:348, q:"Полная эквивалентная длина трубы, используемая для расчёта потерь на трение на участке, равна:", opts:["Только фитинги","Только прямая труба","Значение одного наибольшего фитинга","Фактическая длина прямой трубы ПЛЮС сумма всех эквивалентных длин фитингов/клапанов на этом участке"], re:"Потери на трение основаны на фактической измеренной длине трубы, сложенной с суммой эквивалентных длин всех фитингов и клапанов в трассе потока этого участка. Ref: процедура гидравлического расчёта NFPA 13 (эквивалентная длина)."},
  {id:349, q:"Специально сертифицированные устройства (например, сертифицированные гибкие спринклерные сбросы, обратные предохранители, фильтры-грязевики) должны иметь свои потери на трение, определённые по:", opts:["Сертифицированным данным потерь на трение производителя для конкретного устройства","Только стандартной таблице фитингов","Допущению о нулевых потерях","Использованию значения задвижки"], re:"Сертифицированные специальные устройства имеют собственные опубликованные (сертифицированные) данные потерь на трение, которые должны использоваться вместо общей таблицы фитингов. Ref: положения NFPA 13 о потерях на трение сертифицированных устройств."},
  {id:350, q:"Переходный фитинг или переходник в гидравлических расчётах NFPA 13 обычно учитывается:", opts:["Начислением его как полного отвода 90 градусов","Использованием эквивалентной длины меньшего (выходного) размера трубы для фитинга, согласно примечаниям таблицы","Игнорированием его всегда","Удвоением значения большей трубы"], re:"Примечания таблицы NFPA 13 указывают, что эквивалентная длина фитинга основывается на меньшем (по потоку ниже) отверстии фитинга, когда размеры различаются. Ref: примечания таблицы эквивалентных длин NFPA 13 о переходных фитингах."},
  {id:351, q:"Для стальной трубы Schedule 40 номинальным размером 1 in. и меньше максимальное расстояние между подвесами/опорами, допускаемое NFPA 13, составляет:", opts:["8 ft","10 ft","12 ft","15 ft"], re:"Таблица NFPA 13 для максимального расстояния между подвесами даёт 12 ft для стальной трубы 3/4 in. и 1 in.; для стали 1-1/4 in. и больше — 15 ft. Ref: таблица максимального расстояния между подвесами/опорами NFPA 13."},
  {id:352, q:"Для стальной трубы Schedule 40 размером 1-1/4 in. и больше максимальное расстояние между подвесами/опорами, допускаемое NFPA 13, составляет:", opts:["12 ft","18 ft","20 ft","15 ft"], re:"NFPA 13 допускает максимальный шаг подвесов 15 ft для стальной трубы 1-1/4 in. и больше (12 ft для 3/4 in. и 1 in.). Ref: таблица максимального расстояния между подвесами/опорами NFPA 13."},
  {id:353, q:"NFPA 13 требует, чтобы компоненты подвеса/опоры, контактирующие с трубой, и конструктивное крепление были:", opts:["Сертифицированными (компоненты узла подвеса должны быть сертифицированы), за исключением некоторых допускаемых стандартных креплений","Приварены на объекте","Изготовлены из пластика","Окрашены в красный"], re:"Подвесы/опоры и их компоненты должны быть сертифицированы, с ограниченными исключениями для некоторых стандартных конструктивных креплений (например, обычных крепёжных элементов к зданию). Ref: требования к сертификации подвесов/опор NFPA 13."},
  {id:354, q:"Минимальный диаметр тяги подвеса для спринклерной трубы 4 in. и меньше по NFPA 13 составляет:", opts:["1/4 in.","3/8 in.","1/2 in.","5/8 in."], re:"Таблица размеров тяги подвеса NFPA 13 требует минимальную тягу 3/8 in. для трубы до 4 in. включительно. Ref: таблица размеров тяги подвеса NFPA 13."},
  {id:355, q:"Для спринклерной трубы 5 in. и 6 in. минимальный диаметр тяги подвеса, требуемый NFPA 13, составляет:", opts:["3/8 in.","5/8 in.","1/2 in.","3/4 in."], re:"NFPA 13 требует минимальную тягу подвеса 1/2 in. для трубы 5 in. и 6 in. (3/8 in. для 4 in. и меньше). Ref: таблица размеров тяги подвеса NFPA 13."},
  {id:356, q:"Для спринклерной трубы 8 in. минимальный диаметр тяги подвеса, требуемый NFPA 13, составляет:", opts:["3/8 in.","1/2 in.","1 in.","5/8 in."], re:"NFPA 13 требует минимальную тягу подвеса 5/8 in. для трубы 8 in. (и аналогичной трубы большого размера). Ref: таблица размеров тяги подвеса NFPA 13."},
  {id:357, q:"На распределительной линии NFPA 13 требует не менее одного подвеса/опоры между спринклерами, когда расстояние между ними превышает:", opts:["6 ft","3 ft","10 ft","12 ft"], re:"NFPA 13 требует подвес/опору между спринклерами там, где шаг превышает 6 ft на распределительной линии. Ref: расположение подвесов/опор на распределительных линиях NFPA 13."},
  {id:358, q:"Для стальной трубы распределительной линии максимальная неподдерживаемая длина между крайним спринклером и последним подвесом/опорой линии обычно ограничена (по размеру трубы) примерно:", opts:["6 in. независимо от размера","36 in. для 1 in. до 48 in. для больших размеров стали","10 ft для всех размеров","Без ограничения"], re:"NFPA 13 ограничивает длину неподдерживаемого плеча от последнего подвеса до крайнего спринклера по размеру трубы для стали (порядка 36 in. для 1 in., увеличиваясь для большей трубы). Ref: положения о неподдерживаемой длине/конце линии для стали NFPA 13."},
  {id:359, q:"Для МЕДНОЙ трубки номинальным размером 1 in. NFPA 13 ограничивает неподдерживаемую горизонтальную длину от последнего подвеса/опоры до крайнего спринклера до:", opts:["12 in.","24 in.","18 in.","30 in."], re:"NFPA 13 ограничивает неподдерживаемую концевую длину для меди до 18 in. (1 in.), 24 in. (1-1/4 in.) и 30 in. (1-1/2 in. и больше). Ref: неподдерживаемая длина для медной трубки NFPA 13."},
  {id:360, q:"Поскольку медная трубка менее жёсткая, чем сталь, NFPA 13 обычно требует шаг подвесов/опор для меди, который:", opts:["Больше, чем для стали","Всегда точно такой же, как для стали","Неограниченный","Меньше (более короткий максимальный шаг), чем для стали того же размера в меньших размерах"], re:"Меньшая жёсткость меди требует более близкой опоры, чем для стали в малых размерах (например, шаг для меди составляет примерно 8-15 ft по размеру против 12-15 ft для стали). Ref: максимальное расстояние между подвесами/опорами (медная трубка) NFPA 13."},
  {id:361, q:"Сертифицированная спринклерная труба CPVC размером 1 in. обычно имеет максимальный шаг опор порядка:", opts:["Около 5.5-6 ft согласно её сертификации","15 ft","12 ft","30 ft"], re:"CPVC требует гораздо более близкой опоры, чем металл (около 5.5-6 ft для малых размеров, до ~10 ft для больших), как установлено его сертификацией и отражено в NFPA 13. Ref: шаг подвесов сертификации NFPA 13 / CPVC."},
  {id:362, q:"Подвес-трапеция используется, когда:", opts:["Труба только пластиковая","Конструктивный элемент не расположен непосредственно над трубой и нагрузку нужно передать на два соседних элемента","Труба подземная","Подвесы недоступны"], re:"Подвес-трапеция перекрывает расстояние между двумя конструктивными элементами для опоры трубы там, где ни один элемент не расположен непосредственно над ней; NFPA 13 требует подобрать его по нагрузке с использованием таблиц момента сопротивления сечения. Ref: положения о подвесе-трапеции NFPA 13."},
  {id:363, q:"При подборе элемента трапеции (опоры) NFPA 13 требует, чтобы проектировщик проверил его:", opts:["Цвет","Шаг резьбы","Момент сопротивления сечения (для обеспечения достаточной прочности для опираемой трубы и пролёта)","Сертификацию как спринклера"], re:"Элемент трапеции должен иметь момент сопротивления сечения не менее значения, требуемого таблицами трапеций NFPA 13 для опираемого размера трубы и пролёта. Ref: таблицы момента сопротивления сечения подвеса-трапеции NFPA 13."},
  {id:364, q:"NFPA 13 требует, чтобы каждый подвес/опора (и поддерживающая его конструкция) был способен выдержать:", opts:["Только вес пустой трубы","Удвоенный вес пустой трубы","Только вес спринклера","Пятикратный вес заполненной водой трубы плюс 250 lb в каждой точке опоры трубопровода"], re:"NFPA 13 требует, чтобы подвесы/опоры и их крепёж выдерживали пятикратный вес заполненной водой трубы плюс 250 lb в каждой точке опоры. Ref: требование к нагрузке подвеса (коэффициент запаса) NFPA 13."},
  {id:365, q:"Первый подвес/опора на распределительной линии, отсчитываемый от соединения с поперечной магистралью, должен располагаться обычно в пределах:", opts:["Не более максимального расстояния шага для этой трубы (согласно правилам подвесов распределительной линии)","Ровно 6 in.","30 ft","Без ограничения"], re:"NFPA 13 привязывает расположение первого/каждого подвеса на распределительной линии к максимальному шагу для размера трубы, с конкретными ограничениями в начале линии возле поперечной магистрали. Ref: расположение подвесов/опор на распределительных линиях NFPA 13."},
  {id:366, q:"Там, где спринклер устанавливается на стояковом ниппеле (отвод вверх, sprig-up) длиннее заданной длины, NFPA 13 требует:", opts:["Вообще без опоры","Чтобы отвод/стояковый ниппель был раскреплён или поддержан (например, когда он превышает сертифицированную неподдерживаемую высоту, обычно 30 in.)","Только подвес-трапецию","Заварить его наглухо"], re:"Отвод вверх, превышающий допускаемую неподдерживаемую длину (обычно 30 in.), должен быть раскреплён от бокового движения/хлёстки. Ref: опора стояковых ниппелей / отводов вверх NFPA 13."},
  {id:367, q:"Дюбели порохового монтажа и приварные шпильки, используемые для крепления подвесов к конструкции здания, должны быть:", opts:["Любой крепёж из хозяйственного магазина","Пластиковые анкеры","Сертифицированы для эксплуатации или установлены по одобренному методу и не использоваться для опоры трубы в растяжении сверх их номинала","Полностью исключены"], re:"NFPA 13 ограничивает дюбели порохового монтажа/приварные шпильки и другой крепёж сертифицированными/одобренными типами и нагрузочными номиналами, с ограничениями применения в некоторых материалах. Ref: положения о крепеже в бетоне/стали NFPA 13."},
  {id:368, q:"Назначение БОКОВЫХ сейсмических связей — сопротивляться горизонтальному перемещению трубопровода:", opts:["Параллельно трассе трубы","Только вертикально","Только на кручение","Перпендикулярно (под прямым углом) к трассе трубы"], re:"Боковые связи сопротивляются горизонтальным сейсмическим нагрузкам, действующим перпендикулярно оси раскреплённой трубы. Ref: определения сейсмических связей NFPA 13 (боковая связь)."},
  {id:369, q:"Назначение ПРОДОЛЬНЫХ сейсмических связей — сопротивляться горизонтальному перемещению трубопровода:", opts:["Параллельно (вдоль оси) трассе трубы","Перпендикулярно трассе трубы","Только вертикально вниз","Только у спринклера"], re:"Продольные связи сопротивляются горизонтальным сейсмическим нагрузкам, действующим параллельно (вдоль) оси раскреплённой трубы. Ref: определения сейсмических связей NFPA 13 (продольная связь)."},
  {id:370, q:"Максимальный шаг между БОКОВЫМИ сейсмическими связями на питающих и поперечных магистралях составляет:", opts:["20 ft","40 ft","80 ft","100 ft"], re:"NFPA 13 ограничивает шаг боковых связей максимумом 40 ft по осям. Ref: максимальный шаг боковых сейсмических связей NFPA 13."},
  {id:371, q:"Максимальный шаг между ПРОДОЛЬНЫМИ сейсмическими связями составляет:", opts:["40 ft","60 ft","80 ft","120 ft"], re:"NFPA 13 ограничивает шаг продольных связей максимумом 80 ft по осям. Ref: максимальный шаг продольных сейсмических связей NFPA 13."},
  {id:372, q:"Последняя боковая сейсмическая связь на участке трубы должна располагаться в пределах какого расстояния от конца трубы?", opts:["12 ft","24 ft","40 ft","6 ft"], re:"NFPA 13 требует, чтобы последняя боковая связь была в пределах 6 ft от конца трубопровода. Ref: требование к расстоянию до конца боковой связи NFPA 13."},
  {id:373, q:"Последняя продольная сейсмическая связь должна располагаться в пределах какого расстояния от конца трубы?", opts:["40 ft","6 ft","12 ft","24 ft"], re:"NFPA 13 требует, чтобы последняя продольная связь была в пределах 40 ft от конца трубопровода. Ref: требование к расстоянию до конца продольной связи NFPA 13."},
  {id:374, q:"Боковые сейсмические связи требуются на распределительных линиях (и магистралях), когда труба имеет как минимум какой номинальный размер?", opts:["1 in.","2-1/2 in.","1-1/2 in.","6 in."], re:"NFPA 13 требует раскрепления питающих/поперечных магистралей и распределительных линий 2-1/2 in. и больше; меньшие распределительные линии раскрепляются от перемещения, но не обязательно связями. Ref: область раскрепления NFPA 13 (2-1/2 in. и больше)."},
  {id:375, q:"'Зона влияния' сейсмической связи лучше всего описывается как:", opts:["Площадь пола здания, которую она занимает","Номинальное давление трубы","Длина/вес трубопровода, который связь отвечает за раскрепление, пока следующая связь не примет нагрузку","Зазорное отверстие вокруг прохода"], re:"Зона влияния — это часть трубопровода (и содержащейся воды), приходящаяся на данную связь, используемая с сейсмическим коэффициентом для расчёта нагрузки на связь. Ref: определение сейсмической нагрузки NFPA 13 (зона влияния)."},
  {id:376, q:"Горизонтальная сейсмическая нагрузка (Fpw), используемая для подбора сейсмической связи, вычисляется как:", opts:["Fpw = диаметр трубы / 2","Fpw = длина x значение C","Fpw = 250 lb фиксированно","Fpw = Cp x Wp (сейсмический коэффициент, умноженный на приходящийся вес трубы и воды)"], re:"NFPA 13 вычисляет нагрузку на связь как Fpw = Cp x Wp, где Cp — сейсмический коэффициент, а Wp — вес заполненной водой трубы в зоне влияния. Ref: формула нагрузки сейсмической связи NFPA 13."},
  {id:377, q:"В сейсмической процедуре NFPA 13 коэффициент Cp определяется главным образом из:", opts:["Картированного спектрального отклика короткого периода (Ss) на участке","Цвета трубы","Числа спринклеров","Значения C трубы"], re:"Cp берётся из таблицы NFPA 13 как функция спектрального ускорения отклика короткого периода Ss на участке (часто по умолчанию около 0.5 при отсутствии данных по конкретному участку). Ref: таблица сейсмического коэффициента (Cp) и Ss NFPA 13."},
  {id:378, q:"Сейсмическая связь должна устанавливаться под углом от вертикали (или измеренным согласно NFPA 13) не менее:", opts:["10 градусов","30 градусов","60 градусов","75 градусов"], re:"NFPA 13 требует, чтобы сейсмические связи составляли угол не менее 30 градусов от вертикали (предпочтительно 45-90 градусов), чтобы быть эффективными; углы менее 30 градусов не засчитываются. Ref: требования к углу сейсмической связи NFPA 13."},
  {id:379, q:"В верхней части спринклерного стояка NFPA 13 требует:", opts:["Без раскрепления","Только подвес","Четырёхстороннее раскрепление (как боковое, так и продольное удержание)","Только гибкую муфту"], re:"Стояки должны снабжаться четырёхсторонним раскреплением (сопротивляющимся перемещению в обоих горизонтальных направлениях), расположенным возле верха стояка в пределах требуемого расстояния. Ref: четырёхстороннее раскрепление стояков NFPA 13."},
  {id:380, q:"Одна боковая связь может также служить продольной связью для соседнего участка, когда:", opts:["Никогда; они всегда должны быть раздельными","Труба пластиковая","Угол связи менее 30 градусов","Связь находится в пределах допускаемого смещения (например, в пределах 24 in. от оси трубы), и присоединяемая труба того же или большего размера"], re:"NFPA 13 допускает, чтобы боковая связь работала продольно для присоединённой линии, когда она расположена в пределах допускаемого расстояния (около 24 in.) от оси, и присоединяемая труба не менее равного размера. Ref: положения о совместном использовании связей NFPA 13."},
  {id:381, q:"Узлы сейсмических связей и их крепёж должны подбираться так, чтобы они не разрушались до приложения нагрузок здания; поэтому NFPA 13 требует, чтобы компоненты связи были:", opts:["Сертифицированы и подобраны из таблиц нагрузок связей для расчётной нагрузки и угла связи","Несертифицированы и собраны на объекте","Больше трубы 4 in.","Приварены к спринклеру"], re:"NFPA 13 требует сертифицированных компонентов сейсмических связей, подобранных из таблиц нагрузок на основе расчётного Fpw и установленного угла и длины связи. Ref: сертификация компонентов сейсмических связей и таблицы нагрузок NFPA 13."},
  {id:382, q:"Гибкость (l/r) элемента сейсмической связи важна, потому что:", opts:["Она задаёт значение C трубы","Она ограничивает сжимающую (на потерю устойчивости) способность связей, сопротивляющихся нагрузке на сжатие","Она определяет k-фактор спринклера","Она не влияет"], re:"Для связей, сопротивляющихся сжатию, NFPA 13 ограничивает гибкость (длина/радиус инерции), чтобы предотвратить потерю устойчивости; тросовые связи сопротивляются только растяжению. Ref: ограничения гибкости элементов сейсмических связей NFPA 13."},
  {id:383, q:"Тросовые сейсмические связи (стальной канат) отличаются от жёстких связей тем, что тросовые связи:", opts:["Сопротивляются как растяжению, так и сжатию","Используются только под землёй","Сопротивляются только растяжению, поэтому должны устанавливаться встречными парами для каждого направления","Не требуют сертификации"], re:"Тросовые связи несут только растяжение; чтобы раскрепить направление, их располагают так, чтобы трос сопротивлялся каждому смыслу движения (встречные пары), в отличие от жёстких связей, воспринимающих растяжение или сжатие. Ref: положения о тросовых сейсмических связях NFPA 13."},
  {id:384, q:"Узел сейсмического разрыва требуется везде, где спринклерный трубопровод:", opts:["Переходит со стали на медь","Соединяется со спринклером","Проходит под дверью","Пересекает сейсмический разделительный (деформационный) шов здания"], re:"NFPA 13 требует узел сейсмического разрыва с гибкими фитингами, независимо от размера трубы, там, где трубопровод пересекает сейсмический разделительный шов здания над землёй. Ref: требование к узлу сейсмического разрыва NFPA 13."},
  {id:385, q:"Функция узла сейсмического разрыва — это:", opts:["Допускать перемещение во всех направлениях, чтобы дифференциальное движение двух секций здания не разорвало трубу","Увеличивать давление воды","Уменьшать потери на трение","Действовать как обратный клапан"], re:"Узел использует гибкие муфты/фитинги, чтобы воспринять разнонаправленное дифференциальное перемещение через шов, предотвращая разрыв трубы. Ref: назначение узла сейсмического разрыва NFPA 13."},
  {id:386, q:"Гибкие муфты требуется устанавливать в пределах какого расстояния от верха и низа каждого спринклерного стояка?", opts:["6 in.","24 in.","12 in.","48 in."], re:"NFPA 13 требует сертифицированную гибкую муфту в пределах 24 in. от верха и низа каждого стояка (с исключениями для коротких стояков). Ref: расположение гибких муфт на стояках NFPA 13."},
  {id:387, q:"В многоэтажном здании NFPA 13 требует гибкие муфты на стояках на каждом этаже, обычно расположенные в пределах:", opts:["Без конкретного расстояния","10 ft от этажа","12 in. выше и 24 in. ниже этажа/потолка согласно правилу","Только середины этажа"], re:"NFPA 13 требует гибкие муфты возле каждого этажа (обычно в пределах 12 in. выше и 24 in. ниже этажа), чтобы воспринять междуэтажный сдвиг. Ref: требования к гибким муфтам на этажах в многоэтажных зданиях NFPA 13."},
  {id:388, q:"Там, где спринклерная труба номиналом от 1 in. до 3-1/2 in. проходит сквозь стены или перекрытия, NFPA 13 требует номинальный зазор вокруг трубы, так чтобы диаметр отверстия был больше трубы на:", opts:["Зазор не нужен","6 in. суммарно","12 in. суммарно","2 in. суммарно (около 1 in. по периметру)"], re:"Для трубы номиналом от 1 in. до 3-1/2 in. отверстие выполняется примерно на 2 in. больше трубы (примерно 1 in. зазора с каждой стороны), чтобы допустить перемещение. Ref: зазор вокруг трубопровода в проходах NFPA 13."},
  {id:389, q:"Для спринклерной трубы номиналом 4 in. и больше, проходящей сквозь стены/перекрытия, требуемое отверстие больше трубы примерно на:", opts:["4 in. суммарно (около 2 in. по периметру)","2 in. суммарно","Без зазора","12 in. суммарно"], re:"Для трубы 4 in. и больше отверстие выполняется примерно на 4 in. больше трубы (около 2 in. зазора с каждой стороны). Ref: зазор вокруг трубопровода в проходах NFPA 13."},
  {id:390, q:"Зазор вокруг прохода трубы в конструкции с нормируемым пределом огнестойкости должен по-прежнему:", opts:["Оставаться полностью открытым","Заполняться сертифицированной гибкой/податливой огнепреградой (упругим материалом), которая сохраняет предел, но допускает перемещение","Завариваться наглухо","Заделываться сплошным бетоном"], re:"Там, где требуемый зазор проходит сквозь нормируемую преграду, применяют сертифицированную гибкую систему огнепреграды, чтобы труба могла перемещаться, а предел огнестойкости сохранялся. Ref: положения о зазоре, применяемые с сертифицированной гибкой огнепреградой NFPA 13."},
  {id:391, q:"NFPA 13 допускает не устраивать зазор вокруг прохода (зазор не требуется), когда:", opts:["Труба 8 in. или больше","Стена окрашена","Сертифицированная гибкая муфта предусмотрена в пределах заданного расстояния с каждой стороны прохода","Труба медная"], re:"Зазор может не устраиваться там, где гибкая муфта установлена в пределах заданного расстояния с обеих сторон прохода, поскольку это соединение воспринимает перемещение. Ref: исключение по зазору при наличии соседних гибких муфт NFPA 13."},
  {id:392, q:"Малая труба распределительной линии (менее 2-1/2 in.), которая не раскреплена связями, должна по-прежнему быть:", opts:["Оставлена свободно качаться","Приварена к потолку","Подобрана как 4 in.","Раскреплена от чрезмерного бокового перемещения возле конца линии (например, сертифицированными ограничителями или U-образными скобами)"], re:"NFPA 13 требует концевого раскрепления для нераскреплённых связями распределительных линий (с применением охватывающих U-образных скоб или сертифицированных ограничителей) для ограничения перемещения, хотя полное раскрепление связями не требуется. Ref: раскрепление распределительных линий NFPA 13."},
  {id:393, q:"Сертифицированная гибкая муфта, применяемая в сейсмических целях, обеспечивает защиту, допуская:", opts:["Небольшую угловую/осевую подвижность в соединении, так чтобы напряжение не передавалось как жёсткий момент","Только больший расход","Электрическое заземление","Снижение давления"], re:"Гибкие муфты воспринимают ограниченную угловую и осевую подвижность, снимая сейсмическое напряжение, которое жёсткое соединение иначе передало бы трубе и фитингам. Ref: функция гибкой муфты в сейсмическом проектировании NFPA 13."},
  {id:394, q:"NFPA 13 в целом допускает ПРОПУСК сейсмического раскрепления (и связанных положений) там, где:", opts:["Труба пластиковая","Здание находится в регионе/зоне, освобождённой стандартом, или AHJ не требует сейсмической защиты","Система сухая","Потолок высокий"], re:"Сейсмическая защита по NFPA 13 применяется там, где её требует AHJ, или в определённых сейсмических регионах; она может быть пропущена там, где сейсмическое проектирование для участка не требуется. Ref: применимость сейсмической защиты (где требуется) NFPA 13."},
  {id:395, q:"Сбросы к рукавным линиям, стеллажным спринклерам и антресолям, а также другие части, подверженные дифференциальному перемещению, должны защищаться:", opts:["Только жёсткой сваркой","Удалением сброса","Гибкостью (например, гибкими муфтами или сертифицированными гибкими соединениями) для поглощения относительного перемещения","Большими значениями C"], re:"Там, где ожидается относительное перемещение (между стеллажами/конструкцией и системой), применяют гибкие муфты или сертифицированные гибкие соединения, чтобы сбросы не срезались. Ref: положения о гибкости для сбросов, подверженных дифференциальному перемещению NFPA 13."},
  {id:396, q:"Основная причина, по которой гибкие муфты стояка размещают близко к проходам перекрытий в высотных зданиях, — воспринять:", opts:["Только тепловое расширение","Скачки давления","Гидроудар от спринклеров","Междуэтажный сдвиг (относительное горизонтальное смещение между соседними этажами во время землетрясения)"], re:"Гибкие муфты возле этажей поглощают междуэтажный сдвиг, чтобы сейсмическое относительное смещение между этажами не разрушило стояк. Ref: обоснование гибких муфт на этажах NFPA 13."},
  {id:397, q:"Когда трубопровод жёстко прикреплён к двум отдельным конструкциям (или конструкции и оборудованию), которые могут двигаться независимо, NFPA 13 требует:", opts:["Гибкость между двумя точками крепления, чтобы дифференциальному перемещению не сопротивлялись жёстко","Больший размер трубы","Поворотный обратный клапан","Редукционный клапан давления"], re:"Между независимо движущимися опорами должна быть предусмотрена гибкость (гибкие муфты/узел разрыва), чтобы предотвратить разрыв трубы дифференциальным движением. Ref: гибкость между независимыми конструкциями NFPA 13."},
  {id:398, q:"Для сейсмической защиты по NFPA 13 (в отличие от FM Global) компоненты связей и раскрепления требуется, чтобы были:", opts:["Только одобрены FM","Сертифицированы (например, сертифицированы UL) для эксплуатации","Несертифицированными цеховыми изделиями","Изготовлены из чугуна"], re:"NFPA 13 требует сертифицированных компонентов для сейсмических связей и раскрепления; стандарты FM Global вместо этого требуют одобренных FM компонентов. Ref: требование сертификации компонентов раскрепления NFPA 13."},
  {id:399, q:"Общая цель сейсмических положений NFPA 13 (связи, гибкие муфты, зазоры, узлы разрыва) — это:", opts:["Увеличить расход системы","Снизить давление воды","Сохранить спринклерную систему целой и работоспособной после землетрясения, ограничивая повреждающее перемещение и допуская необходимое перемещение","Уменьшить число спринклеров"], re:"Сейсмический комплекс ограничивает повреждающее дифференциальное перемещение (связи), допуская необходимое перемещение (муфты, зазоры, узлы разрыва), чтобы система пережила событие и работала после него. Ref: назначение сейсмической защиты трубопровода NFPA 13."},
  {id:400, q:"Короткий стояк освобождается от одной или обеих требуемых гибких муфт, когда его длина ниже порога; NFPA 13 обычно допускает пропуск муфт на стояке длиной менее:", opts:["1 ft","12 ft","20 ft","3 ft (с одной муфтой, допускаемой для стояков от 3 ft до 7 ft)"], re:"NFPA 13 допускает пропуск гибких муфт на стояках менее 3 ft и одну гибкую муфту на стояках длиной от 3 ft до 7 ft. Ref: исключения по гибким муфтам для коротких стояков NFPA 13."},
  {id:401, q:"При испытании пожарного гидранта расходом какие три значения давления/расхода регистрируются для определения водоснабжения, доступного для системы?", opts:["Статическое давление, остаточное давление и расходный (пито) сброс","Давление при закрытой задвижке (churn), номинальное давление и давление перегрузки","Рабочее давление, гидростатическое давление и давление гидроудара","Чистое давление, давление на всасывании и давление на нагнетании"], re:"Испытание гидранта расходом регистрирует статическое давление (без расхода), остаточное давление на испытательном гидранте при протекании воды и расходный сброс (вычисляемый по давлению пито на гидранте с расходом). Ссылка: NFPA 291, Рекомендуемая практика испытания пожарного расхода и маркировки гидрантов."},
  {id:402, q:"На графике водоснабжения, используемом для гидравлического расчёта, кривая водопитателя строится с каким показателем степени на логарифмической бумаге (N^1.85)?", opts:["1.50","1.85","2.00","2.63"], re:"Кривые водоснабжения строятся на бумаге N^1.85, соответствующей показателю трения Хазена-Уильямса (Q^1.85), так что линия водопитателя строится как прямая. Ссылка: NFPA 291; процедуры гидравлического расчёта NFPA 13."},
  {id:403, q:"Расходный сброс (Q, gpm) из выходного отверстия гидранта во время испытания расходом вычисляется на основе какой измеренной величины?", opts:["Остаточное давление на соседнем гидранте","Статическое давление перед началом расхода","Давление пито (скоростное) на выходном отверстии с расходом","Разность высот до самого высокого спринклера"], re:"Сброс вычисляется как Q = 29.83 x c x d^2 x sqrt(p), где p — давление пито (скоростное), измеренное на выходном отверстии с расходом, d — диаметр отверстия, c — коэффициент расхода. Ссылка: расчёт расхода NFPA 291."},
  {id:404, q:"Испытание расходом даёт статическое 70 psi и остаточное 50 psi при расходе 1,000 gpm. По сравнению с испытанием, которое падает до 30 psi при 1,000 gpm, первое водоснабжение:", opts:["Слабее, потому что остаточное упало меньше","Идентично, потому что оба дали расход 1,000 gpm","Неопределимо без показания пито","Сильнее, потому что остаточное упало меньше при том же расходе"], re:"Меньшее падение давления (70 до 50 psi против 70 до 30 psi) при том же расходе указывает на более сильное, более жёсткое водоснабжение с большим доступным давлением при более высоких расходах. Ссылка: интерпретация кривой водопитателя NFPA 291."},
  {id:405, q:"Для проектирования спринклерной системы потребность системы (расход и давление) должна сравниваться с доступным водоснабжением в какой точке?", opts:["В общей опорной точке, где оба известны, например в источнике водоснабжения","Только в основании стояка","У самого удалённого спринклера","У соединения пожарной части"], re:"Потребность и водоснабжение строятся/сравниваются в общей опорной точке (часто источник или определённый узел), где известны характеристики обоих. NFPA 13 требует, чтобы расчёты доходили до эффективной точки водоснабжения. Ссылка: NFPA 13, Планы и расчёты."},
  {id:406, q:"Когда гидравлически рассчитанная спринклерная потребность нанесена на график водоснабжения и оказывается НИЖЕ кривой доступного водопитателя, результат указывает:", opts:["Водоснабжение недостаточно, требуется пожарный насос","Водоснабжение достаточно для удовлетворения потребности","Все размеры труб должны быть увеличены","Данные испытания недействительны"], re:"Если точка потребности лежит ниже (и левее) кривой доступного водопитателя, водоснабжение может обеспечить требуемый расход при требуемом давлении или выше, поэтому водоснабжение достаточно. Ссылка: анализ гидравлического графика NFPA 13; NFPA 291."},
  {id:407, q:"Потери на трение в трубопроводах противопожарной защиты чаще всего рассчитываются с использованием какой формулы?", opts:["Уравнение Бернулли","Уравнение Дарси-Вейсбаха","Формула Хазена-Уильямса","Формула Маннинга"], re:"NFPA 13 предписывает определять потери на трение в трубе с использованием формулы Хазена-Уильямса с коэффициентом C, соответствующим материалу трубы. Ссылка: процедуры гидравлического расчёта NFPA 13."},
  {id:408, q:"В формуле Хазена-Уильямса БОЛЕЕ НИЗКОЕ значение коэффициента C представляет:", opts:["Более гладкую трубу с меньшими потерями на трение","Больший диаметр трубы","Более высокую температуру воды","Более шероховатую трубу с большими потерями на трение"], re:"Коэффициент C Хазена-Уильямса описывает шероховатость внутренней поверхности трубы; более низкое C означает более шероховатую внутреннюю поверхность и, следовательно, большие потери на трение при данном расходе. Ссылка: таблицы коэффициента C NFPA 13 (например, C=120 для нефутерованного чугуна/ковкого чугуна, C=140 для футерованного цементом)."},
  {id:409, q:"Скоростное давление в гидравлическом расчёте — это часть давления, обусловленная:", opts:["Скоростью (движением) текущей воды","Высотой воды над манометром","Атмосферным давлением на поверхности","Обратным потоком из городской магистрали"], re:"Скоростное давление (Pv = 0.001123 Q^2 / d^4) — это давление, обусловленное кинетической энергией движущейся воды; нормальное давление — разность между полным и скоростным давлением. Ссылка: определения гидравлического расчёта NFPA 13."},
  {id:410, q:"Потери на высоту (давление) в системе противопожарной защиты принимаются приблизительно как:", opts:["0.500 psi на фут высоты","0.433 psi на фут высоты","1.000 psi на фут высоты","2.310 psi на фут высоты"], re:"Столб воды создаёт 0.433 psi на фут высоты (эквивалентно 1 psi на 2.31 ft). Прирост высоты прибавляется к потребности по давлению в гидравлических расчётах. Ссылка: процедуры гидравлического расчёта NFPA 13."},
  {id:411, q:"Испытание расходом проводится для подбора пожарного насоса. NFPA 20 требует, чтобы данные испытания расходом, используемые для подбора, были получены в течение предшествующих:", opts:["3 месяцев","6 месяцев","12 месяцев","24 месяцев"], re:"NFPA 20 требует, чтобы испытание водопитателя расходом, используемое для определения водоснабжения при подборе пожарного насоса, было проведено в течение 12 месяцев до проектирования (текущая редакция). Ссылка: NFPA 20, Стандарт на установку стационарных насосов для противопожарной защиты."},
  {id:412, q:"При проецировании кривой водоснабжения пожарный расход обычно оценивается при остаточном давлении:", opts:["40 psi","65 psi","100 psi","20 psi"], re:"Доступный пожарный расход обычно указывается при остаточном давлении 20 psi — распространённом минимальном пороге рабочего давления для городских магистралей и стандартной точке проецирования на графиках водоснабжения. Ссылка: NFPA 291; практика пожарного расхода AWWA/ISO."},
  {id:413, q:"Чтобы преобразовать расход Q1, наблюдаемый при остаточном P1, в расход при другом остаточном, аналитик использует соотношение Q2 = Q1 x (h2/h1)^0.54, где h — это:", opts:["Падение давления (статическое минус остаточное)","Диаметр трубы","Только высотный напор","Давление пито"], re:"В NFPA 291 h = падение давления = статическое минус остаточное; номинальная производительность при целевом остаточном равна QR = QF x (hr/hf)^0.54. Ссылка: уравнение проецирования расхода NFPA 291."},
  {id:414, q:"'Закольцованная' или сетчатая магистраль водопитателя по сравнению с одиночной тупиковой магистралью того же размера, как правило, обеспечивает:", opts:["Меньший доступный расход из-за дополнительного трения","Больший доступный расход, потому что вода достигает точки по нескольким путям","Никакой разницы в доступном расходе","Большее статическое, но меньшее остаточное давление"], re:"Закольцованные/сетчатые магистрали питают точку потребности более чем с одного направления, снижая эффективные потери на трение и увеличивая доступный расход при данном остаточном давлении по сравнению с тупиковой магистралью. Ссылка: принципы водоснабжения NFPA 24/NFPA 291."},
  {id:415, q:"В анализе водоснабжения для проектирования 'доступное давление' в точке подключения водоснабжения относится к:", opts:["Давлению, которое требуется системе для работы","Максимальному давлению, которое насос может создать при закрытой задвижке (churn)","Давлению, которое городское/частное водоснабжение может обеспечить при проектном расходе","Гидростатическому испытательному давлению"], re:"Доступное давление — это то, что водоснабжение может обеспечить в точке подключения при требуемом расходе; оно должно равняться или превышать давление потребности системы (плюс запас безопасности), чтобы проект работал. Ссылка: NFPA 13/NFPA 291."},
  {id:416, q:"Проектный запас безопасности часто применяется, чтобы точка потребности не лежала точно на кривой водопитателя. Распространённая практика — поддерживать доступное водоснабжение по крайней мере:", opts:["Точно равным потребности","В три раза выше давления потребности","Ниже потребности, чтобы учесть гидроудар","Примерно на 10 psi (или 10%) выше рассчитанной потребности"], re:"Проектировщики обычно обеспечивают запас (как правило, порядка 10 psi или 10%) между доступным водоснабжением и рассчитанной потребностью, чтобы учесть колебания водоснабжения и его ухудшение со временем. Ссылка: распространённая практика проектирования NFPA 13 / требования AHJ."},
  {id:417, q:"Если доступное водоснабжение здания достаточно по расходу, но недостаточно по ДАВЛЕНИЮ для спринклерной потребности, наиболее подходящее решение обычно:", opts:["Установить пожарный насос для повышения давления","Уменьшить проектную площадь","Добавить больше гидрантов на городскую магистраль","Снизить коэффициент C, используемый в расчётах"], re:"Когда расход достаточен, но давление ниже потребности, добавляется пожарный насос для повышения давления до требуемого уровня. Резервуар (с насосом) решает проблемы дефицита расхода/объёма. Ссылка: NFPA 20; проектирование NFPA 13."},
  {id:418, q:"NFPA 20 ограничивает максимальное давление при закрытой задвижке (без расхода, отсечка) центробежного пожарного насоса не более чем каким процентом от его номинального давления?", opts:["100% от номинального давления","140% от номинального давления","120% от номинального давления","150% от номинального давления"], re:"NFPA 20 требует, чтобы давление при закрытой задвижке (без расхода) не превышало 140% от номинального давления насоса, ограничивая максимальное давление системы. Ссылка: NFPA 20, требования к характеристикам центробежных пожарных насосов."},
  {id:419, q:"При 150% от своей номинальной производительности (точка перегрузки) пожарный насос должен обеспечивать чистое давление не менее:", opts:["50% от номинального давления","85% от номинального давления","65% от номинального давления","100% от номинального давления"], re:"NFPA 20 требует, чтобы насос создавал не менее 65% от номинального давления при 150% от номинального расхода, определяя перегрузочный конец рабочей огибающей. Ссылка: характеристики центробежного насоса NFPA 20."},
  {id:420, q:"Три определяющие точки кривой характеристик пожарного насоса согласно NFPA 20 — это:", opts:["Всасывание, нагнетание и чистое","Статическое, остаточное и пито","Низкая, средняя и высокая скорость","Закрытая задвижка (без расхода), 100% номинального расхода и 150% номинального расхода"], re:"Кривая пожарного насоса определяется закрытой задвижкой (0% расхода, <=140% давления), точкой 100% номинала (номинальный расход при номинальном давлении) и точкой перегрузки 150% (>=65% давления). Ссылка: NFPA 20."},
  {id:421, q:"'Номинал пожарного насоса' (например, 750 gpm при 100 psi) относится к чистому давлению, создаваемому насосом при:", opts:["100% номинальной производительности","Закрытой задвижке / без расхода","150% номинальной производительности","Наименьшем допустимом давлении на всасывании"], re:"Номинал насоса — это чистое давление, которое он создаёт при 100% своей номинальной производительности. Закрытая задвижка и 150% оцениваются относительно этой номинальной точки. Ссылка: NFPA 20."},
  {id:422, q:"Какая из следующих является СТАНДАРТНОЙ номинальной производительностью центробежного пожарного насоса согласно NFPA 20?", opts:["650 gpm","750 gpm","725 gpm","850 gpm"], re:"NFPA 20 перечисляет стандартные номинальные производительности, включая 250, 500, 750, 1000, 1250, 1500 gpm (и другие). 750 gpm является стандартной; 650, 725 и 850 gpm не являются перечисленными стандартными номиналами. Ссылка: таблица номинальной производительности NFPA 20."},
  {id:423, q:"Основная функция жокей-насоса (насоса поддержания давления) — это:", opts:["Обеспечивать полную потребность пожарного расхода","Еженедельно испытывать основной насос","Поддерживать давление системы и предотвращать ненужный запуск основного пожарного насоса","Повышать давление на всасывании во время пожара"], re:"Жокей-насос поддерживает давление в заданных пределах для компенсации незначительных утечек, предотвращая ненужные запуски основного насоса. Он не рассчитан на удовлетворение пожарной потребности. Ссылка: NFPA 20, насосы поддержания давления."},
  {id:424, q:"Жокей-насос для спринклерной системы/системы пожарного стояка обычно должен быть подобран для обеспечения расхода, который:", opts:["Равен производительности основного насоса","Равен 50% производительности основного насоса","Точно равен 150% производительности основного насоса","Меньше расхода одного спринклера, чтобы основной насос запускался при любом реальном водотоке"], re:"Руководство NFPA 20 подбирает жокей-насос для компенсации допустимых утечек и обеспечения расхода меньше расхода одного спринклера, чтобы любое реальное срабатывание спринклера снижало давление и запускало основной насос. Ссылка: подбор насоса поддержания давления NFPA 20."},
  {id:425, q:"Минимальное номинальное чистое давление для центробежного пожарного насоса согласно NFPA 20 составляет:", opts:["40 psi","20 psi","65 psi","100 psi"], re:"NFPA 20 требует, чтобы центробежные пожарные насосы имели номинальное чистое давление 40 psi (2.7 бар) или более. Ссылка: требования к номиналу центробежного насоса NFPA 20."},
  {id:426, q:"Чтобы минимизировать потерянное/избыточное давление, NFPA 20 советует выбирать насос, НОМИНАЛЬНАЯ точка которого помещает проектный расход потребности приблизительно в пределах:", opts:["10%-50% номинального расхода","90%-140% номинального расхода","150%-200% номинального расхода","Только 0% (закрытая задвижка)"], re:"Проектировщики выбирают насос так, чтобы требуемый расход системы попадал примерно между 90% и 140% номинальной производительности (никогда выше 150%), удерживая рабочую точку на полезной части кривой. Ссылка: практика выбора NFPA 20."},
  {id:427, q:"Во время приёмочного испытания/испытания расходом производительность пожарного насоса измеряется при скольких условиях расхода как минимум?", opts:["Одном (только номинальном)","Двух (закрытая задвижка и номинальный)","Трёх (закрытая задвижка, 100% номинала и 150% номинала)","Пяти"], re:"Пожарный насос испытывается минимум при трёх условиях: без расхода (закрытая задвижка), 100% номинального расхода и 150% номинального расхода. Ссылка: испытание насоса NFPA 20 / NFPA 25."},
  {id:428, q:"'Чистое давление насоса' для пожарного насоса определяется как:", opts:["Давление нагнетания плюс давление всасывания","Только давление всасывания","Давление при закрытой задвижке минус 140%","Давление нагнетания минус давление всасывания (с поправкой на скоростной напор)"], re:"Чистое давление — это манометрическое давление нагнетания минус манометрическое давление всасывания (скорректированное на скоростной напор и высоту манометра). Оно представляет давление, которое добавляет сам насос. Ссылка: определения NFPA 20."},
  {id:429, q:"Для насосов, забирающих воду из городской магистрали, NFPA 20 требует, чтобы манометрическое давление на всасывании во время испытания при максимальном (150%) расходе обычно не падало ниже:", opts:["0 psi (манометрических), если только AHJ не разрешает меньшее значение","20 psi минимум во всех случаях","40 psi минимум во всех случаях","65 psi минимум во всех случаях"], re:"NFPA 20 ограничивает давление на всасывании не менее 0 psi манометрических при 150% расхода для насосов на водопитателе (некоторые AHJ/поставщики воды требуют более высокий минимум, например 20 psi). Ссылка: требования к водопитателю на всасывании NFPA 20."},
  {id:430, q:"Горизонтальный пожарный насос с разъёмным корпусом по сравнению с вертикальным турбинным пожарным насосом обычно НЕ подходит, когда:", opts:["Водопитатель — это городская магистраль под давлением выше насоса","Источник воды находится ниже осевой линии насоса (например, подземный резервуар или скважина, требующие всасывающего подъёма)","Требуется высокий расход","Используется дизельный привод"], re:"Горизонтальные насосы с разъёмным корпусом требуют положительного (затопленного) всасывания и не могут поднимать воду; вертикальный турбинный насос используется, когда уровень источника ниже насоса, например скважина или подземный резервуар. Ссылка: типы насосов NFPA 20."},
  {id:431, q:"Уставка давления, при которой основной пожарный насос настроен на ЗАПУСК, обычно:", opts:["Выше уставок запуска и останова жокей-насоса","Равна уставке останова жокей-насоса","Ниже уставки запуска жокей-насоса","На давлении при закрытой задвижке основного насоса"], re:"Последовательность управления настраивает останов/запуск так, чтобы жокей-насос срабатывал первым; уставка запуска основного пожарного насоса устанавливается ниже уставки запуска жокей-насоса, чтобы основной насос запускался только когда жокей не может поддержать давление. Ссылка: руководство по уставкам давления NFPA 20."},
  {id:432, q:"Пожарный насос с приводом от дизельного двигателя (а не от электродвигателя) обычно выбирается главным образом для того, чтобы:", opts:["Снизить требуемое номинальное давление","Исключить необходимость в контроллере","Допустить давление при закрытой задвижке выше 140%","Обеспечить источник питания, независимый от обычной электросети"], re:"Дизельный привод обеспечивает надёжный, независимый источник питания там, где надёжность сетевого электропитания под вопросом или требуется второй источник. Критерии характеристик насоса (закрытая задвижка, 100%, 150%) не меняются. Ссылка: приводы NFPA 20."},
  {id:433, q:"Когда доступный водопитатель на всасывании уже обеспечивает часть требуемого давления, пожарный насос должен иметь номинал только для того, чтобы:", opts:["Восполнить РАЗНИЦУ между потребностью системы и доступным давлением на всасывании (при проектном расходе)","Создавать полное давление потребности системы независимо от всасывания","Создавать 150% потребности системы","Соответствовать давлению при закрытой задвижке городской магистрали"], re:"Насос подбирается для повышения давления на величину дефицита: требуемое чистое давление равно давлению потребности системы минус доступное давление на всасывании при проектном расходе. Ссылка: практика подбора насоса NFPA 20."},
  {id:434, q:"Назначение контроллера пожарного насоса — это:", opts:["Дросселировать расход насоса точно до потребности","Автоматически запускать насос при падении давления и обеспечивать мониторинг/управление приводом насоса","Заменить жокей-насос","Устанавливать гидростатическое испытательное давление"], re:"Сертифицированный контроллер пожарного насоса запускает насос (обычно по сигналу падения давления), контролирует привод и обеспечивает требуемые сигнализацию/мониторинг. Ссылка: контроллеры NFPA 20."},
  {id:435, q:"Для гидравлически рассчитанной системы пожарного стояка Класса I NFPA 14 требует минимальное остаточное давление на гидравлически наиболее удалённом соединении рукава 2 1/2 дюйма:", opts:["65 psi","125 psi","100 psi","175 psi"], re:"NFPA 14 требует минимальное остаточное давление 100 psi на гидравлически наиболее удалённом выходе 2 1/2 дюйма (Класс I/III) при протекании требуемой потребности. Ссылка: NFPA 14, Стандарт на установку систем пожарных стояков и рукавов."},
  {id:436, q:"Для системы пожарного стояка Класса II NFPA 14 требует минимальное остаточное давление на гидравлически наиболее удалённой рукавной станции 1 1/2 дюйма:", opts:["50 psi","100 psi","150 psi","65 psi"], re:"NFPA 14 требует минимальное остаточное давление 65 psi на гидравлически наиболее удалённой рукавной станции 1 1/2 дюйма (Класс II). Ссылка: минимальные проектные давления NFPA 14."},
  {id:437, q:"Система пожарного стояка Класса I обеспечивает соединение рукава какого размера, предназначенное для использования пожарной частью или обученным персоналом?", opts:["Соединения 2 1/2 дюйма","Соединения 1 дюйм","Соединения 1 1/2 дюйма","Соединения 4 дюйма"], re:"Системы Класса I обеспечивают рукавные соединения 2 1/2 дюйма для использования пожарной частью/обученным персоналом. Класс II обеспечивает 1 1/2 дюйма для использования жильцами; Класс III обеспечивает оба. Ссылка: классы систем NFPA 14."},
  {id:438, q:"Система пожарного стояка Класса III обеспечивает:", opts:["Только рукавные соединения 1 1/2 дюйма","Рукавные соединения как 1 1/2 дюйма, так и 2 1/2 дюйма","Только рукавные соединения 2 1/2 дюйма","Только соединение пожарной части, без рукавных клапанов"], re:"Класс III сочетает оба: 1 1/2 дюйма для использования жильцами/первой помощи и 2 1/2 дюйма для использования пожарной частью. Его выходы 2 1/2 дюйма имеют то же требование остаточного 100 psi, что и Класс I. Ссылка: классы систем NFPA 14."},
  {id:439, q:"Для системы Класса I минимальный расход для гидравлически наиболее удалённого пожарного стояка составляет:", opts:["250 gpm","750 gpm","500 gpm","1,000 gpm"], re:"NFPA 14 требует 500 gpm для гидравлически наиболее удалённого пожарного стояка (два наиболее удалённых выхода 2 1/2 дюйма по 250 gpm каждый). Ссылка: требования к расходу Класса I NFPA 14."},
  {id:440, q:"После первого (наиболее удалённого) пожарного стояка каждый дополнительный стояк в системе Класса I добавляет сколько к требуемому расходу?", opts:["100 gpm каждый","500 gpm каждый","Никакого дополнительного расхода","250 gpm каждый"], re:"NFPA 14 добавляет 250 gpm за каждый дополнительный пожарный стояк сверх наиболее удалённого, до максимума системы. Ссылка: требования к расходу Класса I NFPA 14."},
  {id:441, q:"Максимальный общий требуемый расход для системы пожарного стояка Класса I в здании, полностью защищённом спринклерной системой NFPA 13, ограничен:", opts:["1,000 gpm","500 gpm","750 gpm","1,250 gpm"], re:"NFPA 14 ограничивает потребность Класса I до 1,000 gpm для зданий, полностью оборудованных спринклерами согласно NFPA 13, и 1,250 gpm там, где они не полностью оборудованы спринклерами. Ссылка: максимальная потребность по расходу NFPA 14."},
  {id:442, q:"Максимальный общий требуемый расход для системы пожарного стояка Класса I в здании, которое НЕ полностью оборудовано спринклерами, составляет:", opts:["750 gpm","1,250 gpm","1,000 gpm","1,500 gpm"], re:"Для зданий, не защищённых полностью спринклерами NFPA 13, NFPA 14 ограничивает потребность Класса I до 1,250 gpm. Ссылка: максимальная потребность по расходу NFPA 14."},
  {id:443, q:"NFPA 14 ограничивает максимальное статическое или остаточное давление на рукавном соединении до 175 psi (для выходов 2 1/2 дюйма); выше этого значения проект должен предусматривать:", opts:["Больший диаметр пожарного стояка","Второе соединение пожарной части","Устройство понижения или ограничения давления на рукавном клапане","Дополнительный жокей-насос"], re:"Там, где давление на рукавном соединении 2 1/2 дюйма превышает 175 psi, NFPA 14 требует одобренное устройство регулирования давления (понижающее/ограничивающее) для защиты пожарных и рукава. Ссылка: регулирование давления NFPA 14."},
  {id:444, q:"В системе Класса I рукавные соединения в выходных лестничных клетках располагаются:", opts:["Только в верхней части здания","Только в вестибюле","Только у соединения пожарной части","На площадке главного этажа каждой выходной лестничной клетки"], re:"NFPA 14 требует соединения Класса I 2 1/2 дюйма на площадке главного этажа в выходных лестничных клетках (с дополнительными местами, такими как горизонтальные выходы и выходные проходы). Ссылка: расположение рукавных соединений NFPA 14."},
  {id:445, q:"'Автоматическая' система пожарного стояка отличается от 'ручной' системы пожарного стояка тем, что автоматическая система:", opts:["Подключена к водопитателю, способному удовлетворить потребность без подкачки пожарной частью","Не имеет соединения пожарной части","Использует только рукав 1 1/2 дюйма","Не может быть рассчитана гидравлически"], re:"Автоматический пожарный стояк подключён к водопитателю (например, городская магистраль или пожарный насос), который удовлетворяет потребность системы в любое время; ручная система полагается на подкачку пожарной частью в FDC для подачи давления/расхода. Ссылка: типы систем NFPA 14."},
  {id:446, q:"Совмещённая (комбинированная) спринклерная система/система пожарного стояка — это система, в которой:", opts:["Два отдельных стояка обслуживают спринклеры и пожарные стояки независимо","Один стояк питает как спринклерную систему, так и рукавные соединения 2 1/2 дюйма","Обеспечивается только рукав Класса II","Спринклеры не устанавливаются"], re:"Совмещённая система использует один стояк для обслуживания как автоматических спринклеров, так и рукавных соединений пожарного стояка; проект должен удовлетворять обе потребности. Ссылка: совмещённые системы NFPA 14."},
  {id:447, q:"Соединение пожарной части (FDC) для системы пожарного стояка должно быть рассчитано по крайней мере на сколько вводов 2 1/2 дюйма на каждые 250 gpm потребности пожарного стояка?", opts:["Два ввода на 250 gpm","Один ввод на 1,000 gpm","Один ввод на 250 gpm","Никакой связи с потребностью"], re:"NFPA 14 требует, чтобы FDC обеспечивало один ввод 2 1/2 дюйма на каждые 250 gpm требуемой потребности системы пожарного стояка. Ссылка: соединения пожарной части NFPA 14."},
  {id:448, q:"В высотном здании, когда гидростатическое давление на нижних рукавных соединениях превысило бы допустимые пределы, система пожарного стояка обычно:", opts:["Сокращается только до Класса II","Преобразуется в ручную сухую систему","Ограничивается до 50 gpm на выход","Разделяется на отдельные зоны давления (с отдельными стояками и/или PRV)"], re:"Избыточное давление в высотных зданиях контролируется путём разделения пожарного стояка на зоны давления, обслуживаемые отдельными стояками, или применением клапанов регулирования давления, удерживая давления на выходах в пределах. Ссылка: практика высотного строительства/зонирования NFPA 14."},
  {id:449, q:"Для подбора пожарных стояков NFPA 14 исторически требовала минимальный номинальный диаметр пожарного стояка (стояка):", opts:["4 дюйма","2 дюйма","3 дюйма","6 дюймов"], re:"Стояки пожарного стояка Класса I и Класса III имеют минимальный номинальный размер; для гидравлически рассчитанных систем Класса I/III NFPA 14 устанавливает минимальный размер стояка (4 дюйма минимум были давней базой для этих систем). Ссылка: подбор стояка NFPA 14."},
  {id:450, q:"'Мокрый' пожарный стояк против 'сухого' пожарного стояка отличается тем, что мокрый пожарный стояк:", opts:["Заполняется только когда пожарная часть подкачивает в него","Содержит воду в трубопроводе в любое время","Не имеет рукавных клапанов","Ограничен обслуживанием Класса II"], re:"Мокрый пожарный стояк содержит воду в любое время (обычно автоматический), обеспечивая немедленную доступность; сухой пожарный стояк не содержит воды до подачи, что распространено в неотапливаемых или ручных конфигурациях. Ссылка: определения мокрого/сухого пожарного стояка NFPA 14."},
  {id:451, q:"Рукавные клапаны в системах пожарного стояка Класса I должны быть:", opts:["Быстросъёмные 1 дюйм","Только 4 дюйма","2 1/2 дюйма (с переходником, разрешённым в некоторых объектах)","Резьбового садово-шлангового типа"], re:"Рукавные клапаны Класса I — это соединения 2 1/2 дюйма; переходник 2 1/2 дюйма на 1 1/2 дюйма с крышкой может быть разрешён в некоторых полностью оборудованных спринклерами объектах. Ссылка: подбор размера рукавного соединения NFPA 14."},
  {id:452, q:"Рабочие чертежи NFPA 13 (монтажные чертежи) должны быть выполнены в указанном масштабе и, среди прочего, показывать:", opts:["Только адрес здания","Только электрическую разводку","Только расположение панели пожарной сигнализации","Указатель сторон света (стрелка севера), расположения спринклеров и размеры труб"], re:"NFPA 13 требует, чтобы рабочие чертежи в масштабе показывали точку севера, поперечное сечение на полную высоту, типы/расположения спринклеров, размеры/длины труб и подобные детали. Ссылка: NFPA 13, Планы и расчёты (рабочие чертежи)."},
  {id:453, q:"Пакет гидравлических расчётов, требуемый NFPA 13, должен включать что из следующего?", opts:["Сводный лист, подробные рабочие листы и лист графика","Только одно значение общего расхода","Только каталог производителя","Только разрешение на строительство"], re:"NFPA 13 требует, чтобы гидравлические расчёты состояли из сводного листа, подробных рабочих листов (узел за узлом) и листа графика, отображающего водоснабжение против потребности. Ссылка: формы гидравлического расчёта NFPA 13."},
  {id:454, q:"'Проектная площадь' в проектировании спринклеров по методу плотность/площадь представляет:", opts:["Всю площадь этажа здания","Гидравлически наиболее требовательную площадь, которая предположительно работает при пожаре","Только площадь непосредственно под стояком","Площадь, охватываемую соединением пожарной части"], re:"Проектная площадь — это площадь этажа, на которой спринклеры предположительно работают одновременно (гидравлически наиболее требовательная площадь), используемая для расчёта потребности системы. Ссылка: проектирование по плотности/площади NFPA 13."},
  {id:455, q:"Для объекта Лёгкой опасности с использованием метода плотность/площадь часто упоминаемая базовая проектная точка составляет:", opts:["0.05 gpm/ft^2 на 1,000 ft^2","0.20 gpm/ft^2 на 1,500 ft^2","0.10 gpm/ft^2 на 1,500 ft^2","0.30 gpm/ft^2 на 2,500 ft^2"], re:"База Лёгкой опасности составляет приблизительно 0.10 gpm/ft^2 на проектной площади 1,500 ft^2 (согласно кривым плотность/площадь, используемым в NFPA 13). Ссылка: кривые плотность/площадь NFPA 13 для Лёгкой опасности."},
  {id:456, q:"Для Обычной опасности Группы 2 часто упоминаемая базовая проектная точка плотность/площадь составляет:", opts:["0.10 gpm/ft^2 на 1,500 ft^2","0.15 gpm/ft^2 на 1,500 ft^2","0.40 gpm/ft^2 на 3,000 ft^2","0.20 gpm/ft^2 на 1,500 ft^2"], re:"База Обычной опасности Группы 2 составляет приблизительно 0.20 gpm/ft^2 на 1,500 ft^2; Группа 1 — около 0.15 gpm/ft^2 на 1,500 ft^2. Ссылка: кривые плотность/площадь NFPA 13."},
  {id:457, q:"На кривых плотность/площадь увеличение предполагаемой проектной ПЛОЩАДИ обычно позволяет требуемой ПЛОТНОСТИ:", opts:["Уменьшиться","Увеличиться","Остаться точно такой же","Стать нулевой"], re:"Кривые плотность/площадь имеют наклон, при котором выбор большей проектной площади допускает меньшую плотность (и наоборот); проектировщик выбирает точку на кривой. Ссылка: кривые проектирования по плотности/площади NFPA 13."},
  {id:458, q:"Табличка информации гидравлического проектирования, требуемая NFPA 13 на стояке, должна указывать:", opts:["Номер телефона владельца здания","Проектную плотность, проектную площадь и требуемый расход/давление в основании стояка","Гарантию производителя спринклеров","Список зон пожарной сигнализации"], re:"NFPA 13 требует постоянно нанесённую табличку информации гидравлического проектирования, перечисляющую расположение проектной площади, плотность, классификацию объекта и требуемый расход и давление (потребность) в основании стояка, плюс резерв на рукав. Ссылка: требования к идентификации/табличке NFPA 13."},
  {id:459, q:"При подборе труб табличным методом (где разрешено) проектировщик определяет размеры труб на основе:", opts:["Гидравлического расчёта в каждом узле","Номинала пожарного насоса","Числа спринклеров, обслуживаемых каждой трубой, и таблицы классификации опасности","Потребности пожарного стояка"], re:"Табличный метод назначает размеры труб из таблиц на основе числа питаемых спринклеров и класса опасности; он разрешён только для ограниченных существующих ситуаций лёгкой и обычной опасности согласно NFPA 13. Ссылка: табличный метод NFPA 13."},
  {id:460, q:"NFPA 13 требует, чтобы гидравлические расчёты доходили до:", opts:["Только самого удалённого спринклера","Только основания стояка","Прибора управления пожарной сигнализацией","Эффективной точки водоснабжения, где известны характеристики"], re:"Расчёты должны доходить от проектной площади до эффективной точки водоснабжения, где известны характеристики водоснабжения, чтобы потребность можно было сравнить с водоснабжением. Ссылка: процедуры гидравлического расчёта NFPA 13."},
  {id:461, q:"В гидравлическом узле (где расходы объединяются) NFPA 13 требует, чтобы давления от сходящихся путей уравновешивались в пределах:", opts:["0.5 psi","2 psi","5 psi","10 psi"], re:"В точках узлов рассчитанные давления от сливающихся ветвей должны уравновешиваться в пределах 0.5 psi; более высокое давление является определяющим, и расходы корректируются соответственно. Ссылка: правило балансировки гидравлического расчёта NFPA 13."},
  {id:462, q:"'Резерв на рукавную струю' добавляется к спринклерной потребности в гидравлических расчётах для учёта:", opts:["Утечки в подземной магистрали","Воды, используемой рукавами пожарной части во время пожара","Расхода жокей-насоса","Трения обратного клапана"], re:"Резерв на рукавную струю (внутренний/наружный рукав) добавляется в соответствующей точке для резервирования расхода на рукава ручного пожаротушения, работающие одновременно со спринклерами. Ссылка: резерв на рукавную струю и таблицы продолжительности водоснабжения NFPA 13."},
  {id:463, q:"Общая продолжительность водоснабжения и резерв на рукав, требуемые для данного объекта, берутся из:", opts:["Заводской таблички пожарного насоса","Таблички FDC пожарного стояка","Таблиц NFPA 13 на основе классификации опасности","Графика нагрузок электрика"], re:"NFPA 13 предоставляет таблицы требуемой минимальной продолжительности работы (водоснабжения) и резерва на внутренний/наружный рукав, привязанные к классификации опасности, используемой в методе плотность/площадь. Ссылка: таблицы требований к водоснабжению NFPA 13."},
  {id:464, q:"На рабочих чертежах относительные ВЫСОТЫ спринклеров, узловых точек и точек водоснабжения/опорных точек должны показываться, потому что они:", opts:["Влияют только на эстетическую компоновку","Определяют цвет краски","Требуются только для сухих систем","Нужны для расчёта высотного давления в гидравлических расчётах"], re:"Данные о высотах требуются, чтобы расчёт мог прибавлять/вычитать высотное давление (0.433 psi/ft) в каждой точке; NFPA 13 требует относительные высоты на чертежах. Ссылка: содержание рабочих чертежей NFPA 13."},
  {id:465, q:"Какой элемент НЕ требуется обычно в содержании рабочих чертежей NFPA 13?", opts:["Подробная платёжная ведомость монтажного подрядчика","Температурные номиналы и расположения спринклеров","Размеры, длины труб и типы фитингов","Точка подключения к водоснабжению"], re:"Рабочие чертежи должны показывать типы/номиналы спринклеров, подбор труб и фитингов и подключение водоснабжения; платёжная ведомость подрядчика не является требованием к чертежу. Ссылка: список содержания рабочих чертежей NFPA 13."},
  {id:466, q:"'Расчётная точка' (наиболее требовательный спринклер), выбранная в пределах проектной площади, обычно является спринклером, который:", opts:["Ближе всего к стояку","Гидравлически наиболее удалён (требует наибольшего давления)","Имеет наибольшее отверстие независимо от расположения","Находится на самой низкой высоте"], re:"Проектирование начинается с гидравлически наиболее удалённого/наиболее требовательного спринклера в проектной площади и движется обратно к водоснабжению, обеспечивая, что каждый спринклер в площади удовлетворяет минимальной плотности. Ссылка: процедура гидравлического проектирования NFPA 13."},
  {id:467, q:"Коэффициент K спринклера используется в расчётах для связи:", opts:["Диаметра трубы с длиной","Температурного номинала с цветом","Расхода при сбросе (Q) с давлением (P) через Q = K x sqrt(P)","Высоты с потерями на трение"], re:"Сброс из спринклера равен Q = K x sqrt(P), где K — сертифицированный коэффициент расхода; он преобразует рассчитанное давление у спринклера в расход. Ссылка: NFPA 13 / характеристики сброса спринклера."},
  {id:468, q:"Минимальное рабочее давление для стандартного распылительного спринклера согласно NFPA 13 обычно не менее:", opts:["3 psi","15 psi","30 psi","7 psi"], re:"NFPA 13 требует минимальное рабочее давление 7 psi для стандартных распылительных спринклеров (некоторые специальные/сертифицированные спринклеры имеют более высокие минимумы согласно их сертификации). Ссылка: минимальное рабочее давление NFPA 13."},
  {id:469, q:"В кодексах противопожарной защиты 'AHJ' означает:", opts:["Орган, имеющий юрисдикцию (Authority Having Jurisdiction)","Одобренный гидравлический узел (Approved Hydraulic Junction)","Ежегодная оценка опасности (Annual Hazard Judgment)","Автоматический рукавный узел (Automatic Hose Junction)"], re:"AHJ означает Authority Having Jurisdiction (Орган, имеющий юрисдикцию): организация, учреждение или лицо, ответственное за обеспечение соблюдения требований кодекса и одобрение оборудования, установок и процедур. Ссылка: определения NFPA (например, NFPA 13/14/20)."},
  {id:470, q:"Перед началом монтажа NFPA 13 требует, чтобы рабочие чертежи были:", opts:["Поданы только после монтажа системы","Поданы в AHJ для рассмотрения и одобрения","Сохранены в тайне от AHJ","Поданы только производителю спринклеров"], re:"NFPA 13 требует, чтобы рабочие чертежи (и расчёты) были поданы в AHJ и одобрены им до монтажа. Ссылка: требования к подаче чертежей NFPA 13."},
  {id:471, q:"Если проектировщик желает использовать метод или решение, конкретно не рассмотренное кодексом, типичный путь — это:", opts:["Действовать без уведомления","Полностью игнорировать кодекс","Подать его в AHJ для рассмотрения/одобрения как эквивалентность или альтернативное средство","Использовать его только по выходным"], re:"Кодексы разрешают альтернативные материалы/методы, которые AHJ может одобрить, когда показана эквивалентность по качеству, прочности, безопасности и характеристикам. Предложение подаётся в AHJ. Ссылка: положения об эквивалентности NFPA; типовые кодексы пожарной безопасности/строительства."},
  {id:472, q:"Термин 'сертифицированный' (listed) в стандартах NFPA означает, что оборудование или материал:", opts:["Просто рекламируется производителем","Окрашен в красный цвет","Доступен в любом хозяйственном магазине","Включён в список, опубликованный организацией, приемлемой для AHJ, которая проводит оценку"], re:"'Сертифицированный' означает опубликованный в списке организацией (приемлемой для AHJ), занимающейся оценкой продукции, что указывает, что оборудование соответствует подходящим стандартам или было испытано для указанного применения. Ссылка: определения NFPA."},
  {id:473, q:"Термин 'одобренный' (approved), используемый во всех кодексах NFPA, конкретно означает:", opts:["Приемлемый для Органа, имеющего юрисдикцию (Authority Having Jurisdiction)","Одобренный производителем оборудования","Сертифицированный только Underwriters Laboratories","Разрешённый владельцем здания"], re:"'Одобренный' определяется в кодексах NFPA как приемлемый для Органа, имеющего юрисдикцию (Authority Having Jurisdiction). Ссылка: определения NFPA (NFPA 13/14/20)."},
  {id:474, q:"Гидравлические расчёты, подаваемые с чертежами, обычно требуются, чтобы они были:", opts:["Только рукописными","Подписаны/заверены печатью или подготовлены квалифицированным проектировщиком и согласованы с рабочими чертежами","Поданы без данных испытания водопитателя","Ограничены одной страницей независимо от размера системы"], re:"Расчёты должны быть подготовлены квалифицированным персоналом, согласовываться с рабочими чертежами и включать вспомогательную информацию о водоснабжении; многие AHJ требуют сертификацию проектировщика или печать PE. Ссылка: планы/расчёты NFPA 13; правила подачи AHJ."},
  {id:475, q:"Основная причина, по которой AHJ рассматривает и одобряет чертежи пожарных спринклеров до строительства, — это:", opts:["Установить цену подрядчика","Выбрать цвет краски трубы","Проверить, что проект соответствует применимым требованиям кодекса до начала работ","Выбрать мебель здания"], re:"Рассмотрение чертежей подтверждает, что предлагаемый проект соответствует принятым кодексам/стандартам (NFPA 13/14/и т. д.) до монтажа, выявляя недостатки на раннем этапе. Ссылка: положения о рассмотрении чертежей типового кодекса пожарной безопасности; NFPA 13."},
  {id:476, q:"'Классификация объекта/опасности', установленная на чертежах, важна для рассмотрения AHJ, потому что она определяет:", opts:["Спецификацию краски","Число парковочных мест","Грузоподъёмность лифта","Требуемую проектную плотность, проектную площадь и продолжительность водоснабжения"], re:"Классификация опасности (Лёгкая, Обычная, Повышенная или складская) определяет проектную точку плотность/площадь и продолжительность водоснабжения/резерв на рукав, поэтому AHJ тщательно её проверяет. Ссылка: классификация объектов NFPA 13."},
  {id:477, q:"Какой комплект документов обычно подаётся для рассмотрения чертежей пожарных спринклеров?", opts:["Рабочие (монтажные) чертежи, гидравлические расчёты и информация о водоснабжении (испытание расходом)","Только план этажа","Только прайс-лист производителя","Только сертификат о вводе в эксплуатацию"], re:"Полная подача включает рабочие/монтажные чертежи, вспомогательные гидравлические расчёты и данные о водоснабжении/испытании расходом, использованные в проекте. Ссылка: подача планов и расчётов NFPA 13."},
  {id:478, q:"Когда принятая редакция стандарта NFPA противоречит предпочитаемой проектировщиком более новой редакции, проект должен соответствовать:", opts:["Любой редакции, которую предпочитает проектировщик","Редакции, принятой/применяемой AHJ (юрисдикцией)","Самой старой когда-либо опубликованной редакции","Никакой редакции вообще"], re:"Законно принятая редакция, на которую ссылается кодекс юрисдикции, является определяющей; AHJ применяет эту редакцию, если только формально не разрешает другую. Ссылка: практика принятия типового кодекса; область применения/AHJ NFPA."},
  {id:479, q:"Если полевое условие требует отклонения от одобренных чертежей во время монтажа, правильное действие — это:", opts:["Внести изменение незаметно и не документировать его","Остановить все работы навсегда","Получить одобрение изменения (пересмотренных чертежей) от AHJ до или по мере необходимости","Удалить спринклерную систему"], re:"Изменения относительно одобренных чертежей обычно требуют пересмотренных чертежей/одобрения, чтобы смонтированная система по-прежнему соответствовала, а запись отражала условия как построено. Ссылка: практика пересмотра чертежей NFPA 13/AHJ."},
  {id:480, q:"'Shall' против 'should' в стандартах NFPA: слово 'shall' указывает на требование, которое является:", opts:["Необязательным/рекомендательным","Только рекомендацией","Применимым только к существующим системам","Обязательным"], re:"В документах NFPA 'shall' указывает на обязательное требование; 'should' указывает на рекомендацию или рекомендательное положение. Ссылка: Руководство по стилю NFPA; применение стандартов NFPA."},
  {id:481, q:"'Испытание расходом' водоснабжения, подаваемое с чертежами, обычно должно быть не старше:", opts:["12 месяцев (согласно распространённой практике AHJ/NFPA 20)","1 месяца","5 лет","Нет ограничения по времени"], re:"Данные испытания расходом, используемые для проектирования, обычно требуются в пределах 12 месяцев (NFPA 20 требует в пределах 12 месяцев для подбора насоса); многие AHJ применяют аналогичные ограничения к подачам спринклеров для отражения текущего водоснабжения. Ссылка: NFPA 20; практика подачи AHJ."},
  {id:482, q:"Сторона, ответственная за обеспечение того, чтобы смонтированная система соответствовала ОДОБРЕННЫМ чертежам, — это в первую очередь:", opts:["Арендаторы здания","Монтажный подрядчик (с проверкой AHJ при инспекции)","Водоснабжающая организация","Поставщик мебели"], re:"Монтажный подрядчик монтирует согласно одобренным чертежам и сертифицирует работу; AHJ проверяет соответствие при инспекции/приёмке. Ссылка: обязанности по монтажу/приёмке NFPA 13."},
  {id:483, q:"Там, где строительное должностное лицо принимает Международный пожарный кодекс или NFPA 1/101, упоминаемый стандарт на установку спринклеров обычно:", opts:["NFPA 70 (Национальный электротехнический кодекс)","NFPA 72 (пожарная сигнализация)","NFPA 13 (и NFPA 13R/13D для жилья)","NFPA 25 (инспекция/испытание)"], re:"Установка спринклеров регулируется NFPA 13 (с NFPA 13R для малоэтажного жилья и 13D для одно- и двухсемейных домов); NFPA 25 охватывает ITM, а NFPA 72 охватывает пожарную сигнализацию. Ссылка: ссылки типового кодекса на NFPA 13."},
  {id:484, q:"Положение об 'эквивалентности' в стандарте NFPA позволяет AHJ принять альтернативу при условии, что она обеспечивает:", opts:["Более низкий уровень безопасности для экономии средств","Более быстрый монтаж независимо от характеристик","Только эстетическое улучшение","Эквивалентные качество, прочность, огнестойкость, эффективность, долговечность и безопасность"], re:"Положения об эквивалентности позволяют AHJ одобрить альтернативные материалы/методы/устройства, демонстрирующие эквивалентность по качеству, прочности, огнестойкости, эффективности, долговечности и безопасности. Ссылка: положения об эквивалентности NFPA (например, NFPA 13)."},
  {id:485, q:"Новый надземный спринклерный трубопровод должен испытываться гидростатически при давлении не менее:", opts:["200 psi в течение 2 часов (или 50 psi выше рабочего давления, если оно превышает 150 psi)","100 psi в течение 1 часа","150 psi в течение 30 минут","300 psi в течение 24 часов"], re:"NFPA 13 требует гидростатического испытания при 200 psi в течение 2 часов, или 50 psi выше максимального рабочего давления системы, когда это давление превышает 150 psi, выдерживаемого в течение 2 часов. Ссылка: приёмка/гидростатическое испытание NFPA 13."},
  {id:486, q:"Во время 2-часового гидростатического испытания надземного спринклерного трубопровода критерий приёмки по сути:", opts:["Падение на 20 psi приемлемо","Отсутствие утечки / отсутствие падения манометрического давления (отсутствие видимой утечки) в течение 2 часов","Падение давления на 50% приемлемо","Любое показание давления приемлемо"], re:"Испытание проходит только если нет видимой утечки и нет падения манометрического давления в течение 2-часового периода (по сути нулевые потери). Ссылка: критерии приёмки гидростатического испытания NFPA 13."},
  {id:487, q:"Форма, документирующая, что новая спринклерная система/система пожарного стояка была смонтирована и испытана согласно стандарту, — это:", opts:["Энергетическая декларация здания","Гарантийный талон производителя","Акт материалов и испытаний подрядчика","Бирка инспекции лифта"], re:"Акт материалов и испытаний подрядчика (для надземного и для подземного трубопровода) фиксирует смонтированные материалы и проведённые испытания и требуется к заполнению и подписанию при приёмке. Ссылка: формы акта NFPA 13/NFPA 24."},
  {id:488, q:"Акт материалов и испытаний подрядчика заполняется и подписывается:", opts:["Страховым брокером здания","Расчётным отделом водоснабжающей организации","Только архитектором проекта","Монтажным подрядчиком (и подписывается для владельца имущества/AHJ по мере применимости)"], re:"Монтажный подрядчик заполняет и подписывает акт, документируя, что система была смонтирована и испытана в соответствии со стандартом; он предоставляется владельцу и AHJ. Ссылка: документация приёмки NFPA 13."},
  {id:489, q:"Подземный трубопровод водоснабжения (NFPA 24) должен быть ПРОМЫТ перед подключением к надземному трубопроводу главным образом для того, чтобы:", opts:["Удалить мусор, камни и посторонние материалы, которые могли бы засорить спринклеры","Охладить трубу","Добавить хлор для вкуса","Постоянно увеличить коэффициент C"], re:"Промывка удаляет строительный мусор и посторонние материалы из подземной магистрали, чтобы они не могли попасть и засорить спринклеры или клапаны; расходы промывки указаны по размеру трубы. Ссылка: требования к промывке NFPA 24; фиксируется в подземном акте."},
  {id:490, q:"Подземные магистрали пожарного водоснабжения (NFPA 24) испытываются гидростатически при:", opts:["100 psi или 25 psi выше рабочего давления","200 psi или 50 psi выше максимального рабочего давления системы (что больше), в течение 2 часов","300 psi в течение 8 часов","Гидростатическое испытание не требуется"], re:"NFPA 24 требует, чтобы подземные магистрали испытывались при 200 psi, или 50 psi выше максимального рабочего давления системы, когда оно больше, в течение 2 часов, с утечкой, ограниченной допустимой величиной. Ссылка: гидростатическое испытание NFPA 24."},
  {id:491, q:"В отличие от надземного спринклерного трубопровода (который по сути не допускает утечки), для заглублённого/подземного трубопровода допускается небольшое количество утечки во время его гидростатического испытания, потому что:", opts:["Труба слабее","Подземная труба никогда не испытывается","Допускается незначительное просачивание на стыках заглублённой трубы, в пределах рассчитанного лимита","Утечка улучшает поток"], re:"NFPA 24 допускает ограниченный, рассчитанный допуск на утечку для подземных стыков во время 2-часового испытания, тогда как надземный спринклерный трубопровод не должен показывать утечки/падения давления. Ссылка: формула допустимой утечки NFPA 24."},
  {id:492, q:"'Испытание главного дренажа', выполняемое при приёмке, используется для проверки:", opts:["Уровня звука пожарной сигнализации","Толщины краски","Скорости лифта","Того, что водоснабжение не заблокировано, путём сравнения статического и остаточного (текущего) давлений"], re:"Открытие главного дренажа и сравнение статического давления с текущим проверяет, что управляющие задвижки водоснабжения открыты и водоснабжение не заблокировано; показания фиксируются и используются как базовая линия. Ссылка: испытание главного дренажа NFPA 13/NFPA 25."},
  {id:493, q:"При приёмке сигнализации водотока система испытывается расходом для подтверждения, что сигнализация срабатывает в течение:", opts:["90 секунд от расхода на уровне инициирования сигнализации","10 минут расхода","1 часа расхода","Нет требования по времени"], re:"Устройства сигнализации водотока должны инициировать сигнал в течение 90 секунд от расхода, равного или превышающего расход наименьшего спринклера; проверяется при приёмке. Ссылка: испытание сигнализации водотока NFPA 13."},
  {id:494, q:"Акт материалов и испытаний подрядчика фиксирует что из следующего?", opts:["Только квадратные метры здания","Тип системы, использованные материалы, испытательные давления/продолжительности, промывку и результаты испытания сигнализации","Только адрес электронной почты владельца","Только цвет краски"], re:"Акт документирует тип системы, материалы трубопровода/компонентов, гидростатическое испытательное давление и продолжительность, промывку, испытания сигнализации/работы и подписи. Ссылка: содержание акта NFPA 13/24."},
  {id:495, q:"Спринклерная система с сухой трубой, помимо гидростатического испытания, также требует приёмочного испытания на:", opts:["Однородность цвета","Сопряжение с лифтом","Испытание на утечку давления воздуха (например, не более указанной потери давления за 24 часа)","Воспламеняемость ковра"], re:"Сухие системы получают испытание воздухом низкого давления; NFPA 13 ограничивает потерю давления за 24 часа (обычно не более 1.5 psi потери за 24 часа при указанном испытательном давлении) и проверяет срабатывание/работу. Ссылка: испытание воздухом сухой системы NFPA 13."},
  {id:496, q:"Сборки предотвращения обратного потока, установленные на линии пожарного обслуживания, должны после установки быть:", opts:["Окрашены в чёрный цвет","Удалены до приёмки","Оставлены без испытания","Испытаны прямым потоком при расходе потребности системы, и сборка испытана на правильную работу"], re:"NFPA 13/24 требуют испытание прямым потоком через сборку предотвращения обратного потока при расходе потребности системы (чтобы подтвердить, что она чрезмерно не ограничивает поток) плюс собственное испытание работы сборки. Ссылка: испытание прямым потоком обратного клапана NFPA 13/24."},
  {id:497, q:"Для пожарного насоса полевое ПРИЁМОЧНОЕ испытание демонстрирует, что смонтированный насос соответствует своему номиналу, путём испытания при:", opts:["Закрытой задвижке, 100% номинального расхода и 150% номинального расхода, сравниваемых с сертифицированной кривой","Только закрытой задвижке","Только номинальном расходе","200% номинального расхода"], re:"Приёмочное испытание насоса прогоняет точки закрытой задвижки, 100% и 150% и сравнивает результаты с сертифицированной заводской кривой испытания производителя для подтверждения характеристик. Ссылка: полевое приёмочное испытание NFPA 20."},
  {id:498, q:"При приёмке пожарного насоса характеристики в каждой испытательной точке обычно должны составлять не менее какого процента от сертифицированной (заводской) кривой / значений заводской таблички?", opts:["50%","95%","75%","140%"], re:"Характеристики полевого испытания в каждой точке должны быть не менее 95% от значений номинальной/сертифицированной (заводской) кривой насоса для приёмки. Ссылка: критерии приёмки NFPA 20/NFPA 25."},
  {id:499, q:"Какое испытание подтверждает, что автоматическая система пожарного стояка обеспечивает требуемое давление и расход на самом удалённом выходе?", opts:["Испытание адгезии краски","Испытание возврата лифта","Испытание расходом на гидравлически наиболее удалённом рукавном соединении","Испытание чувствительности дымового извещателя"], re:"Испытание расходом пожарного стояка на гидравлически наиболее удалённом выходе 2 1/2 дюйма проверяет, что достигается требуемое остаточное давление (100 psi для Класса I/III) при требуемом расходе (500 gpm). Ссылка: приёмочное испытание расходом NFPA 14."},
  {id:500, q:"Заполненный Акт материалов и испытаний подрядчика в конечном итоге предоставляется владельцу имущества и делается доступным для AHJ, чтобы он мог служить:", opts:["Маркетинговой брошюрой","Заменой рабочих чертежей","Заменой периодических инспекций NFPA 25","Постоянной записью того, что система была смонтирована и испытана в соответствии со стандартом"], re:"Акт является постоянной записью приёмки, подтверждающей соответствующий монтаж и успешные испытания; он сохраняется владельцем и предоставляется AHJ, но не заменяет постоянную инспекцию, испытание и обслуживание по NFPA 25. Ссылка: документация приёмки NFPA 13/24; ITM NFPA 25."}
];
